} from 'lucide-react';
import { 
  Category, 
  Status, 
  Khand, 
  Mandal, 
  Village, 
  Contact, 
  TripPlan, 
  CustomList, 
  VisitHistory 
} from './types';
import { 
  INITIAL_KHANDS, 
  INITIAL_MANDALS, 
  INITIAL_VILLAGES, 
  INITIAL_CONTACTS, 
  INITIAL_TRIPS, 
  INITIAL_LISTS 
} from './constants';

type Tab = 'home' | 'people' | 'trips' | 'lists' | 'calendar' | 'settings';

const App: React.FC = () => {
  // --- State ---
  const [activeTab, setActiveTab] = useState<Tab>('home');
  const [khands, setKhands] = useState<Khand[]>(INITIAL_KHANDS);
  const [mandals, setMandals] = useState<Mandal[]>(INITIAL_MANDALS);
  const [villages, setVillages] = useState<Village[]>(INITIAL_VILLAGES);
  const [contacts, setContacts] = useState<Contact[]>(INITIAL_CONTACTS);
  const [trips, setTrips] = useState<TripPlan[]>(INITIAL_TRIPS);
  const [customLists, setCustomLists] = useState<CustomList[]>(INITIAL_LISTS);

  // Filters for Dashboard
  const [dashKhand, setDashKhand] = useState<string>('all');
  const [dashMandal, setDashMandal] = useState<string>('all');

  // Selected Item for Detail Views
  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [selectedTripId, setSelectedTripId] = useState<string | null>(null);
  const [selectedListId, setSelectedListId] = useState<string | null>(null);

  // UI Modals
  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isAddingTrip, setIsAddingTrip] = useState(false);
  const [isLoggingVisit, setIsLoggingVisit] = useState<string | null>(null); // contactId
  const [isAddingList, setIsAddingList] = useState(false);

  // --- Helpers ---
  const getKhandName = (id: string) => khands.find(k => k.id === id)?.name || id;
  const getMandalName = (id: string) => mandals.find(m => m.id === id)?.name || id;
  const getVillageName = (id: string) => villages.find(v => v.id === id)?.name || id;

  const getFilteredContacts = (kId: string, mId: string) => {
    return contacts.filter(c => 
      (kId === 'all' || c.khandId === kId) && 
      (mId === 'all' || c.mandalId === mId)
    );
  };

  const getStats = () => {
    const filtered = getFilteredContacts(dashKhand, dashMandal);
    return {
      total: filtered.length,
      active: filtered.filter(c => c.status === Status.SAKRIYA).length,
      sanchit: filtered.filter(c => c.status === Status.SANCHIT).length,
      sajjan: filtered.filter(c => c.status === Status.SAJJAN).length,
      utsuk: filtered.filter(c => c.status === Status.UTSUK).length,
      pending: filtered.filter(c => {
         const lastVisit = c.history[c.history.length - 1];
         if (!lastVisit?.nextFollowUp) return false;
         return new Date(lastVisit.nextFollowUp) < new Date();
      }).length
    };
  };

  // --- Handlers ---
  const handleAddContact = (newContact: Omit<Contact, 'id' | 'listIds' | 'history'>) => {
    const contact: Contact = {
      ...newContact,
      id: `c${Date.now()}`,
      listIds: [],
      history: []
    };
    setContacts(prev => [...prev, contact]);
    setIsAddingContact(false);
  };

  const handleDeleteContact = (id: string) => {
    setContacts(prev => prev.filter(c => c.id !== id));
    setSelectedContactId(null);
  };

  const handleUpdateContact = (id: string, updates: Partial<Contact>) => {
    setContacts(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  };

  const handleLogVisit = (contactId: string, notes: string, nextFollowUp: string) => {
    const newVisit: VisitHistory = {
      id: `h${Date.now()}`,
      date: new Date().toISOString().split('T')[0],
      notes,
      nextFollowUp
    };
    setContacts(prev => prev.map(c => 
      c.id === contactId 
        ? { ...c, lastVisited: newVisit.date, history: [...c.history, newVisit] } 
        : c
    ));
    setIsLoggingVisit(null);
  };

  const handleCreateTrip = (trip: Omit<TripPlan, 'id' | 'isCompleted'>) => {
    const newTrip: TripPlan = { ...trip, id: `t${Date.now()}`, isCompleted: false };
    setTrips(prev => [...prev, newTrip]);
    setIsAddingTrip(false);
  };

  const handleCompleteTrip = (tripId: string) => {
    setTrips(prev => prev.map(t => t.id === tripId ? { ...t, isCompleted: true } : t));
    setSelectedTripId(null);
  };

  const handleCreateList = (name: string) => {
    const newList: CustomList = { id: `l${Date.now()}`, name, peopleIds: [] };
    setCustomLists(prev => [...prev, newList]);
    setIsAddingList(false);
  };

  const handleAddToList = (listId: string, contactId: string) => {
    setCustomLists(prev => prev.map(l => 
      l.id === listId ? { ...l, peopleIds: [...new Set([...l.peopleIds, contactId])] } : l
    ));
    setContacts(prev => prev.map(c => 
      c.id === contactId ? { ...c, listIds: [...new Set([...c.listIds, listId])] } : c
    ));
  };

  const handleRemoveFromList = (listId: string, contactId: string) => {
    setCustomLists(prev => prev.map(l => 
      l.id === listId ? { ...l, peopleIds: l.peopleIds.filter(pid => pid !== contactId) } : l
    ));
    setContacts(prev => prev.map(c => 
      c.id === contactId ? { ...c, listIds: c.listIds.filter(lid => lid !== listId) } : c
    ));
  };

  // --- Views ---
  const renderHome = () => {
    const stats = getStats();
    const upcomingTrips = trips.filter(t => !t.isCompleted).sort((a,b) => a.date.localeCompare(b.date)).slice(0, 3);

    return (
      <div className="p-4 pb-24 space-y-6">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900">फील्ड कनेक्ट</h1>
          <div className="flex gap-2">
            <select 
              value={dashKhand} 
              onChange={(e) => { setDashKhand(e.target.value); setDashMandal('all'); }}
              className="bg-white border text-sm p-1 rounded"
            >
              <option value="all">सभी खंड</option>
              {khands.map(k => <option key={k.id} value={k.id}>{k.name}</option>)}
            </select>
            <select 
              value={dashMandal} 
              onChange={(e) => setDashMandal(e.target.value)}
              className="bg-white border text-sm p-1 rounded"
              disabled={dashKhand === 'all'}
            >
              <option value="all">सभी मंडल</option>
              {mandals.filter(m => m.khandId === dashKhand).map(m => (
                <option key={m.id} value={m.id}>{m.name}</option>
              ))}
            </select>
          </div>
        </header>

        {/* Stats Grid */}
        <div className="grid grid-cols-2 gap-3">
          <StatCard label="कुल शक्ति" value={stats.total} color="bg-blue-100 text-blue-800" />
          <StatCard label="सक्रिय शक्ति" value={stats.active} color="bg-green-100 text-green-800" />
          <StatCard label="संचित शक्ति" value={stats.sanchit} color="bg-yellow-100 text-yellow-800" />
          <StatCard label="सज्जन शक्ति" value={stats.sajjan} color="bg-purple-100 text-purple-800" />
          <StatCard label="उत्सुक शक्ति" value={stats.utsuk} color="bg-orange-100 text-orange-800" />
          <StatCard label="पेंडिंग फॉलो-अप" value={stats.pending} color="bg-red-100 text-red-800" />
        </div>

        {/* Upcoming Section */}
        <section className="space-y-3">
          <h2 className="text-lg font-semibold flex items-center gap-2">
            <CalendarIcon size={20} className="text-blue-600" /> आगामी योजनाएं
          </h2>
          {upcomingTrips.length === 0 ? (
            <p className="text-gray-500 italic">कोई आगामी योजना नहीं है।</p>
          ) : (
            upcomingTrips.map(trip => (
              <div 
                key={trip.id} 
                className="bg-white p-4 rounded-xl shadow-sm border-l-4 border-orange-500 flex justify-between items-center"
                onClick={() => { setSelectedTripId(trip.id); setActiveTab('trips'); }}
              >
                <div>
                  <div className="text-sm text-gray-500">{new Date(trip.date).toLocaleDateString('hi-IN')}</div>
                  <div className="font-semibold">{getMandalName(trip.mandalId)} दौरा</div>
                  <div className="text-xs text-gray-400">{trip.peopleIds.length} लोग शामिल</div>
                </div>
                <ChevronRight size={20} className="text-gray-300" />
              </div>
            ))
          )}
        </section>
      </div>
    );
  };

  const renderPeople = () => {
    if (selectedContactId) {
      const contact = contacts.find(c => c.id === selectedContactId);
      if (!contact) return null;
      return (
        <ContactProfile 
          contact={contact} 
          khands={khands}
          mandals={mandals}
          villages={villages}
          customLists={customLists}
          onBack={() => setSelectedContactId(null)} 
          onDelete={() => handleDeleteContact(contact.id)}
          onUpdate={(updates) => handleUpdateContact(contact.id, updates)}
          onLogVisit={() => setIsLoggingVisit(contact.id)}
          onAddToList={(lid) => handleAddToList(lid, contact.id)}
          onRemoveFromList={(lid) => handleRemoveFromList(lid, contact.id)}
        />
      );
    }

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900">संपर्क सूची</h1>
          <button 
            onClick={() => setIsAddingContact(true)}
            className="bg-blue-600 text-white p-2 rounded-full shadow-lg"
          >
            <Plus size={24} />
          </button>
        </header>

        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text" 
            placeholder="नाम या फोन से खोजें..." 
            className="w-full bg-white border border-gray-200 rounded-xl py-2 pl-10 pr-4 outline-none focus:ring-2 focus:ring-blue-400"
          />
        </div>

        <div className="space-y-3">
          {contacts.map(contact => (
            <div 
              key={contact.id} 
              onClick={() => setSelectedContactId(contact.id)}
              className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex items-center gap-4 active:scale-95 transition-transform"
            >
              <div className={`w-12 h-12 rounded-full flex items-center justify-center text-white font-bold text-lg ${
                contact.status === Status.SAKRIYA ? 'bg-green-500' : 
                contact.status === Status.UTSUK ? 'bg-orange-400' : 'bg-blue-400'
              }`}>
                {contact.name[0]}
              </div>
              <div className="flex-1">
                <div className="font-bold text-gray-800">{contact.name}</div>
                <div className="text-sm text-gray-500">{getMandalName(contact.mandalId)} • {contact.category}</div>
              </div>
              <a 
                href={`tel:${contact.phone}`} 
                onClick={(e) => e.stopPropagation()}
                className="p-2 bg-blue-50 text-blue-600 rounded-full"
              >
                <Phone size={20} />
              </a>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderTrips = () => {
    if (selectedTripId) {
      const trip = trips.find(t => t.id === selectedTripId);
      if (!trip) return null;
      return (
        <TripExecutionView 
          trip={trip}
          contacts={contacts}
          onBack={() => setSelectedTripId(null)}
          onComplete={() => handleCompleteTrip(trip.id)}
          onLogVisit={(cid) => setIsLoggingVisit(cid)}
          getMandalName={getMandalName}
        />
      );
    }

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900">यात्रा योजना</h1>
          <button 
            onClick={() => setIsAddingTrip(true)}
            className="bg-orange-600 text-white p-2 rounded-full shadow-lg"
          >
            <Plus size={24} />
          </button>
        </header>

        <div className="space-y-4">
          <h2 className="text-sm font-semibold uppercase text-gray-400 tracking-wider">सक्रिय योजनाएं</h2>
          {trips.filter(t => !t.isCompleted).map(trip => (
            <div 
              key={trip.id} 
              onClick={() => setSelectedTripId(trip.id)}
              className="bg-white p-4 rounded-xl shadow-sm border-l-4 border-orange-500 space-y-2"
            >
              <div className="flex justify-between items-start">
                <div>
                  <div className="font-bold text-lg">{getMandalName(trip.mandalId)} दौरा</div>
                  <div className="text-sm text-gray-500">{new Date(trip.date).toLocaleDateString('hi-IN', { dateStyle: 'full' })}</div>
                </div>
                <div className="px-2 py-1 bg-orange-100 text-orange-700 text-xs font-bold rounded">लंबित</div>
              </div>
              <div className="text-sm text-gray-600 italic">"{trip.notes}"</div>
              <div className="pt-2 flex items-center justify-between text-xs text-gray-400">
                <span>{trip.peopleIds.length} सदस्य</span>
                <span className="flex items-center gap-1">शुरू करें <ChevronRight size={14} /></span>
              </div>
            </div>
          ))}

          <h2 className="text-sm font-semibold uppercase text-gray-400 tracking-wider pt-4">पूर्ण योजनाएं</h2>
          {trips.filter(t => t.isCompleted).map(trip => (
            <div 
              key={trip.id} 
              className="bg-gray-50 p-4 rounded-xl shadow-sm border-l-4 border-green-500 opacity-75"
            >
              <div className="flex justify-between items-start">
                <div>
                  <div className="font-bold text-gray-700">{getMandalName(trip.mandalId)} दौरा</div>
                  <div className="text-sm text-gray-500">{new Date(trip.date).toLocaleDateString('hi-IN')}</div>
                </div>
                <CheckCircle2 size={20} className="text-green-500" />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderLists = () => {
    if (selectedListId) {
      const list = customLists.find(l => l.id === selectedListId);
      if (!list) return null;
      return (
        <ListView 
          list={list} 
          allContacts={contacts}
          onBack={() => setSelectedListId(null)}
          onRemove={(cid) => handleRemoveFromList(list.id, cid)}
          onAdd={(cid) => handleAddToList(list.id, cid)}
        />
      );
    }

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900">कस्टम सूचियां</h1>
          <button 
            onClick={() => setIsAddingList(true)}
            className="bg-purple-600 text-white p-2 rounded-full shadow-lg"
          >
            <Plus size={24} />
          </button>
        </header>

        <div className="grid grid-cols-1 gap-4">
          {customLists.map(list => (
            <div 
              key={list.id} 
              onClick={() => setSelectedListId(list.id)}
              className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between active:scale-[0.98]"
            >
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-purple-100 text-purple-600 rounded-xl flex items-center justify-center">
                  <List size={24} />
                </div>
                <div>
                  <div className="font-bold text-gray-800">{list.name}</div>
                  <div className="text-sm text-gray-500">{list.peopleIds.length} सदस्य</div>
                </div>
              </div>
              <ChevronRight className="text-gray-300" />
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderCalendar = () => {
    return <CalendarView trips={trips} contacts={contacts} khands={khands} />;
  };

  const renderSettings = () => {
    return (
      <div className="p-4 pb-24 space-y-4">
        <h1 className="text-2xl font-bold text-blue-900">सेटिंग्स (भूगोल प्रबंधन)</h1>

        <div className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100">
          <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
            <MapPin size={20} className="text-blue-600" /> भौगोलिक संरचना
          </h2>

          <div className="space-y-6">
            {khands.map(k => (
              <div key={k.id} className="border-l-4 border-blue-600 pl-4 space-y-2">
                <div className="flex justify-between items-center">
                  <h3 className="font-bold text-blue-900">{k.name}</h3>
                  <Edit2 size={16} className="text-gray-400" />
                </div>
                <div className="ml-2 space-y-1">
                  {mandals.filter(m => m.khandId === k.id).map(m => (
                    <div key={m.id} className="text-sm flex justify-between items-center text-gray-600 bg-gray-50 p-1 rounded">
                      <span>• {m.name}</span>
                      <span className="text-xs bg-white border px-1 rounded">{villages.filter(v => v.mandalId === m.id).length} गांव</span>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>

          <button className="w-full mt-6 py-3 border-2 border-dashed border-gray-300 rounded-xl text-gray-500 font-medium flex items-center justify-center gap-2">
            <Plus size={18} /> नया खंड जोड़ें
          </button>
        </div>
      </div>
    );
  };

  // --- Main Render ---
  return (
    <div className="min-h-screen max-w-md mx-auto relative bg-gray-50 overflow-x-hidden">
      {/* Tab Content */}
      <main className="min-h-screen">
        {activeTab === 'home' && renderHome()}
        {activeTab === 'people' && renderPeople()}
        {activeTab === 'trips' && renderTrips()}
        {activeTab === 'lists' && renderLists()}
        {activeTab === 'calendar' && renderCalendar()}
        {activeTab === 'settings' && renderSettings()}
      </main>

      {/* Bottom Nav */}
      <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-md bg-white border-t border-gray-200 flex justify-around items-center p-2 z-40 shadow-xl rounded-t-3xl bottom-nav">
        <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon={<Home />} label="होम" />
        <NavButton active={activeTab === 'people'} onClick={() => {setActiveTab('people'); setSelectedContactId(null);}} icon={<Users />} label="संपर्क" />
        <NavButton active={activeTab === 'trips'} onClick={() => {setActiveTab('trips'); setSelectedTripId(null);}} icon={<MapPin />} label="यात्रा" />
        <NavButton active={activeTab === 'lists'} onClick={() => {setActiveTab('lists'); setSelectedTripId(null);}} icon={<List />} label="सूचियां" />
        <NavButton active={activeTab === 'calendar'} onClick={() => setActiveTab('calendar')} icon={<CalendarIcon />} label="कैलेंडर" />
        <NavButton active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} icon={<Settings />} label="सेट" />
      </nav>

      {/* Global Modals */}
      {isAddingContact && (
        <ContactFormModal 
          khands={khands} 
          mandals={mandals} 
          villages={villages} 
          onClose={() => setIsAddingContact(false)}
          onSubmit={handleAddContact}
        />
      )}

      {isAddingTrip && (
        <TripFormModal 
          khands={khands}
          mandals={mandals}
          villages={villages}
          contacts={contacts}
          onClose={() => setIsAddingTrip(false)}
          onSubmit={handleCreateTrip}
        />
      )}

      {isLoggingVisit && (
        <VisitLogModal 
          contactName={contacts.find(c => c.id === isLoggingVisit)?.name || ''}
          onClose={() => setIsLoggingVisit(null)}
          onSubmit={(notes, followUp) => handleLogVisit(isLoggingVisit, notes, followUp)}
        />
      )}

      {isAddingList && (
        <SimpleInputModal 
          title="नई सूची बनाएं" 
          placeholder="सूची का नाम..." 
          onClose={() => setIsAddingList(false)} 
          onSubmit={handleCreateList} 
        />
      )}
    </div>
  );
};

// --- Sub-Components ---

const NavButton = ({ active, icon, label, onClick }: { active: boolean, icon: React.ReactNode, label: string, onClick: () => void }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center p-2 rounded-xl transition-colors ${active ? 'text-blue-600 bg-blue-50' : 'text-gray-400'}`}
  >
    {/* Fix: cast icon to React.ReactElement<any> and check validity before cloning to avoid type errors with 'size' prop */}
    {React.isValidElement(icon) ? React.cloneElement(icon as React.ReactElement<any>, { size: 22 }) : icon}
    <span className="text-[10px] mt-1 font-medium">{label}</span>
  </button>
);

const StatCard = ({ label, value, color }: { label: string, value: number, color: string }) => (
  <div className={`${color} p-4 rounded-2xl flex flex-col justify-between shadow-sm`}>
    <div className="text-sm font-medium opacity-80">{label}</div>
    <div className="text-2xl font-bold mt-1">{value}</div>
  </div>
);

// --- Profile View ---
const ContactProfile = ({ 
  contact, 
  onBack, 
  onDelete, 
  onUpdate, 
  onLogVisit, 
  onAddToList, 
  onRemoveFromList,
  khands,
  mandals,
  villages,
  customLists
}: { 
  contact: Contact, 
  onBack: () => void, 
  onDelete: () => void, 
  onUpdate: (u: Partial<Contact>) => void, 
  onLogVisit: () => void,
  onAddToList: (lid: string) => void,
  onRemoveFromList: (lid: string) => void,
  khands: Khand[],
  mandals: Mandal[],
  villages: Village[],
  customLists: CustomList[]
}) => (
  <div className="p-4 pb-24 space-y-6">
    <button onClick={onBack} className="p-2 bg-white rounded-full shadow-sm"><ArrowLeft size={20} /></button>

    <div className="flex flex-col items-center space-y-3">
      <div className="w-24 h-24 bg-blue-500 rounded-full flex items-center justify-center text-white text-3xl font-bold shadow-lg">
        {contact.name[0]}
      </div>
      <div className="text-center">
        <h2 className="text-2xl font-bold text-gray-800">{contact.name}</h2>
        <p className="text-gray-500">{contact.phone}</p>
      </div>
      <div className="flex gap-4">
        <a href={`tel:${contact.phone}`} className="flex items-center gap-2 bg-blue-600 text-white px-6 py-2 rounded-full shadow-md font-medium">
          <Phone size={18} /> कॉल करें
        </a>
        <button onClick={onLogVisit} className="flex items-center gap-2 bg-green-600 text-white px-6 py-2 rounded-full shadow-md font-medium">
          <CheckCircle2 size={18} /> विजिट दर्ज करें
        </button>
      </div>
    </div>

    <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 space-y-4">
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="text-xs font-bold text-gray-400 uppercase">श्रेणी</label>
          <select 
            value={contact.category} 
            onChange={(e) => onUpdate({ category: e.target.value as Category })}
            className="w-full mt-1 font-semibold text-gray-700 outline-none"
