// --- Calendar View ---
const CalendarView = ({ trips, contacts, khands }: any) => {
  const today = new Date();
  const [currMonth, setCurrMonth] = useState(today.getMonth());
  const [currYear, setCurrYear] = useState(today.getFullYear());

  const daysInMonth = new Date(currYear, currMonth + 1, 0).getDate();
  const firstDay = new Date(currYear, currMonth, 1).getDay();

  const getTripsOnDate = (d: number) => {
    const dateStr = `${currYear}-${String(currMonth + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
    return trips.filter((t: any) => t.date === dateStr);
  };

  const monthName = new Intl.DateTimeFormat('hi-IN', { month: 'long' }).format(new Date(currYear, currMonth));

  return (
    <div className="p-4 pb-24 space-y-4">
       <h1 className="text-2xl font-bold text-blue-900">गतिविधि कैलेंडर</h1>

       <div className="bg-white rounded-3xl p-4 shadow-sm border border-gray-100">
         <div className="flex justify-between items-center mb-4">
           <button onClick={() => setCurrMonth(m => m === 0 ? 11 : m - 1)} className="p-2 bg-gray-50 rounded-full">←</button>
           <h2 className="font-bold text-lg">{monthName} {currYear}</h2>
           <button onClick={() => setCurrMonth(m => m === 11 ? 0 : m + 1)} className="p-2 bg-gray-50 rounded-full">→</button>
         </div>

         <div className="grid grid-cols-7 gap-1 text-center mb-2">
           {['र', 'सो', 'म', 'बु', 'गु', 'शु', 'श'].map(d => <div key={d} className="text-xs font-bold text-gray-400">{d}</div>)}
         </div>

         <div className="grid grid-cols-7 gap-2">
           {Array.from({ length: firstDay }).map((_, i) => <div key={`empty-${i}`} />)}
           {Array.from({ length: daysInMonth }).map((_, i) => {
             const day = i + 1;
             const dateTrips = getTripsOnDate(day);
             const isToday = day === today.getDate() && currMonth === today.getMonth() && currYear === today.getFullYear();

             return (
               <div key={day} className={`h-12 flex flex-col items-center justify-center rounded-xl relative ${isToday ? 'bg-blue-600 text-white' : 'bg-gray-50 text-gray-800'}`}>
                 <span className="text-sm font-bold">{day}</span>
                 <div className="flex gap-1 mt-1">
                   {dateTrips.map((t: any) => (
                     <div 
                      key={t.id} 
                      className={`w-1.5 h-1.5 rounded-full ${t.isCompleted ? 'bg-green-500' : t.khandId === 'k1' ? 'bg-orange-500' : 'bg-purple-500'}`} 
                     />
                   ))}
                 </div>
               </div>
             );
           })}
         </div>

         <div className="mt-6 flex flex-wrap gap-4 text-xs">
           <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-green-500"></div> पूर्ण</div>
           <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-orange-500"></div> खंड अ योजना</div>
           <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-purple-500"></div> खंड ब योजना</div>
         </div>
       </div>
    </div>
  );
};

