import React, { useState, useMemo, useEffect } from 'react';
import { 
  Home, 
  Users, 
  MapPin, 
  List, 
  Calendar as CalendarIcon, 
  Settings, 
  Plus, 
  ChevronRight, 
  Phone, 
  Filter, 
  CheckCircle2, 
  ArrowLeft,
  Search,
  Trash2,
  Edit2,
  X,
  Moon,
  Sun
} from 'lucide-react';
import { 
  Category, 
  Status, 
  Khand, 
  Mandal, 
  Village, 
  Contact, 
  TripPlan, 
  CustomList, 
  VisitHistory 
} from './types';
import { 
  INITIAL_KHANDS, 
  INITIAL_MANDALS, 
  INITIAL_VILLAGES, 
  INITIAL_CONTACTS, 
  INITIAL_TRIPS, 
  INITIAL_LISTS 
} from './constants';

type Tab = 'home' | 'people' | 'trips' | 'lists' | 'calendar' | 'settings';

const App: React.FC = () => {
  // --- State ---
  const [activeTab, setActiveTab] = useState<Tab>('home');
  const [khands, setKhands] = useState<Khand[]>(INITIAL_KHANDS);
  const [mandals, setMandals] = useState<Mandal[]>(INITIAL_MANDALS);
  const [villages, setVillages] = useState<Village[]>(INITIAL_VILLAGES);
  const [contacts, setContacts] = useState<Contact[]>(INITIAL_CONTACTS);
  const [trips, setTrips] = useState<TripPlan[]>(INITIAL_TRIPS);
  const [customLists, setCustomLists] = useState<CustomList[]>(INITIAL_LISTS);
  const [darkMode, setDarkMode] = useState(false);

  // Filters for Dashboard/People
  const [dashKhand, setDashKhand] = useState<string>('all');
  const [dashMandal, setDashMandal] = useState<string>('all');
  const [peopleSearch, setPeopleSearch] = useState('');
  const [peopleStatusFilter, setPeopleStatusFilter] = useState<string | 'all'>('all');

  // Selected Item for Detail Views
  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [selectedTripId, setSelectedTripId] = useState<string | null>(null);
  const [selectedListId, setSelectedListId] = useState<string | null>(null);

  // UI Modals
  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isAddingTrip, setIsAddingTrip] = useState(false);
  const [isLoggingVisit, setIsLoggingVisit] = useState<string | null>(null); // contactId
  const [isAddingList, setIsAddingList] = useState(false);
  const [isAddingKhand, setIsAddingKhand] = useState(false);
  const [isAddingMandal, setIsAddingMandal] = useState<string | null>(null); // khandId

  // --- Effects ---
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // --- Helpers ---
  const getKhandName = (id: string) => khands.find(k => k.id === id)?.name || id;
  const getMandalName = (id: string) => mandals.find(m => m.id === id)?.name || id;
  const getVillageName = (id: string) => villages.find(v => v.id === id)?.name || id;

  const getFilteredContacts = (kId: string, mId: string, status: string = 'all') => {
    return contacts.filter(c => 
      (kId === 'all' || c.khandId === kId) && 
      (mId === 'all' || c.mandalId === mId) &&
      (status === 'all' || c.status === status)
    );
  };

  const getStats = () => {
    const filtered = getFilteredContacts(dashKhand, dashMandal);
    return {
      total: filtered.length,
      active: filtered.filter(c => c.status === Status.SAKRIYA).length,
      sanchit: filtered.filter(c => c.status === Status.SANCHIT).length,
      sajjan: filtered.filter(c => c.status === Status.SAJJAN).length,
      utsuk: filtered.filter(c => c.status === Status.UTSUK).length,
      pending: filtered.filter(c => {
         const lastVisit = c.history[c.history.length - 1];
         if (!lastVisit?.nextFollowUp) return false;
         return new Date(lastVisit.nextFollowUp) < new Date();
      }).length
    };
  };

  // --- Handlers ---
  const handleStatClick = (status: string | 'all') => {
    setPeopleStatusFilter(status);
    setActiveTab('people');
  };

  const handleAddContact = (newContact: Omit<Contact, 'id' | 'listIds' | 'history'>) => {
    const contact: Contact = {
      ...newContact,
      id: `c${Date.now()}`,
      listIds: [],
      history: []
    };
    setContacts(prev => [...prev, contact]);
    setIsAddingContact(false);
  };

  const handleDeleteContact = (id: string) => {
    setContacts(prev => prev.filter(c => c.id !== id));
    setSelectedContactId(null);
  };

  const handleUpdateContact = (id: string, updates: Partial<Contact>) => {
    setContacts(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  };

  const handleLogVisit = (contactId: string, notes: string, nextFollowUp: string) => {
    const newVisit: VisitHistory = {
      id: `h${Date.now()}`,
      date: new Date().toISOString().split('T')[0],
      notes,
      nextFollowUp
    };
    setContacts(prev => prev.map(c => 
      c.id === contactId 
        ? { ...c, lastVisited: newVisit.date, history: [...c.history, newVisit] } 
        : c
    ));
    setIsLoggingVisit(null);
  };

  const handleCreateTrip = (trip: Omit<TripPlan, 'id' | 'isCompleted'>) => {
    const newTrip: TripPlan = { ...trip, id: `t${Date.now()}`, isCompleted: false };
    setTrips(prev => [...prev, newTrip]);
    setIsAddingTrip(false);
  };

  const handleCompleteTrip = (tripId: string) => {
    setTrips(prev => prev.map(t => t.id === tripId ? { ...t, isCompleted: true } : t));
    setSelectedTripId(null);
  };

  const handleCreateList = (name: string) => {
    const newList: CustomList = { id: `l${Date.now()}`, name, peopleIds: [] };
    setCustomLists(prev => [...prev, newList]);
    setIsAddingList(false);
  };

  const handleAddToList = (listId: string, contactId: string) => {
    setCustomLists(prev => prev.map(l => 
      l.id === listId ? { ...l, peopleIds: [...new Set([...l.peopleIds, contactId])] } : l
    ));
    setContacts(prev => prev.map(c => 
      c.id === contactId ? { ...c, listIds: [...new Set([...c.listIds, listId])] } : c
    ));
  };

  const handleRemoveFromList = (listId: string, contactId: string) => {
    setCustomLists(prev => prev.map(l => 
      l.id === listId ? { ...l, peopleIds: l.peopleIds.filter(pid => pid !== contactId) } : l
    ));
    setContacts(prev => prev.map(c => 
      c.id === contactId ? { ...c, listIds: c.listIds.filter(lid => lid !== listId) } : c
    ));
  };

  // --- Geography Handlers ---
  const addKhand = (name: string) => {
    setKhands(prev => [...prev, { id: `k${Date.now()}`, name }]);
    setIsAddingKhand(false);
  };

  const deleteKhand = (id: string) => {
    setKhands(prev => prev.filter(k => k.id !== id));
    setMandals(prev => prev.filter(m => m.khandId !== id));
  };

  const addMandal = (name: string, khandId: string) => {
    setMandals(prev => [...prev, { id: `m${Date.now()}`, name, khandId }]);
    setIsAddingMandal(null);
  };

  const deleteMandal = (id: string) => {
    setMandals(prev => prev.filter(m => m.id !== id));
  };

  // --- Views ---
  const renderHome = () => {
    const stats = getStats();

    // Grouping trips by date
    const groupedTrips = useMemo(() => {
      const pending = trips.filter(t => !t.isCompleted).sort((a,b) => a.date.localeCompare(b.date));
      const groups: Record<string, TripPlan[]> = {};
      pending.forEach(t => {
        if (!groups[t.date]) groups[t.date] = [];
        groups[t.date].push(t);
      });
      return Object.entries(groups).slice(0, 3); // Top 3 dates
    }, [trips]);

    return (
      <div className="p-4 pb-24 space-y-6">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">फील्ड कनेक्ट</h1>
          <div className="flex gap-2">
            <select 
              value={dashKhand} 
              onChange={(e) => { setDashKhand(e.target.value); setDashMandal('all'); }}
              className="bg-white dark:bg-gray-800 dark:text-gray-200 border border-gray-200 dark:border-gray-700 text-sm p-1 rounded"
            >
              <option value="all">सभी खंड</option>
              {khands.map(k => <option key={k.id} value={k.id}>{k.name}</option>)}
            </select>
            <select 
              value={dashMandal} 
              onChange={(e) => setDashMandal(e.target.value)}
              className="bg-white dark:bg-gray-800 dark:text-gray-200 border border-gray-200 dark:border-gray-700 text-sm p-1 rounded"
              disabled={dashKhand === 'all'}
            >
              <option value="all">सभी मंडल</option>
              {mandals.filter(m => m.khandId === dashKhand).map(m => (
                <option key={m.id} value={m.id}>{m.name}</option>
              ))}
            </select>
          </div>
        </header>

        {/* Stats Grid */}
        <div className="grid grid-cols-2 gap-3">
          <StatCard label="कुल शक्ति" value={stats.total} color="bg-blue-100 dark:bg-blue-900/40 text-blue-800 dark:text-blue-300" onClick={() => handleStatClick('all')} />
          <StatCard label="सक्रिय शक्ति" value={stats.active} color="bg-green-100 dark:bg-green-900/40 text-green-800 dark:text-green-300" onClick={() => handleStatClick(Status.SAKRIYA)} />
          <StatCard label="संचित शक्ति" value={stats.sanchit} color="bg-yellow-100 dark:bg-yellow-900/40 text-yellow-800 dark:text-yellow-300" onClick={() => handleStatClick(Status.SANCHIT)} />
          <StatCard label="सज्जन शक्ति" value={stats.sajjan} color="bg-purple-100 dark:bg-purple-900/40 text-purple-800 dark:text-purple-300" onClick={() => handleStatClick(Status.SAJJAN)} />
          <StatCard label="उत्सुक शक्ति" value={stats.utsuk} color="bg-orange-100 dark:bg-orange-900/40 text-orange-800 dark:text-orange-300" onClick={() => handleStatClick(Status.UTSUK)} />
          <StatCard label="पेंडिंग फॉलो-अप" value={stats.pending} color="bg-red-100 dark:bg-red-900/40 text-red-800 dark:text-red-300" onClick={() => handleStatClick('pending')} />
        </div>

        {/* Upcoming Section */}
        <section className="space-y-3">
          <h2 className="text-lg font-semibold flex items-center gap-2 dark:text-gray-200">
            <CalendarIcon size={20} className="text-blue-600" /> आगामी योजनाएं
          </h2>
          {groupedTrips.length === 0 ? (
            <p className="text-gray-500 italic">कोई आगामी योजना नहीं है।</p>
          ) : (
            groupedTrips.map(([date, dateTrips]) => (
              <div 
                key={date} 
                className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border-l-4 border-orange-500 space-y-2"
              >
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">{new Date(date).toLocaleDateString('hi-IN', { dateStyle: 'long' })}</span>
                  <span className="text-xs bg-orange-100 dark:bg-orange-900/50 text-orange-600 dark:text-orange-400 px-2 py-0.5 rounded-full">{dateTrips.length} योजनाएं</span>
                </div>
                <div className="space-y-3">
                  {dateTrips.map(trip => (
                    <div 
                      key={trip.id} 
                      className="flex justify-between items-center py-2 border-t border-gray-50 dark:border-gray-700/50"
                      onClick={() => { setSelectedTripId(trip.id); setActiveTab('trips'); }}
                    >
                      <div className="flex-1">
                        <div className="font-semibold dark:text-gray-100">{getMandalName(trip.mandalId)} दौरा</div>
                        <div className="text-xs text-gray-400">{trip.peopleIds.length} सदस्य • {getKhandName(trip.khandId)}</div>
                      </div>
                      <ChevronRight size={18} className="text-gray-300" />
                    </div>
                  ))}
                </div>
              </div>
            ))
          )}
        </section>
      </div>
    );
  };

  const renderPeople = () => {
    if (selectedContactId) {
      const contact = contacts.find(c => c.id === selectedContactId);
      if (!contact) return null;
      return (
        <ContactProfile 
          contact={contact} 
          khands={khands}
          mandals={mandals}
          villages={villages}
          customLists={customLists}
          onBack={() => setSelectedContactId(null)} 
          onDelete={() => handleDeleteContact(contact.id)}
          onUpdate={(updates) => handleUpdateContact(contact.id, updates)}
          onLogVisit={() => setIsLoggingVisit(contact.id)}
          onAddToList={(lid) => handleAddToList(lid, contact.id)}
          onRemoveFromList={(lid) => handleRemoveFromList(lid, contact.id)}
        />
      );
    }

    const filtered = contacts.filter(c => {
      const matchesSearch = c.name.toLowerCase().includes(peopleSearch.toLowerCase()) || c.phone.includes(peopleSearch);
      const matchesStatus = peopleStatusFilter === 'all' || 
                           (peopleStatusFilter === 'pending' ? (c.history.length > 0 && c.history[c.history.length - 1].nextFollowUp ? new Date(c.history[c.history.length - 1].nextFollowUp!) < new Date() : false) : c.status === peopleStatusFilter);
      return matchesSearch && matchesStatus;
    });

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">संपर्क सूची</h1>
          <button 
            onClick={() => setIsAddingContact(true)}
            className="bg-blue-600 text-white p-2 rounded-full shadow-lg"
          >
            <Plus size={24} />
          </button>
        </header>

        <div className="flex gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="खोजें..." 
              value={peopleSearch}
              onChange={(e) => setPeopleSearch(e.target.value)}
              className="w-full bg-white dark:bg-gray-800 dark:text-gray-100 border border-gray-200 dark:border-gray-700 rounded-xl py-2 pl-10 pr-4 outline-none focus:ring-2 focus:ring-blue-400"
            />
          </div>
          <select 
            className="bg-white dark:bg-gray-800 dark:text-gray-200 border border-gray-200 dark:border-gray-700 text-xs px-2 rounded-xl"
            value={peopleStatusFilter}
            onChange={(e) => setPeopleStatusFilter(e.target.value)}
          >
            <option value="all">सभी स्थिति</option>
            <option value="pending">पेंडिंग फॉलो-अप</option>
            {Object.values(Status).map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>

        <div className="space-y-3">
          {filtered.length === 0 ? (
            <div className="text-center py-10 text-gray-400">कोई संपर्क नहीं मिला</div>
          ) : (
            filtered.map(contact => (
              <div 
                key={contact.id} 
                onClick={() => setSelectedContactId(contact.id)}
                className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center gap-4 active:scale-95 transition-transform"
              >
                <div className={`w-12 h-12 rounded-full flex items-center justify-center text-white font-bold text-lg ${
                  contact.status === Status.SAKRIYA ? 'bg-green-500' : 
                  contact.status === Status.UTSUK ? 'bg-orange-400' : 'bg-blue-400'
                }`}>
                  {contact.name[0]}
                </div>
                <div className="flex-1">
                  <div className="font-bold text-gray-800 dark:text-gray-100">{contact.name}</div>
                  <div className="text-sm text-gray-500 dark:text-gray-400">{getMandalName(contact.mandalId)} • {contact.category}</div>
                </div>
                <a 
                  href={`tel:${contact.phone}`} 
                  onClick={(e) => e.stopPropagation()}
                  className="p-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-full"
                >
                  <Phone size={20} />
                </a>
              </div>
            ))
          )}
        </div>
      </div>
    );
  };

  const renderTrips = () => {
    if (selectedTripId) {
      const trip = trips.find(t => t.id === selectedTripId);
      if (!trip) return null;
      return (
        <TripExecutionView 
          trip={trip}
          contacts={contacts}
          onBack={() => setSelectedTripId(null)}
          onComplete={() => handleCompleteTrip(trip.id)}
          onLogVisit={(cid: string) => setIsLoggingVisit(cid)}
          getMandalName={getMandalName}
        />
      );
    }

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">यात्रा योजना</h1>
          <button 
            onClick={() => setIsAddingTrip(true)}
            className="bg-orange-600 text-white p-2 rounded-full shadow-lg"
          >
            <Plus size={24} />
          </button>
        </header>

        <div className="space-y-4">
          <h2 className="text-sm font-semibold uppercase text-gray-400 tracking-wider">सक्रिय योजनाएं</h2>
          {trips.filter(t => !t.isCompleted).map(trip => (
            <div 
              key={trip.id} 
              onClick={() => setSelectedTripId(trip.id)}
              className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border-l-4 border-orange-500 space-y-2"
            >
              <div className="flex justify-between items-start">
                <div>
                  <div className="font-bold text-lg dark:text-gray-100">{getMandalName(trip.mandalId)} दौरा</div>
                  <div className="text-sm text-gray-500">{new Date(trip.date).toLocaleDateString('hi-IN', { dateStyle: 'full' })}</div>
                </div>
                <div className="px-2 py-1 bg-orange-100 dark:bg-orange-900/50 text-orange-700 dark:text-orange-400 text-xs font-bold rounded">लंबित</div>
              </div>
              <div className="text-sm text-gray-600 dark:text-gray-400 italic">"{trip.notes}"</div>
              <div className="pt-2 flex items-center justify-between text-xs text-gray-400">
                <span>{trip.peopleIds.length} सदस्य</span>
                <span className="flex items-center gap-1">शुरू करें <ChevronRight size={14} /></span>
              </div>
            </div>
          ))}

          <h2 className="text-sm font-semibold uppercase text-gray-400 tracking-wider pt-4">पूर्ण योजनाएं</h2>
          {trips.filter(t => t.isCompleted).map(trip => (
            <div 
              key={trip.id} 
              className="bg-gray-50 dark:bg-gray-900/40 p-4 rounded-xl shadow-sm border-l-4 border-green-500 opacity-75"
            >
              <div className="flex justify-between items-start">
                <div>
                  <div className="font-bold text-gray-700 dark:text-gray-300">{getMandalName(trip.mandalId)} दौरा</div>
                  <div className="text-sm text-gray-500">{new Date(trip.date).toLocaleDateString('hi-IN')}</div>
                </div>
                <CheckCircle2 size={20} className="text-green-500" />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderLists = () => {
    if (selectedListId) {
      const list = customLists.find(l => l.id === selectedListId);
      if (!list) return null;
      return (
        <ListView 
          list={list} 
          allContacts={contacts}
          onBack={() => setSelectedListId(null)}
          onRemove={(cid: string) => handleRemoveFromList(list.id, cid)}
          onAdd={(cid: string) => handleAddToList(list.id, cid)}
        />
      );
    }

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">कस्टम सूचियां</h1>
          <button 
            onClick={() => setIsAddingList(true)}
            className="bg-purple-600 text-white p-2 rounded-full shadow-lg"
          >
            <Plus size={24} />
          </button>
        </header>

        <div className="grid grid-cols-1 gap-4">
          {customLists.map(list => (
            <div 
              key={list.id} 
              onClick={() => setSelectedListId(list.id)}
              className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center justify-between active:scale-[0.98]"
            >
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 rounded-xl flex items-center justify-center">
                  <List size={24} />
                </div>
                <div>
                  <div className="font-bold text-gray-800 dark:text-gray-100">{list.name}</div>
                  <div className="text-sm text-gray-500 dark:text-gray-400">{list.peopleIds.length} सदस्य</div>
                </div>
              </div>
              <ChevronRight className="text-gray-300" />
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderCalendar = () => {
    return <CalendarView trips={trips} contacts={contacts} khands={khands} />;
  };

  const renderSettings = () => {
    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">सेटिंग्स</h1>
          <button 
            onClick={() => setDarkMode(!darkMode)}
            className="p-2 bg-white dark:bg-gray-800 rounded-full shadow-sm"
          >
            {darkMode ? <Sun size={24} className="text-yellow-400" /> : <Moon size={24} className="text-blue-600" />}
          </button>
        </header>

        <div className="bg-white dark:bg-gray-800 rounded-2xl p-4 shadow-sm border border-gray-100 dark:border-gray-700">
          <h2 className="text-lg font-bold mb-4 flex items-center justify-between dark:text-gray-100">
            <span className="flex items-center gap-2"><MapPin size={20} className="text-blue-600" /> भौगोलिक संरचना</span>
            <button onClick={() => setIsAddingKhand(true)} className="text-blue-600 text-sm font-bold">+ नया खंड</button>
          </h2>

          <div className="space-y-6">
            {khands.map(k => (
              <div key={k.id} className="border-l-4 border-blue-600 pl-4 space-y-2">
                <div className="flex justify-between items-center">
                  <h3 className="font-bold text-blue-900 dark:text-blue-400">{k.name}</h3>
                  <div className="flex gap-2">
                    <button onClick={() => setIsAddingMandal(k.id)} className="text-[10px] bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-300 px-2 rounded">+ मंडल</button>
                    <button onClick={() => deleteKhand(k.id)} className="text-red-400"><Trash2 size={16} /></button>
                  </div>
                </div>
                <div className="ml-2 space-y-1">
                  {mandals.filter(m => m.khandId === k.id).map(m => (
                    <div key={m.id} className="text-sm flex justify-between items-center text-gray-600 dark:text-gray-400 bg-gray-50 dark:bg-gray-900/40 p-1.5 rounded">
                      <span>• {m.name}</span>
                      <div className="flex items-center gap-2">
                        <span className="text-[10px] bg-white dark:bg-gray-800 border dark:border-gray-700 px-1 rounded">{villages.filter(v => v.mandalId === m.id).length} गांव</span>
                        <button onClick={() => deleteMandal(m.id)} className="text-red-400"><X size={14} /></button>
                      </div>
                    </div>
                  ))}
                  {mandals.filter(m => m.khandId === k.id).length === 0 && (
                    <div className="text-xs text-gray-400 italic">कोई मंडल नहीं</div>
                  )}
                </div>
              </div>
            ))}
            {khands.length === 0 && (
              <div className="text-center py-4 text-gray-400">कोई खंड नहीं है</div>
            )}
          </div>
        </div>
      </div>
    );
  };

  // --- Main Render ---
  return (
    <div className="min-h-screen max-w-md mx-auto relative bg-gray-50 dark:bg-gray-950 overflow-x-hidden transition-colors duration-200">
      {/* Tab Content */}
      <main className="min-h-screen">
        {activeTab === 'home' && renderHome()}
        {activeTab === 'people' && renderPeople()}
        {activeTab === 'trips' && renderTrips()}
        {activeTab === 'lists' && renderLists()}
        {activeTab === 'calendar' && renderCalendar()}
        {activeTab === 'settings' && renderSettings()}
      </main>

      {/* Bottom Nav */}
      <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-md bg-white dark:bg-gray-900 border-t border-gray-200 dark:border-gray-800 flex justify-around items-center p-2 z-40 shadow-xl rounded-t-3xl bottom-nav transition-colors">
        <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon={<Home />} label="होम" />
        <NavButton active={activeTab === 'people'} onClick={() => {setActiveTab('people'); setSelectedContactId(null); setPeopleStatusFilter('all');}} icon={<Users />} label="संपर्क" />
        <NavButton active={activeTab === 'trips'} onClick={() => {setActiveTab('trips'); setSelectedTripId(null);}} icon={<MapPin />} label="यात्रा" />
        <NavButton active={activeTab === 'lists'} onClick={() => {setActiveTab('lists'); setSelectedListId(null);}} icon={<List />} label="सूचियां" />
        <NavButton active={activeTab === 'calendar'} onClick={() => setActiveTab('calendar')} icon={<CalendarIcon />} label="कैलेंडर" />
        <NavButton active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} icon={<Settings />} label="सेट" />
      </nav>

      {/* Global Modals */}
      {isAddingContact && (
        <ContactFormModal 
          khands={khands} 
          mandals={mandals} 
          villages={villages} 
          onClose={() => setIsAddingContact(false)}
          onSubmit={handleAddContact}
        />
      )}

      {isAddingTrip && (
        <TripFormModal 
          khands={khands}
          mandals={mandals}
          villages={villages}
          contacts={contacts}
          onClose={() => setIsAddingTrip(false)}
          onSubmit={handleCreateTrip}
        />
      )}

      {isLoggingVisit && (
        <VisitLogModal 
          contactName={contacts.find(c => c.id === isLoggingVisit)?.name || ''}
          onClose={() => setIsLoggingVisit(null)}
          onSubmit={(notes: string, followUp: string) => handleLogVisit(isLoggingVisit!, notes, followUp)}
        />
      )}

      {isAddingList && (
        <SimpleInputModal 
          title="नई सूची बनाएं" 
          placeholder="सूची का नाम..." 
          onClose={() => setIsAddingList(false)} 
          onSubmit={handleCreateList} 
        />
      )}

      {isAddingKhand && (
        <SimpleInputModal 
          title="नया खंड जोड़ें" 
          placeholder="खंड का नाम..." 
          onClose={() => setIsAddingKhand(false)} 
          onSubmit={addKhand} 
        />
      )}

      {isAddingMandal && (
        <SimpleInputModal 
          title="नया मंडल जोड़ें" 
          placeholder="मंडल का नाम..." 
          onClose={() => setIsAddingMandal(null)} 
          onSubmit={(name: string) => addMandal(name, isAddingMandal!)} 
        />
      )}
    </div>
  );
};

// --- Sub-Components ---

const NavButton = ({ active, icon, label, onClick }: { active: boolean, icon: React.ReactNode, label: string, onClick: () => void }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center p-2 rounded-xl transition-colors ${active ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/30' : 'text-gray-400 dark:text-gray-600'}`}
  >
    {React.cloneElement(icon as React.ReactElement<any>, { size: 22 })}
    <span className="text-[10px] mt-1 font-medium">{label}</span>
  </button>
);

const StatCard = ({ label, value, color, onClick }: { label: string, value: number, color: string, onClick?: () => void }) => (
  <div onClick={onClick} className={`${color} p-4 rounded-2xl flex flex-col justify-between shadow-sm active:scale-95 transition-all cursor-pointer`}>
    <div className="text-sm font-medium opacity-80">{label}</div>
