  const [category, setCategory] = useState(Category.KARYAKARTA);
  const [status, setStatus] = useState(Status.SAKRIYA);

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-end">
      <div className="bg-white dark:bg-gray-900 w-full max-w-md mx-auto rounded-t-3xl p-6 space-y-4 max-h-[90vh] overflow-y-auto animate-in slide-in-from-bottom">
        <h2 className="text-xl font-bold dark:text-gray-100">नया संपर्क जोड़ें</h2>
        <input placeholder="पूरा नाम" className="w-full p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl outline-none" value={name} onChange={e => setName(e.target.value)} />
        <input placeholder="मोबाइल नंबर" className="w-full p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl outline-none" value={phone} onChange={e => setPhone(e.target.value)} />

        <div className="grid grid-cols-2 gap-2">
          <select value={khandId} onChange={e => {setKhandId(e.target.value); setMandalId('');}} className="p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl outline-none">
            <option value="">खंड चुनें</option>
            {khands.map((k: any) => <option key={k.id} value={k.id}>{k.name}</option>)}
          </select>
          <select value={mandalId} onChange={e => {setMandalId(e.target.value); setVillageId('');}} className="p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl outline-none" disabled={!khandId}>
            <option value="">मंडल चुनें</option>
            {mandals.filter((m: any) => m.khandId === khandId).map((m: any) => <option key={m.id} value={m.id}>{m.name}</option>)}
          </select>
        </div>

        <select value={villageId} onChange={e => setVillageId(e.target.value)} className="w-full p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl outline-none" disabled={!mandalId}>
          <option value="">गांव चुनें</option>
          {villages.filter((v: any) => v.mandalId === mandalId).map((v: any) => <option key={v.id} value={v.id}>{v.name}</option>)}
        </select>

        <div className="grid grid-cols-2 gap-2">
           <select value={category} onChange={e => setCategory(e.target.value as Category)} className="p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl outline-none">
             {Object.values(Category).map(v => <option key={v} value={v}>{v}</option>)}
           </select>
           <select value={status} onChange={e => setStatus(e.target.value as Status)} className="p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl outline-none">
             {Object.values(Status).map(v => <option key={v} value={v}>{v}</option>)}
           </select>
        </div>

        <div className="flex gap-2 pt-4">
          <button onClick={onClose} className="flex-1 py-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-400 font-bold rounded-xl">रद्द करें</button>
          <button 
            onClick={() => onSubmit({ name, phone, khandId, mandalId, villageId, category, status })} 
            className="flex-1 py-3 bg-blue-600 text-white font-bold rounded-xl"
            disabled={!name || !phone || !villageId}
          >
            सुरक्षित करें
          </button>
        </div>
      </div>
    </div>
  );
};

