        <div className="grid grid-cols-2 gap-2">
          <select value={khandId} onChange={e => {setKhandId(e.target.value); setMandalId('');}} className="p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl outline-none">
            <option value="">खंड चुनें</option>
            {khands.map((k: any) => <option key={k.id} value={k.id}>{k.name}</option>)}
          </select>
          <select value={mandalId} onChange={e => setMandalId(e.target.value)} className="p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl outline-none" disabled={!khandId}>
            <option value="">मंडल चुनें</option>
            {mandals.filter((m: any) => m.khandId === khandId).map((m: any) => <option key={m.id} value={m.id}>{m.name}</option>)}
          </select>
        </div>

        <div className="space-y-2">
          <label className="text-xs font-bold text-gray-400 dark:text-gray-500 uppercase">सदस्य चुनें</label>
          <div className="max-h-40 overflow-y-auto bg-gray-50 dark:bg-gray-800 p-2 rounded-xl space-y-1">
            {filteredContacts.map((c: Contact) => (
              <label key={c.id} className="flex items-center gap-2 p-1">
                <input 
                  type="checkbox" 
                  checked={selectedPeople.includes(c.id)} 
                  onChange={e => {
                    if (e.target.checked) setSelectedPeople([...selectedPeople, c.id]);
                    else setSelectedPeople(selectedPeople.filter(id => id !== c.id));
                  }}
                />
                <span className="text-sm dark:text-gray-300">{c.name}</span>
              </label>
            ))}
          </div>
        </div>

        <textarea placeholder="मुख्य उद्देश्य..." className="w-full p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl outline-none min-h-[100px]" value={notes} onChange={e => setNotes(e.target.value)} />

        <div className="flex gap-2 pt-4">
          <button onClick={onClose} className="flex-1 py-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-400 font-bold rounded-xl">रद्द करें</button>
          <button 
            onClick={() => onSubmit({ date, khandId, mandalId, villageIds: [], peopleIds: selectedPeople, notes })} 
            className="flex-1 py-3 bg-orange-600 text-white font-bold rounded-xl"
            disabled={!mandalId || selectedPeople.length === 0}
          >
            योजना सुरक्षित करें
          </button>
        </div>
      </div>
    </div>
  );
};

