  const tripPeople = contacts.filter((c: Contact) => trip.peopleIds.includes(c.id));

  return (
    <div className="p-4 pb-24 space-y-4">
      <div className="flex items-center justify-between">
        <button onClick={onBack} className="p-2 bg-white dark:bg-gray-800 dark:text-gray-200 rounded-full shadow-sm"><ArrowLeft size={20} /></button>
        <button onClick={onComplete} className="bg-green-600 text-white px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2">
          <CheckCircle2 size={16} /> पूरा हो गया
        </button>
      </div>

      <div>
        <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-100">{getMandalName(trip.mandalId)} दौरा</h2>
        <p className="text-gray-500 dark:text-gray-400">{new Date(trip.date).toLocaleDateString('hi-IN')}</p>
        <p className="mt-2 p-3 bg-orange-50 dark:bg-orange-900/30 text-orange-800 dark:text-orange-300 rounded-xl text-sm italic">"{trip.notes}"</p>
      </div>

      <div className="space-y-4 pt-4">
        <h3 className="font-bold flex items-center gap-2 text-gray-400 dark:text-gray-500 uppercase text-xs">मिलने वाले लोग ({tripPeople.length})</h3>
        {tripPeople.map((c: Contact) => (
          <div key={c.id} className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-gray-100 dark:bg-gray-900 dark:text-gray-300 rounded-full flex items-center justify-center font-bold">{c.name[0]}</div>
              <div>
                <div className="font-bold dark:text-gray-100">{c.name}</div>
                <div className="text-xs text-gray-500 dark:text-gray-400">{c.phone}</div>
              </div>
            </div>
            <div className="flex gap-2">
              <a href={`tel:${c.phone}`} className="p-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-full"><Phone size={18} /></a>
              <button onClick={() => onLogVisit(c.id)} className="p-2 bg-green-50 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-full"><CheckCircle2 size={18} /></button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
