  const nonMembers = allContacts.filter((c: Contact) => !list.peopleIds.includes(c.id) && c.name.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="p-4 pb-24 space-y-4">
      <div className="flex items-center justify-between">
        <button onClick={onBack} className="p-2 bg-white dark:bg-gray-800 dark:text-gray-200 rounded-full shadow-sm"><ArrowLeft size={20} /></button>
