        <div className="bg-white dark:bg-gray-800 p-4 rounded-2xl border-2 border-purple-200 dark:border-purple-800 space-y-4 animate-in slide-in-from-top">
          <input 
            type="text" 
            placeholder="नाम खोजें..." 
            className="w-full bg-gray-50 dark:bg-gray-900 dark:text-gray-100 p-2 rounded-lg border dark:border-gray-700 outline-none"
