            {nonMembers.map((c: Contact) => (
              <div key={c.id} className="flex items-center justify-between p-2 hover:bg-gray-50 dark:hover:bg-gray-700 rounded transition-colors">
                <span className="font-medium dark:text-gray-200">{c.name}</span>
                <button onClick={() => onAdd(c.id)} className="text-purple-600 dark:text-purple-400 font-bold text-sm">+ जोड़ें</button>
