  const [notes, setNotes] = useState('');
  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center p-4">
      <div className="bg-white dark:bg-gray-900 w-full rounded-3xl p-6 space-y-4 animate-in zoom-in duration-300">
        <h2 className="text-xl font-bold dark:text-white">{contactName} - रिपोर्ट</h2>
        <textarea placeholder="मुख्य चर्चा..." className="w-full p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-xl min-h-[100px]" value={notes} onChange={e=>setNotes(e.target.value)} />
        <div className="flex gap-2">
          <button onClick={onClose} className="flex-1 p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-400 font-bold rounded-xl">रद्द</button>
          <button onClick={()=>onSubmit(notes, '')} className="flex-1 p-3 bg-green-600 text-white font-bold rounded-xl">दर्ज करें</button>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Home, 
  Users, 
  MapPin, 
  List, 
  Calendar as CalendarIcon, 
  Settings, 
  Plus, 
  ChevronRight, 
  Phone, 
  CheckCircle2, 
  ArrowLeft,
  Search,
  Trash2,
  X,
  Moon,
  Sun,
  LayoutGrid,
  Building2,
  UserPlus,
  BarChart3
} from 'lucide-react';
import { 
  Category, 
  Status, 
  Khand, 
  Mandal, 
  Village, 
  Contact, 
  TripPlan, 
  CustomList, 
  VisitHistory,
  VillageStage,
  ShakhaPosition,
  ShakhaData
} from './types';
import { 
  INITIAL_KHANDS, 
  INITIAL_MANDALS, 
  INITIAL_VILLAGES, 
  INITIAL_CONTACTS, 
  INITIAL_TRIPS, 
  INITIAL_LISTS 
} from './constants';

type Tab = 'home' | 'people' | 'trips' | 'lists' | 'work-status' | 'calendar' | 'settings';

const App: React.FC = () => {
  // --- State ---
  const [activeTab, setActiveTab] = useState<Tab>('home');
  const [khands, setKhands] = useState<Khand[]>(INITIAL_KHANDS);
  const [mandals, setMandals] = useState<Mandal[]>(INITIAL_MANDALS);
  const [villages, setVillages] = useState<Village[]>(INITIAL_VILLAGES);
  const [contacts, setContacts] = useState<Contact[]>(INITIAL_CONTACTS);
  const [trips, setTrips] = useState<TripPlan[]>(INITIAL_TRIPS);
  const [customLists, setCustomLists] = useState<CustomList[]>(INITIAL_LISTS);
  const [darkMode, setDarkMode] = useState(false);

  // Filters
  const [dashKhand, setDashKhand] = useState<string>('all');
  const [peopleSearch, setPeopleSearch] = useState('');
  const [peopleStatusFilter, setPeopleStatusFilter] = useState<string | 'all'>('all');
  const [workStatusSearch, setWorkStatusSearch] = useState('');

  // Selected Items
  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [selectedTripId, setSelectedTripId] = useState<string | null>(null);
  const [selectedVillageId, setSelectedVillageId] = useState<string | null>(null);

  // Modals
  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isAddingTrip, setIsAddingTrip] = useState(false);
  const [isLoggingVisit, setIsLoggingVisit] = useState<string | null>(null);

  // --- Effects ---
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // --- Helpers & Memos ---
  const getKhandName = (id: string) => khands.find(k => k.id === id)?.name || id;
  const getMandalName = (id: string) => mandals.find(m => m.id === id)?.name || id;
  const getVillageName = (id: string) => villages.find(v => v.id === id)?.name || id;

  const groupedTrips = useMemo(() => {
    const pending = trips.filter(t => !t.isCompleted).sort((a,b) => a.date.localeCompare(b.date));
    const groups: Record<string, TripPlan[]> = {};
    pending.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return Object.entries(groups).slice(0, 3);
  }, [trips]);

  const stats = useMemo(() => {
    const filteredContacts = contacts.filter(c => dashKhand === 'all' || c.khandId === dashKhand);

    const villageStats = villages.reduce((acc, v) => {
      acc[v.stage] = (acc[v.stage] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return {
      total: filteredContacts.length,
      active: filteredContacts.filter(c => c.status === Status.SAKRIYA).length,
      sanchit: filteredContacts.filter(c => c.status === Status.SANCHIT).length,
      sajjan: filteredContacts.filter(c => c.status === Status.SAJJAN).length,
      utsuk: filteredContacts.filter(c => c.status === Status.UTSUK).length,
      pending: filteredContacts.filter(c => {
         const lastVisit = c.history[c.history.length - 1];
         if (!lastVisit?.nextFollowUp) return false;
         return new Date(lastVisit.nextFollowUp) < new Date();
      }).length,
      villages: villageStats
    };
  }, [contacts, villages, dashKhand]);

  // --- Handlers ---
  const handleStatClick = (filter: string | 'all') => {
    setPeopleStatusFilter(filter);
    setActiveTab('people');
    setSelectedContactId(null);
  };

  const handleWorkStatClick = () => {
    setActiveTab('work-status');
    setSelectedVillageId(null);
  };

  const handleAddContact = (newContact: Omit<Contact, 'id' | 'listIds' | 'history'>) => {
    const contact: Contact = { ...newContact, id: `c${Date.now()}`, listIds: [], history: [] };
    setContacts(prev => [...prev, contact]);
    setIsAddingContact(false);
  };

  const handleUpdateContact = (id: string, updates: Partial<Contact>) => {
    setContacts(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  };

  const handleDeleteContact = (id: string) => {
    setContacts(prev => prev.filter(c => c.id !== id));
    setSelectedContactId(null);
  };

  const handleLogVisit = (contactId: string, notes: string, nextFollowUp: string) => {
    const newVisit: VisitHistory = { id: `h${Date.now()}`, date: new Date().toISOString().split('T')[0], notes, nextFollowUp };
    setContacts(prev => prev.map(c => c.id === contactId ? { ...c, lastVisited: newVisit.date, history: [...c.history, newVisit] } : c));
    setIsLoggingVisit(null);
  };

  const updateVillageStage = (villageId: string, stage: VillageStage) => {
    setVillages(prev => prev.map(v => v.id === villageId ? { ...v, stage } : v));
  };

  const updateShakhaData = (villageId: string, data: Partial<ShakhaData>) => {
    setVillages(prev => prev.map(v => v.id === villageId ? { 
      ...v, 
      shakhaData: { 
        shakhaName: v.shakhaData?.shakhaName || '', 
        positions: v.shakhaData?.positions || {}, 
        ...data 
      } 
    } : v));
  };

  // --- Views ---

  const renderHome = () => (
    <div className="p-4 pb-24 space-y-6">
      <header className="flex justify-between items-center">
        <div>
           <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">फील्ड कनेक्ट</h1>
           <p className="text-xs text-gray-500 font-medium">कार्यकर्ता प्रबंधन प्रणाली</p>
        </div>
        <button onClick={() => setDarkMode(!darkMode)} className="p-2 bg-white dark:bg-gray-800 rounded-full shadow-sm border dark:border-gray-700">
          {darkMode ? <Sun size={20} className="text-yellow-400" /> : <Moon size={20} className="text-blue-600" />}
        </button>
      </header>

      <section className="space-y-3">
        <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">संपर्क डैशबोर्ड</h2>
        <div className="grid grid-cols-2 gap-3">
          <StatCard label="कुल शक्ति" value={stats.total} color="bg-blue-50 dark:bg-blue-900/20 text-blue-800 dark:text-blue-300 border-blue-100 dark:border-blue-800" onClick={() => handleStatClick('all')} />
          <StatCard label="सक्रिय शक्ति" value={stats.active} color="bg-green-50 dark:bg-green-900/20 text-green-800 dark:text-green-300 border-green-100 dark:border-green-800" onClick={() => handleStatClick(Status.SAKRIYA)} />
          <StatCard label="संचित शक्ति" value={stats.sanchit} color="bg-indigo-50 dark:bg-indigo-900/20 text-indigo-800 dark:text-indigo-300 border-indigo-100 dark:border-indigo-800" onClick={() => handleStatClick(Status.SANCHIT)} />
          <StatCard label="सज्जन शक्ति" value={stats.sajjan} color="bg-purple-50 dark:bg-purple-900/20 text-purple-800 dark:text-purple-300 border-purple-100 dark:border-purple-800" onClick={() => handleStatClick(Status.SAJJAN)} />
          <StatCard label="उत्सुक शक्ति" value={stats.utsuk} color="bg-orange-50 dark:bg-orange-900/20 text-orange-800 dark:text-orange-300 border-orange-100 dark:border-orange-800" onClick={() => handleStatClick(Status.UTSUK)} />
          <StatCard label="पेंडिंग फॉलो-अप" value={stats.pending} color="bg-red-50 dark:bg-red-900/20 text-red-800 dark:text-red-300 border-red-100 dark:border-red-800" onClick={() => handleStatClick('pending')} />
        </div>
      </section>

      <section className="space-y-3">
        <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">कार्यस्थिति सारांश</h2>
        <div 
          onClick={handleWorkStatClick}
          className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border dark:border-gray-700 grid grid-cols-3 divide-x dark:divide-gray-700 text-center cursor-pointer active:scale-[0.98] transition-all"
        >
          <div className="flex flex-col gap-1">
            <span className="text-[10px] font-bold text-orange-600 dark:text-orange-400 uppercase">शाखा</span>
            <span className="text-xl font-bold dark:text-white">{stats.villages[VillageStage.SHAKHA] || 0}</span>
          </div>
          <div className="flex flex-col gap-1">
            <span className="text-[10px] font-bold text-blue-600 dark:text-blue-400 uppercase">मिलन</span>
            <span className="text-xl font-bold dark:text-white">{stats.villages[VillageStage.MILAN] || 0}</span>
          </div>
          <div className="flex flex-col gap-1">
            <span className="text-[10px] font-bold text-purple-600 dark:text-purple-400 uppercase">मंडली</span>
            <span className="text-xl font-bold dark:text-white">{stats.villages[VillageStage.MANDALI] || 0}</span>
          </div>
        </div>
      </section>

      <section className="space-y-3">
        <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">आगामी योजनाएं</h2>
        {groupedTrips.length > 0 ? groupedTrips.map(([date, dateTrips]) => (
          <div key={date} className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border dark:border-gray-700 border-l-4 border-l-orange-500">
            <span className="text-[10px] font-bold text-gray-400 block mb-2">{new Date(date).toLocaleDateString('hi-IN', { dateStyle: 'long' })}</span>
            {dateTrips.map(trip => (
              <div key={trip.id} className="flex justify-between items-center py-2 border-t dark:border-gray-700/50 first:border-t-0" onClick={() => { setSelectedTripId(trip.id); setActiveTab('trips'); }}>
                <div>
                  <div className="font-semibold text-sm dark:text-gray-100">{getMandalName(trip.mandalId)} दौरा</div>
                  <div className="text-[10px] text-gray-400 uppercase">{trip.peopleIds.length} सदस्य निर्धारित</div>
                </div>
                <ChevronRight size={18} className="text-gray-300" />
              </div>
            ))}
          </div>
        )) : (
          <div className="bg-white dark:bg-gray-800 p-8 rounded-2xl text-center border dark:border-gray-700 border-dashed">
            <CalendarIcon size={32} className="mx-auto text-gray-300 mb-2" />
            <p className="text-gray-400 text-sm italic">कोई आगामी योजना नहीं है</p>
          </div>
        )}
      </section>
    </div>
  );

  const renderPeople = () => {
    if (selectedContactId) {
      const contact = contacts.find(c => c.id === selectedContactId);
      if (!contact) return null;
      return (
        <ContactProfile 
          contact={contact} 
          khands={khands} mandals={mandals} villages={villages} customLists={customLists}
          onBack={() => setSelectedContactId(null)} 
          onDelete={() => handleDeleteContact(contact.id)}
          onUpdate={(updates) => handleUpdateContact(contact.id, updates)}
          onLogVisit={() => setIsLoggingVisit(contact.id)}
        />
      );
    }

    const filtered = contacts.filter(c => {
      const matchesSearch = c.name.toLowerCase().includes(peopleSearch.toLowerCase()) || c.phone.includes(peopleSearch);

      const matchesStatus = peopleStatusFilter === 'all' || 
                           (peopleStatusFilter === 'pending' 
                              ? (c.history.length > 0 && c.history[c.history.length - 1].nextFollowUp 
                                  ? new Date(c.history[c.history.length - 1].nextFollowUp!) < new Date() 
                                  : false) 
                              : c.status === peopleStatusFilter);

      return matchesSearch && matchesStatus;
    });

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">संपर्क सूची</h1>
          <div className="flex gap-2">
            {peopleStatusFilter !== 'all' && (
               <button 
                onClick={() => setPeopleStatusFilter('all')}
                className="bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 px-3 py-1 rounded-full text-xs font-bold border dark:border-gray-700"
               >
                 साफ करें (X)
               </button>
            )}
            <button onClick={() => setIsAddingContact(true)} className="bg-blue-600 text-white p-2 rounded-full shadow-lg"><Plus size={24} /></button>
          </div>
        </header>

        <div className="flex flex-col gap-2">
           {peopleStatusFilter !== 'all' && (
              <div className="bg-blue-50 dark:bg-blue-900/30 p-2 rounded-lg text-xs font-bold text-blue-700 dark:text-blue-300 border border-blue-100 dark:border-blue-800 flex justify-between">
                <span>दिखा रहा है: {peopleStatusFilter === 'pending' ? 'पेंडिंग फॉलो-अप' : peopleStatusFilter}</span>
                <span>{filtered.length} परिणाम</span>
              </div>
           )}
           <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input type="text" placeholder="खोजें (नाम या मोबाइल)..." value={peopleSearch} onChange={(e) => setPeopleSearch(e.target.value)} className="w-full bg-white dark:bg-gray-800 dark:text-gray-100 border dark:border-gray-700 rounded-xl py-3 pl-10 pr-4 outline-none shadow-sm focus:ring-2 focus:ring-blue-500/20" />
          </div>
        </div>

        <div className="space-y-3">
          {filtered.length > 0 ? filtered.map(contact => (
            <div key={contact.id} onClick={() => setSelectedContactId(contact.id)} className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center gap-4 active:scale-95 transition-transform">
              <div className="w-12 h-12 rounded-full bg-blue-500 flex items-center justify-center text-white font-bold text-lg shadow-inner">{contact.name[0]}</div>
              <div className="flex-1">
                <div className="font-bold dark:text-gray-100">{contact.name}</div>
                <div className="text-[10px] text-gray-500 dark:text-gray-400 uppercase font-bold tracking-wider">{getMandalName(contact.mandalId)} • {contact.category}</div>
              </div>
              <a href={`tel:${contact.phone}`} onClick={(e) => e.stopPropagation()} className="p-3 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-full"><Phone size={20} /></a>
            </div>
          )) : (
            <div className="text-center py-20 text-gray-400">
              <Users size={48} className="mx-auto opacity-20 mb-4" />
              <p>कोई संपर्क नहीं मिला</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderWorkStatus = () => {
    if (selectedVillageId) {
      const village = villages.find(v => v.id === selectedVillageId);
      if (!village) return null;
      return (
        <VillageWorkStatusDetail 
          village={village} 
          contacts={contacts}
          onBack={() => setSelectedVillageId(null)}
          onUpdateStage={(stage) => updateVillageStage(village.id, stage)}
          onUpdateShakhaData={(data) => updateShakhaData(village.id, data)}
        />
      );
    }

    const filteredVillages = villages.filter(v => v.name.toLowerCase().includes(workStatusSearch.toLowerCase()));

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">कार्यस्थिति</h1>
          <Building2 className="text-blue-600" />
        </header>
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input type="text" placeholder="गांव खोजें..." value={workStatusSearch} onChange={(e) => setWorkStatusSearch(e.target.value)} className="w-full bg-white dark:bg-gray-800 dark:text-gray-100 border dark:border-gray-700 rounded-xl py-3 pl-10 pr-4 outline-none shadow-sm" />
        </div>

        <div className="space-y-6">
          {mandals.map(m => {
            const mandalVillages = filteredVillages.filter(v => v.mandalId === m.id);
            if (mandalVillages.length === 0) return null;
            return (
              <div key={m.id} className="space-y-2">
                <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] px-1 flex items-center gap-2">
                   <LayoutGrid size={12} /> {m.name}
                </h3>
                <div className="grid grid-cols-1 gap-2">
                  {mandalVillages.map(v => (
                    <div 
                      key={v.id} 
                      onClick={() => setSelectedVillageId(v.id)}
                      className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex justify-between items-center active:scale-[0.98] transition-all"
                    >
                      <div>
                        <div className="font-bold dark:text-gray-100">{v.name}</div>
                        {v.stage === VillageStage.SHAKHA && v.shakhaData?.shakhaName && (
                          <div className="text-[10px] text-orange-600 dark:text-orange-400 font-bold uppercase mt-1">शाखा: {v.shakhaData.shakhaName}</div>
                        )}
                      </div>
                      <span className={`text-[10px] px-3 py-1 rounded-full font-bold uppercase tracking-wider ${
                        v.stage === VillageStage.SHAKHA ? 'bg-orange-100 text-orange-700 dark:bg-orange-900/40 dark:text-orange-300' :
                        v.stage === VillageStage.MILAN ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300' :
                        v.stage === VillageStage.MANDALI ? 'bg-purple-100 text-purple-700 dark:bg-purple-900/40 dark:text-purple-300' :
                        'bg-gray-100 text-gray-500 dark:bg-gray-700 dark:text-gray-400'
                      }`}>
                        {v.stage}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const renderTrips = () => (
    <div className="p-4 pb-24 space-y-4">
      <header className="flex justify-between items-center">
        <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">यात्रा योजना</h1>
        <button onClick={() => setIsAddingTrip(true)} className="bg-orange-600 text-white p-2 rounded-full shadow-lg"><Plus size={24} /></button>
      </header>
      <div className="space-y-4">
        {trips.map(trip => (
          <div key={trip.id} className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border dark:border-gray-700 border-l-4 border-l-orange-500">
            <div className="flex justify-between items-start">
              <div>
                <div className="font-bold text-lg dark:text-gray-100">{getMandalName(trip.mandalId)} दौरा</div>
                <div className="text-xs text-gray-500 font-medium">{new Date(trip.date).toLocaleDateString('hi-IN', { dateStyle: 'full' })}</div>
              </div>
              <span className={`text-[10px] px-2 py-1 rounded-full font-bold uppercase tracking-wider ${trip.isCompleted ? 'bg-green-100 text-green-700 dark:bg-green-900/40 dark:text-green-300' : 'bg-orange-100 text-orange-700 dark:bg-orange-900/40 dark:text-orange-300'}`}>
                {trip.isCompleted ? 'पूर्ण' : 'लंबित'}
              </span>
            </div>
            <p className="mt-3 text-sm text-gray-600 dark:text-gray-400 italic bg-gray-50 dark:bg-gray-900/40 p-3 rounded-xl border border-dashed dark:border-gray-700">"{trip.notes}"</p>
          </div>
        ))}
      </div>
    </div>
  );

  const renderSettings = () => (
    <div className="p-4 pb-24 space-y-4">
       <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">सेटिंग्स</h1>
       <div className="bg-white dark:bg-gray-800 rounded-3xl p-4 shadow-sm space-y-4 border dark:border-gray-700">
          <div className="flex items-center justify-between p-3 border-b dark:border-gray-700 last:border-0">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-xl"><Moon size={20} /></div>
              <span className="font-bold dark:text-gray-200">डार्क मोड इंटरफ़ेस</span>
            </div>
            <button onClick={() => setDarkMode(!darkMode)} className="p-1 bg-gray-100 dark:bg-gray-700 rounded-full w-12 flex justify-start items-center relative transition-all duration-300">
               <div className={`w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-all ${darkMode ? 'translate-x-4 bg-blue-600' : 'bg-white'}`}>
                 {darkMode ? <Moon size={12} className="text-white" /> : <Sun size={12} className="text-yellow-500" />}
               </div>
            </button>
          </div>
          <div className="flex items-center gap-3 p-3 text-gray-400">
            <BarChart3 size={20} />
            <span className="text-xs font-bold uppercase tracking-widest">ऐप वर्जन 1.0.5</span>
          </div>
       </div>
    </div>
  );

  return (
    <div className="min-h-screen max-w-md mx-auto relative bg-gray-50 dark:bg-gray-950 transition-colors duration-200">
      <main className="min-h-screen">
        {activeTab === 'home' && renderHome()}
        {activeTab === 'people' && renderPeople()}
        {activeTab === 'trips' && renderTrips()}
        {activeTab === 'work-status' && renderWorkStatus()}
        {activeTab === 'settings' && renderSettings()}
      </main>

      <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-md bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg border-t border-gray-200 dark:border-gray-800 flex justify-around items-center p-3 z-40 shadow-2xl rounded-t-[2.5rem]">
        <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon={<Home />} label="होम" />
        <NavButton active={activeTab === 'people'} onClick={() => {setActiveTab('people'); setSelectedContactId(null); setPeopleStatusFilter('all');}} icon={<Users />} label="संपर्क" />
        <NavButton active={activeTab === 'work-status'} onClick={() => {setActiveTab('work-status'); setSelectedVillageId(null);}} icon={<LayoutGrid />} label="कार्यस्थिति" />
        <NavButton active={activeTab === 'trips'} onClick={() => setActiveTab('trips')} icon={<MapPin />} label="यात्रा" />
        <NavButton active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} icon={<Settings />} label="सेट" />
      </nav>

      {isAddingContact && (
        <ContactFormModal 
          khands={khands} mandals={mandals} villages={villages} 
          onClose={() => setIsAddingContact(false)} 
          onSubmit={handleAddContact} 
        />
      )}

      {isLoggingVisit && (
        <VisitLogModal 
          contactName={contacts.find(c => c.id === isLoggingVisit)?.name || ''} 
          onClose={() => setIsLoggingVisit(null)} 
          onSubmit={(notes, followUp) => handleLogVisit(isLoggingVisit!, notes, followUp)} 
        />
      )}
    </div>
  );
};

