      <div className="bg-white dark:bg-gray-900 w-full rounded-t-[3rem] p-8 space-y-5 max-h-[90vh] overflow-y-auto animate-in slide-in-from-bottom duration-500 shadow-2xl">
        <div className="w-12 h-1.5 bg-gray-200 dark:bg-gray-700 rounded-full mx-auto mb-2" />
        <h2 className="text-2xl font-black dark:text-white tracking-tight">नया संपर्क जोड़ें</h2>

        <div className="space-y-4">
           <input placeholder="पूर्ण नाम" className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-bold focus:ring-2 focus:ring-blue-500/20" value={name} onChange={e=>setName(e.target.value)} />
           <input placeholder="मोबाइल नंबर" type="tel" className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-bold focus:ring-2 focus:ring-blue-500/20" value={phone} onChange={e=>setPhone(e.target.value)} />

           <div className="grid grid-cols-2 gap-3">
             <select className="p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-bold text-sm" value={mandalId} onChange={e=>setMandalId(e.target.value)}>
               <option value="">मंडल चुनें</option>
               {mandals.map((m: any) => <option key={m.id} value={m.id}>{m.name}</option>)}
             </select>
             <select className="p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-bold text-sm" value={villageId} onChange={e=>setVillageId(e.target.value)}>
               <option value="">गांव चुनें</option>
               {villages.filter((v: any)=>v.mandalId===mandalId).map((v: any) => <option key={v.id} value={v.id}>{v.name}</option>)}
             </select>
           </div>

           <div className="space-y-1">
             <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">कार्यकर्ता श्रेणी</label>
             <select className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-bold text-sm" value={cat} onChange={e=>setCat(e.target.value as Category)}>
               {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
             </select>
           </div>
        </div>

        <div className="flex gap-4 pt-4">
          <button onClick={onClose} className="flex-1 p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-400 font-bold rounded-2xl active:scale-95 transition-all">रद्द करें</button>
          <button 
            disabled={!name || !phone || !villageId}
            onClick={()=>onSubmit({ name, phone, mandalId, villageId, category: cat, status: Status.SAKRIYA, khandId: mandals.find((m: any)=>m.id===mandalId)?.khandId || '' })} 
            className="flex-1 p-4 bg-blue-600 text-white font-bold rounded-2xl shadow-lg shadow-blue-500/30 active:scale-95 transition-all disabled:opacity-50"
          >
            सुरक्षित करें
          </button>
        </div>
      </div>
    </div>
  );
};

const VisitLogModal = ({ contactName, onClose, onSubmit }: any) => {
  const [notes, setNotes] = useState('');
  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center p-6">
      <div className="bg-white dark:bg-gray-900 w-full rounded-[2.5rem] p-8 space-y-6 animate-in zoom-in duration-300 shadow-2xl">
        <div className="text-center space-y-1">
           <h2 className="text-2xl font-black dark:text-white tracking-tight">{contactName}</h2>
           <p className="text-xs font-bold text-gray-500 uppercase tracking-widest">मुलाकात का विवरण</p>
        </div>
        <textarea 
          placeholder="आज की बैठक में क्या चर्चा हुई?..." 
          className="w-full p-5 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-3xl min-h-[160px] outline-none font-medium border dark:border-gray-700 focus:ring-2 focus:ring-green-500/20" 
          value={notes} 
          onChange={e=>setNotes(e.target.value)} 
        />
        <div className="flex gap-3">
          <button onClick={onClose} className="flex-1 p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-400 font-bold rounded-2xl active:scale-95 transition-all">रद्द</button>
          <button 
            disabled={!notes}
            onClick={()=>onSubmit(notes, '')} 
            className="flex-1 p-4 bg-green-600 text-white font-bold rounded-2xl shadow-lg shadow-green-500/30 active:scale-95 transition-all disabled:opacity-50"
          >
            दर्ज करें
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Home, 
  Users, 
  MapPin, 
  List, 
  Calendar as CalendarIcon, 
  Settings, 
  Plus, 
  ChevronRight, 
  Phone, 
  CheckCircle2, 
  ArrowLeft,
  Search,
  Trash2,
  X,
  Moon,
  Sun,
  LayoutGrid,
  Building2,
  UserPlus,
  BarChart3,
  Map,
  Edit2,
  ChevronDown,
  Filter
} from 'lucide-react';
import { 
  Category, 
  Status, 
  Khand, 
  Mandal, 
  Village, 
  Contact, 
  TripPlan, 
  CustomList, 
  VisitHistory,
  VillageStage,
  ShakhaPosition,
  ShakhaData
} from './types';
import { 
  INITIAL_KHANDS, 
  INITIAL_MANDALS, 
  INITIAL_VILLAGES, 
  INITIAL_CONTACTS, 
  INITIAL_TRIPS, 
  INITIAL_LISTS 
} from './constants';

type Tab = 'home' | 'people' | 'trips' | 'lists' | 'work-status' | 'calendar' | 'settings' | 'area-mgmt';

const App: React.FC = () => {
  // --- State ---
  const [activeTab, setActiveTab] = useState<Tab>('home');
  const [khands, setKhands] = useState<Khand[]>(INITIAL_KHANDS);
  const [mandals, setMandals] = useState<Mandal[]>(INITIAL_MANDALS);
  const [villages, setVillages] = useState<Village[]>(INITIAL_VILLAGES);
  const [contacts, setContacts] = useState<Contact[]>(INITIAL_CONTACTS);
  const [trips, setTrips] = useState<TripPlan[]>(INITIAL_TRIPS);
  const [customLists, setCustomLists] = useState<CustomList[]>(INITIAL_LISTS);
  const [darkMode, setDarkMode] = useState(false);

  // Global Filters (Shared between Home and People)
  const [dashKhand, setDashKhand] = useState<string>('all');
  const [dashMandal, setDashMandal] = useState<string>('all');

  // People specific
  const [peopleSearch, setPeopleSearch] = useState('');
  const [peopleStatusFilter, setPeopleStatusFilter] = useState<string | 'all'>('all');

  // Work Status specific
  const [workStatusSearch, setWorkStatusSearch] = useState('');

  // Selected Items
  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [selectedTripId, setSelectedTripId] = useState<string | null>(null);
  const [selectedVillageId, setSelectedVillageId] = useState<string | null>(null);

  // Area Management State
  const [editingItem, setEditingItem] = useState<{ type: 'khand' | 'mandal' | 'village', id?: string, parentId?: string, name: string } | null>(null);

  // Modals
  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isAddingTrip, setIsAddingTrip] = useState(false);
  const [isLoggingVisit, setIsLoggingVisit] = useState<string | null>(null);

  // --- Effects ---
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // --- Helpers & Memos ---
  const getKhandName = (id: string) => khands.find(k => k.id === id)?.name || id;
  const getMandalName = (id: string) => mandals.find(m => m.id === id)?.name || id;
  const getVillageName = (id: string) => villages.find(v => v.id === id)?.name || id;

  const groupedTrips = useMemo(() => {
    const pending = trips.filter(t => !t.isCompleted).sort((a,b) => a.date.localeCompare(b.date));
    const groups: Record<string, TripPlan[]> = {};
    pending.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return Object.entries(groups).slice(0, 3);
  }, [trips]);

  const stats = useMemo(() => {
    const filteredContacts = contacts.filter(c => {
      const kMatch = dashKhand === 'all' || c.khandId === dashKhand;
      const mMatch = dashMandal === 'all' || c.mandalId === dashMandal;
      return kMatch && mMatch;
    });

    const villageStats = villages.filter(v => {
      const mandal = mandals.find(m => m.id === v.mandalId);
      if (!mandal) return false;
      const kMatch = dashKhand === 'all' || mandal.khandId === dashKhand;
      const mMatch = dashMandal === 'all' || v.mandalId === dashMandal;
      return kMatch && mMatch;
    }).reduce((acc, v) => {
      acc[v.stage] = (acc[v.stage] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return {
      total: filteredContacts.length,
      active: filteredContacts.filter(c => c.status === Status.SAKRIYA).length,
      sanchit: filteredContacts.filter(c => c.status === Status.SANCHIT).length,
      sajjan: filteredContacts.filter(c => c.status === Status.SAJJAN).length,
      utsuk: filteredContacts.filter(c => c.status === Status.UTSUK).length,
      pending: filteredContacts.filter(c => {
         const lastVisit = c.history[c.history.length - 1];
         if (!lastVisit?.nextFollowUp) return false;
         return new Date(lastVisit.nextFollowUp) < new Date();
      }).length,
      villages: villageStats
    };
  }, [contacts, villages, mandals, dashKhand, dashMandal]);

  // --- Handlers ---
  const handleStatClick = (filter: string | 'all') => {
    setPeopleStatusFilter(filter);
    setActiveTab('people');
    setSelectedContactId(null);
  };

  const handleWorkStatClick = () => {
    setActiveTab('work-status');
    setSelectedVillageId(null);
  };

  const handleAddContact = (newContact: Omit<Contact, 'id' | 'listIds' | 'history'>) => {
    const contact: Contact = { ...newContact, id: `c${Date.now()}`, listIds: [], history: [] };
    setContacts(prev => [...prev, contact]);
    setIsAddingContact(false);
  };

  const handleUpdateContact = (id: string, updates: Partial<Contact>) => {
    setContacts(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  };

  const handleDeleteContact = (id: string) => {
    setContacts(prev => prev.filter(c => c.id !== id));
    setSelectedContactId(null);
  };

  const handleAddTrip = (newTrip: Omit<TripPlan, 'id' | 'isCompleted'>) => {
    const trip: TripPlan = { ...newTrip, id: `t${Date.now()}`, isCompleted: false };
    setTrips(prev => [...prev, trip]);
    setIsAddingTrip(false);
  };

  const handleDeleteTrip = (id: string) => {
    setTrips(prev => prev.filter(t => t.id !== id));
    setSelectedTripId(null);
  };

  const handleToggleTripCompletion = (id: string) => {
    setTrips(prev => prev.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t));
  };

  const handleLogVisit = (contactId: string, notes: string, nextFollowUp: string) => {
    const newVisit: VisitHistory = { id: `h${Date.now()}`, date: new Date().toISOString().split('T')[0], notes, nextFollowUp };
    setContacts(prev => prev.map(c => c.id === contactId ? { ...c, lastVisited: newVisit.date, history: [...c.history, newVisit] } : c));
    setIsLoggingVisit(null);
  };

  const updateVillageStage = (villageId: string, stage: VillageStage) => {
    setVillages(prev => prev.map(v => v.id === villageId ? { ...v, stage } : v));
  };

  const updateShakhaData = (villageId: string, data: Partial<ShakhaData>) => {
    setVillages(prev => prev.map(v => v.id === villageId ? { 
      ...v, 
      shakhaData: { 
        shakhaName: v.shakhaData?.shakhaName || '', 
        positions: v.shakhaData?.positions || {}, 
        ...data 
      } 
    } : v));
  };

  const handleSaveAreaItem = () => {
    if (!editingItem) return;
    const { type, id, name, parentId } = editingItem;

    if (type === 'khand') {
      if (id) setKhands(prev => prev.map(k => k.id === id ? { ...k, name } : k));
      else setKhands(prev => [...prev, { id: `k${Date.now()}`, name }]);
    } else if (type === 'mandal') {
      if (id) setMandals(prev => prev.map(m => m.id === id ? { ...m, name } : m));
      else setMandals(prev => [...prev, { id: `m${Date.now()}`, name, khandId: parentId! }]);
    } else if (type === 'village') {
      if (id) setVillages(prev => prev.map(v => v.id === id ? { ...v, name } : v));
      else setVillages(prev => [...prev, { id: `v${Date.now()}`, name, mandalId: parentId!, stage: VillageStage.NONE }]);
    }
    setEditingItem(null);
  };

  const handleDeleteAreaItem = (type: 'khand' | 'mandal' | 'village', id: string) => {
    if (type === 'khand') {
      setKhands(prev => prev.filter(k => k.id !== id));
      setMandals(prev => prev.filter(m => m.khandId !== id));
    } else if (type === 'mandal') {
      setMandals(prev => prev.filter(m => m.id !== id));
      setVillages(prev => prev.filter(v => v.mandalId !== id));
    } else if (type === 'village') {
      setVillages(prev => prev.filter(v => v.id !== id));
    }
  };

  // --- Views ---

  const renderHome = () => (
    <div className="p-4 pb-24 space-y-6">
      <header className="flex justify-between items-center">
        <div>
           <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">फील्ड कनेक्ट</h1>
           <p className="text-xs text-gray-500 font-medium">कार्यकर्ता प्रबंधन प्रणाली</p>
        </div>
        <button onClick={() => setDarkMode(!darkMode)} className="p-2 bg-white dark:bg-gray-800 rounded-full shadow-sm border dark:border-gray-700">
          {darkMode ? <Sun size={20} className="text-yellow-400" /> : <Moon size={20} className="text-blue-600" />}
        </button>
      </header>

      {/* Area Filters */}
      <section className="bg-white dark:bg-gray-800 p-5 rounded-[2rem] shadow-sm border dark:border-gray-700 space-y-4">
        <div className="flex items-center gap-2 px-1">
          <Filter size={14} className="text-blue-600" />
          <h2 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">क्षेत्र चयन</h2>
        </div>
        <div className="grid grid-cols-2 gap-3">
          <div className="relative">
            <label className="text-[10px] text-gray-400 absolute left-3 -top-2 bg-white dark:bg-gray-800 px-1 font-bold z-10">खंड</label>
            <select 
              value={dashKhand} 
              onChange={(e) => { setDashKhand(e.target.value); setDashMandal('all'); }}
              className="w-full bg-gray-50 dark:bg-gray-900 dark:text-gray-100 p-3 rounded-xl border dark:border-gray-700 font-bold text-sm appearance-none outline-none"
            >
              <option value="all">सभी खंड</option>
              {khands.map(k => <option key={k.id} value={k.id}>{k.name}</option>)}
            </select>
            <ChevronDown size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
          </div>
          <div className="relative">
            <label className="text-[10px] text-gray-400 absolute left-3 -top-2 bg-white dark:bg-gray-800 px-1 font-bold z-10">मंडल</label>
            <select 
              value={dashMandal} 
              disabled={dashKhand === 'all'}
              onChange={(e) => setDashMandal(e.target.value)}
              className="w-full bg-gray-50 dark:bg-gray-900 dark:text-gray-100 p-3 rounded-xl border dark:border-gray-700 font-bold text-sm appearance-none outline-none disabled:opacity-50"
            >
              <option value="all">सभी मंडल</option>
              {mandals.filter(m => m.khandId === dashKhand).map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
            <ChevronDown size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
          </div>
        </div>
      </section>

      <section className="space-y-3">
        <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">संपर्क डैशबोर्ड</h2>
        <div className="grid grid-cols-2 gap-3">
          <StatCard label="कुल शक्ति" value={stats.total} color="bg-blue-50 dark:bg-blue-900/20 text-blue-800 dark:text-blue-300 border-blue-100 dark:border-blue-800" onClick={() => handleStatClick('all')} />
          <StatCard label="सक्रिय शक्ति" value={stats.active} color="bg-green-50 dark:bg-green-900/20 text-green-800 dark:text-green-300 border-green-100 dark:border-green-800" onClick={() => handleStatClick(Status.SAKRIYA)} />
          <StatCard label="संचित शक्ति" value={stats.sanchit} color="bg-indigo-50 dark:bg-indigo-900/20 text-indigo-800 dark:text-indigo-300 border-indigo-100 dark:border-indigo-800" onClick={() => handleStatClick(Status.SANCHIT)} />
          <StatCard label="सज्जन शक्ति" value={stats.sajjan} color="bg-purple-50 dark:bg-purple-900/20 text-purple-800 dark:text-purple-300 border-purple-100 dark:border-purple-800" onClick={() => handleStatClick(Status.SAJJAN)} />
          <StatCard label="उत्सुक शक्ति" value={stats.utsuk} color="bg-orange-50 dark:bg-orange-900/20 text-orange-800 dark:text-orange-300 border-orange-100 dark:border-orange-800" onClick={() => handleStatClick(Status.UTSUK)} />
          <StatCard label="पेंडिंग फॉलो-अप" value={stats.pending} color="bg-red-50 dark:bg-red-900/20 text-red-800 dark:text-red-300 border-red-100 dark:border-red-800" onClick={() => handleStatClick('pending')} />
        </div>
      </section>

      <section className="space-y-3">
        <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">कार्यस्थिति सारांश</h2>
        <div 
          onClick={handleWorkStatClick}
          className="bg-white dark:bg-gray-800 p-5 rounded-[2rem] shadow-sm border dark:border-gray-700 grid grid-cols-3 divide-x dark:divide-gray-700 text-center cursor-pointer active:scale-[0.98] transition-all"
        >
          <div className="flex flex-col gap-1">
            <span className="text-[10px] font-bold text-orange-600 dark:text-orange-400 uppercase">शाखा</span>
            <span className="text-xl font-bold dark:text-white">{stats.villages[VillageStage.SHAKHA] || 0}</span>
          </div>
          <div className="flex flex-col gap-1">
            <span className="text-[10px] font-bold text-blue-600 dark:text-blue-400 uppercase">मिलन</span>
            <span className="text-xl font-bold dark:text-white">{stats.villages[VillageStage.MILAN] || 0}</span>
          </div>
          <div className="flex flex-col gap-1">
            <span className="text-[10px] font-bold text-purple-600 dark:text-purple-400 uppercase">मंडली</span>
            <span className="text-xl font-bold dark:text-white">{stats.villages[VillageStage.MANDALI] || 0}</span>
          </div>
        </div>
      </section>

      <section className="space-y-3">
        <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">आगामी योजनाएं</h2>
        {groupedTrips.length > 0 ? groupedTrips.map(([date, dateTrips]) => (
          <div key={date} className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border dark:border-gray-700 border-l-4 border-l-orange-500">
            <span className="text-[10px] font-bold text-gray-400 block mb-2">{new Date(date).toLocaleDateString('hi-IN', { dateStyle: 'long' })}</span>
            {dateTrips.map(trip => (
              <div key={trip.id} className="flex justify-between items-center py-2 border-t dark:border-gray-700/50 first:border-t-0" onClick={() => { setSelectedTripId(trip.id); setActiveTab('trips'); }}>
                <div>
                  <div className="font-semibold text-sm dark:text-gray-100">{getMandalName(trip.mandalId)} दौरा</div>
                  <div className="text-[10px] text-gray-400 uppercase">{trip.peopleIds.length} सदस्य निर्धारित</div>
                </div>
                <ChevronRight size={18} className="text-gray-300" />
              </div>
            ))}
          </div>
        )) : (
          <div className="bg-white dark:bg-gray-800 p-8 rounded-2xl text-center border dark:border-gray-700 border-dashed">
            <CalendarIcon size={32} className="mx-auto text-gray-300 mb-2" />
            <p className="text-gray-400 text-sm italic">कोई आगामी योजना नहीं है</p>
          </div>
        )}
      </section>
    </div>
  );

  const renderPeople = () => {
    if (selectedContactId) {
      const contact = contacts.find(c => c.id === selectedContactId);
      if (!contact) return null;
      return (
        <ContactProfile 
          contact={contact} 
          khands={khands} mandals={mandals} villages={villages} customLists={customLists}
          onBack={() => setSelectedContactId(null)} 
          onDelete={() => handleDeleteContact(contact.id)}
          onUpdate={(updates) => handleUpdateContact(contact.id, updates)}
          onLogVisit={() => setIsLoggingVisit(contact.id)}
        />
      );
    }

    const filtered = contacts.filter(c => {
      const matchesSearch = c.name.toLowerCase().includes(peopleSearch.toLowerCase()) || c.phone.includes(peopleSearch);

      const matchesStatus = peopleStatusFilter === 'all' || 
                           (peopleStatusFilter === 'pending' 
                              ? (c.history.length > 0 && c.history[c.history.length - 1].nextFollowUp 
                                  ? new Date(c.history[c.history.length - 1].nextFollowUp!) < new Date() 
                                  : false) 
                              : c.status === peopleStatusFilter);

      const kMatch = dashKhand === 'all' || c.khandId === dashKhand;
      const mMatch = dashMandal === 'all' || c.mandalId === dashMandal;

      return matchesSearch && matchesStatus && kMatch && mMatch;
    });

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">संपर्क सूची</h1>
          <div className="flex gap-2">
            {(peopleStatusFilter !== 'all' || dashKhand !== 'all' || dashMandal !== 'all') && (
               <button 
                onClick={() => { setPeopleStatusFilter('all'); setDashKhand('all'); setDashMandal('all'); }}
                className="bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 px-3 py-1 rounded-full text-[10px] font-bold border dark:border-gray-700 flex items-center gap-1"
               >
                 <X size={10} /> फ़िल्टर हटाएँ
               </button>
            )}
            <button onClick={() => setIsAddingContact(true)} className="bg-blue-600 text-white p-2 rounded-full shadow-lg"><Plus size={24} /></button>
          </div>
        </header>

        <div className="flex flex-col gap-3">
           {/* Area display if filtered */}
           {(dashKhand !== 'all' || dashMandal !== 'all') && (
              <div className="bg-blue-50 dark:bg-blue-900/30 p-2.5 rounded-xl border border-blue-100 dark:border-blue-800 flex flex-wrap gap-2 items-center">
                <MapPin size={12} className="text-blue-600" />
                <span className="text-[10px] font-bold text-blue-800 dark:text-blue-300">
                  {dashKhand !== 'all' && getKhandName(dashKhand)}
                  {dashMandal !== 'all' && ` • ${getMandalName(dashMandal)}`}
                </span>
                <span className="text-[10px] ml-auto bg-blue-100 dark:bg-blue-800 px-2 py-0.5 rounded-full font-bold">{filtered.length} सदस्य</span>
              </div>
           )}

           <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input type="text" placeholder="नाम या मोबाइल नंबर..." value={peopleSearch} onChange={(e) => setPeopleSearch(e.target.value)} className="w-full bg-white dark:bg-gray-800 dark:text-gray-100 border dark:border-gray-700 rounded-xl py-3 pl-10 pr-4 outline-none shadow-sm focus:ring-2 focus:ring-blue-500/20" />
          </div>

          <div className="flex overflow-x-auto gap-2 pb-1 scrollbar-hide no-scrollbar">
            {['all', Status.SAKRIYA, Status.SANCHIT, Status.SAJJAN, Status.UTSUK, 'pending'].map(f => (
              <button 
                key={f}
                onClick={() => setPeopleStatusFilter(f)}
                className={`whitespace-nowrap px-4 py-1.5 rounded-full text-[10px] font-bold border transition-all ${
                  peopleStatusFilter === f 
                    ? 'bg-blue-600 text-white border-blue-600' 
                    : 'bg-white dark:bg-gray-800 text-gray-500 border-gray-200 dark:border-gray-700'
                }`}
              >
                {f === 'all' ? 'सभी' : f === 'pending' ? 'पेंडिंग' : f}
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-3">
          {filtered.length > 0 ? filtered.map(contact => (
            <div key={contact.id} onClick={() => setSelectedContactId(contact.id)} className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center gap-4 active:scale-95 transition-transform">
              <div className="w-12 h-12 rounded-full bg-blue-500 flex items-center justify-center text-white font-bold text-lg shadow-inner">{contact.name[0]}</div>
              <div className="flex-1">
                <div className="font-bold dark:text-gray-100">{contact.name}</div>
                <div className="text-[10px] text-gray-500 dark:text-gray-400 uppercase font-bold tracking-wider">
                  {getKhandName(contact.khandId)} • {getMandalName(contact.mandalId)}
                </div>
              </div>
              <a href={`tel:${contact.phone}`} onClick={(e) => e.stopPropagation()} className="p-3 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-full"><Phone size={20} /></a>
            </div>
          )) : (
            <div className="text-center py-20 text-gray-400">
              <Users size={48} className="mx-auto opacity-20 mb-4" />
              <p>कोई संपर्क नहीं मिला</p>
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderTrips = () => {
    if (selectedTripId) {
      const trip = trips.find(t => t.id === selectedTripId);
      if (!trip) return null;
      return (
        <TripDetail 
          trip={trip}
          mandals={mandals}
          villages={villages}
          contacts={contacts}
          onBack={() => setSelectedTripId(null)}
          onDelete={() => handleDeleteTrip(trip.id)}
          onToggleComplete={() => handleToggleTripCompletion(trip.id)}
        />
      );
    }

    const pending = trips.filter(t => !t.isCompleted).sort((a, b) => a.date.localeCompare(b.date));
    const completed = trips.filter(t => t.isCompleted).sort((a, b) => b.date.localeCompare(a.date));

    return (
      <div className="p-4 pb-24 space-y-6">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">यात्रा योजना</h1>
          <button onClick={() => setIsAddingTrip(true)} className="bg-orange-600 text-white p-2 rounded-full shadow-lg"><Plus size={24} /></button>
        </header>

        <section className="space-y-3">
          <h2 className="text-xs font-bold text-gray-400 uppercase tracking-widest px-1">आगामी (Pending)</h2>
          {pending.length > 0 ? pending.map(trip => (
            <TripCard key={trip.id} trip={trip} mandalName={getMandalName(trip.mandalId)} onClick={() => setSelectedTripId(trip.id)} />
          )) : (
            <div className="bg-white dark:bg-gray-800 p-8 rounded-2xl text-center border dark:border-gray-700 border-dashed">
              <CalendarIcon size={32} className="mx-auto text-gray-300 mb-2" />
              <p className="text-gray-400 text-sm italic">कोई लंबित यात्रा नहीं है</p>
            </div>
          )}
        </section>

        {completed.length > 0 && (
          <section className="space-y-3 pt-4">
            <h2 className="text-xs font-bold text-gray-400 uppercase tracking-widest px-1">पूर्ण (Completed)</h2>
            {completed.map(trip => (
              <TripCard key={trip.id} trip={trip} mandalName={getMandalName(trip.mandalId)} onClick={() => setSelectedTripId(trip.id)} isCompleted />
            ))}
          </section>
        )}
      </div>
    );
  };

  const renderAreaManagement = () => (
    <div className="p-4 pb-24 space-y-6 animate-in slide-in-from-right duration-300">
      <header className="flex items-center gap-4">
        <button onClick={() => setActiveTab('settings')} className="p-2 bg-white dark:bg-gray-800 rounded-full shadow-sm border dark:border-gray-700"><ArrowLeft size={20} className="dark:text-gray-200"/></button>
        <h1 className="text-xl font-bold dark:text-white">क्षेत्र प्रबंधन</h1>
      </header>

      <section className="space-y-5">
        <div className="flex justify-between items-center px-1">
          <h2 className="font-bold text-gray-400 uppercase text-[10px] tracking-widest">खंड एवं मंडल संरचना</h2>
          <button onClick={() => setEditingItem({ type: 'khand', name: '' })} className="text-blue-600 text-[10px] font-bold flex items-center gap-1 bg-blue-50 dark:bg-blue-900/30 px-3 py-2 rounded-xl"><Plus size={14}/> नया खंड</button>
        </div>
        <div className="space-y-4">
          {khands.map(k => (
            <div key={k.id} className="bg-white dark:bg-gray-800 rounded-3xl border dark:border-gray-700 overflow-hidden shadow-sm">
              <div className="p-4 flex justify-between items-center bg-gray-50/50 dark:bg-gray-900/20 border-b dark:border-gray-700">
                <div className="flex items-center gap-2">
                  <div className="p-1.5 bg-blue-600 text-white rounded-lg"><Map size={14}/></div>
                  <div className="font-black text-sm dark:text-white">{k.name}</div>
                </div>
                <div className="flex gap-1">
                   <button onClick={() => setEditingItem({ type: 'khand', id: k.id, name: k.name })} className="p-2 text-gray-400 hover:text-blue-600"><Edit2 size={16}/></button>
                   <button onClick={() => handleDeleteAreaItem('khand', k.id)} className="p-2 text-gray-400 hover:text-red-600"><Trash2 size={16}/></button>
                </div>
              </div>
              <div className="p-4 space-y-3">
                <div className="flex justify-between items-center">
                  <span className="text-[10px] font-bold text-gray-400 uppercase tracking-tight">अंतर्गत मंडल</span>
                  <button onClick={() => setEditingItem({ type: 'mandal', parentId: k.id, name: '' })} className="text-[10px] font-bold text-blue-600 flex items-center gap-1"><Plus size={12}/> मंडल जोड़ें</button>
                </div>
                <div className="grid grid-cols-1 gap-2">
                  {mandals.filter(m => m.khandId === k.id).map(m => (
                    <div key={m.id} className="bg-gray-50 dark:bg-gray-900/50 p-3 rounded-2xl border dark:border-gray-700 flex flex-col gap-3">
                      <div className="flex justify-between items-center">
                        <div className="font-bold dark:text-gray-200 text-sm">{m.name}</div>
                        <div className="flex items-center gap-1">
                           <button onClick={() => setEditingItem({ type: 'mandal', id: m.id, parentId: k.id, name: m.name })} className="p-1.5 text-gray-400 hover:text-blue-600"><Edit2 size={14}/></button>
                           <button onClick={() => handleDeleteAreaItem('mandal', m.id)} className="p-1.5 text-gray-400 hover:text-red-600"><Trash2 size={14}/></button>
                        </div>
                      </div>

                      {/* Villages List inside Mandal */}
                      <div className="border-t dark:border-gray-700/50 pt-2 space-y-2">
                         <div className="flex justify-between items-center">
                           <span className="text-[9px] font-bold text-gray-400 uppercase">गांव ({villages.filter(v => v.mandalId === m.id).length})</span>
                           <button onClick={() => setEditingItem({ type: 'village', parentId: m.id, name: '' })} className="text-[9px] font-bold text-orange-600 flex items-center gap-1"><Plus size={10}/> गांव जोड़ें</button>
                         </div>
                         <div className="flex flex-wrap gap-1.5">
                            {villages.filter(v => v.mandalId === m.id).map(v => (
                              <div key={v.id} className="bg-white dark:bg-gray-800 px-2.5 py-1 rounded-lg border dark:border-gray-700 text-[10px] font-bold dark:text-gray-300 flex items-center gap-2">
                                {v.name}
                                <button onClick={() => setEditingItem({ type: 'village', id: v.id, parentId: m.id, name: v.name })} className="text-gray-400 hover:text-blue-600"><Edit2 size={8}/></button>
                                <button onClick={() => handleDeleteAreaItem('village', v.id)} className="text-gray-400 hover:text-red-600"><Trash2 size={8}/></button>
                              </div>
                            ))}
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {editingItem && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[60] flex items-center p-6">
          <div className="bg-white dark:bg-gray-900 w-full rounded-[2.5rem] p-8 space-y-6 shadow-2xl animate-in zoom-in duration-300">
            <h2 className="text-xl font-black dark:text-white tracking-tight">
               {editingItem.id ? 'संपादित करें' : 'नया'} {editingItem.type === 'khand' ? 'खंड' : editingItem.type === 'mandal' ? 'मंडल' : 'गांव'}
            </h2>
            <input 
              autoFocus
              className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-white rounded-2xl outline-none border dark:border-gray-700 font-bold focus:ring-2 focus:ring-blue-500/20"
              placeholder="नाम लिखें..."
              value={editingItem.name}
              onChange={e => setEditingItem({ ...editingItem, name: e.target.value })}
            />
            <div className="flex gap-3">
              <button onClick={() => setEditingItem(null)} className="flex-1 p-4 bg-gray-100 dark:bg-gray-800 text-gray-500 font-bold rounded-2xl">रद्द</button>
              <button 
                onClick={handleSaveAreaItem}
                disabled={!editingItem.name}
                className="flex-1 p-4 bg-blue-600 text-white font-bold rounded-2xl shadow-lg shadow-blue-500/30 disabled:opacity-50"
              >
                सुरक्षित करें
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  const renderWorkStatus = () => {
    if (selectedVillageId) {
      const village = villages.find(v => v.id === selectedVillageId);
      if (!village) return null;
      return (
        <VillageWorkStatusDetail 
          village={village} 
          contacts={contacts}
          onBack={() => setSelectedVillageId(null)}
          onUpdateStage={(stage) => updateVillageStage(village.id, stage)}
          onUpdateShakhaData={(data) => updateShakhaData(village.id, data)}
        />
      );
    }

    const filteredVillages = villages.filter(v => {
      const matchesSearch = v.name.toLowerCase().includes(workStatusSearch.toLowerCase());
      const mandal = mandals.find(m => m.id === v.mandalId);
      const kMatch = dashKhand === 'all' || mandal?.khandId === dashKhand;
      const mMatch = dashMandal === 'all' || v.mandalId === dashMandal;
      return matchesSearch && kMatch && mMatch;
    });

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">कार्यस्थिति</h1>
          <Building2 className="text-blue-600" />
        </header>

        {/* Sync Area Filters Display */}
        {(dashKhand !== 'all' || dashMandal !== 'all') && (
           <div className="bg-orange-50 dark:bg-orange-900/20 p-2 rounded-xl border border-orange-100 dark:border-orange-800 text-[10px] font-bold text-orange-700 dark:text-orange-300 flex justify-between">
             <span>दिखा रहा है: {dashKhand !== 'all' ? getKhandName(dashKhand) : ''} {dashMandal !== 'all' ? `• ${getMandalName(dashMandal)}` : ''}</span>
             <button onClick={() => {setDashKhand('all'); setDashMandal('all');}} className="flex items-center gap-1"><X size={10}/> साफ़ करें</button>
           </div>
        )}

        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input type="text" placeholder="गांव खोजें..." value={workStatusSearch} onChange={(e) => setWorkStatusSearch(e.target.value)} className="w-full bg-white dark:bg-gray-800 dark:text-gray-100 border dark:border-gray-700 rounded-xl py-3 pl-10 pr-4 outline-none shadow-sm" />
        </div>

        <div className="space-y-6">
          {mandals.filter(m => {
            const kMatch = dashKhand === 'all' || m.khandId === dashKhand;
            const mMatch = dashMandal === 'all' || m.id === dashMandal;
            return kMatch && mMatch;
          }).map(m => {
            const mandalVillages = filteredVillages.filter(v => v.mandalId === m.id);
            if (mandalVillages.length === 0) return null;
            return (
              <div key={m.id} className="space-y-2">
                <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] px-1 flex items-center gap-2">
                   <LayoutGrid size={12} /> {m.name}
                </h3>
                <div className="grid grid-cols-1 gap-2">
                  {mandalVillages.map(v => (
                    <div 
                      key={v.id} 
                      onClick={() => setSelectedVillageId(v.id)}
                      className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex justify-between items-center active:scale-[0.98] transition-all"
                    >
                      <div>
                        <div className="font-bold dark:text-gray-100">{v.name}</div>
                        {v.stage === VillageStage.SHAKHA && v.shakhaData?.shakhaName && (
                          <div className="text-[10px] text-orange-600 dark:text-orange-400 font-bold uppercase mt-1">शाखा: {v.shakhaData.shakhaName}</div>
                        )}
                      </div>
                      <span className={`text-[10px] px-3 py-1 rounded-full font-bold uppercase tracking-wider ${
                        v.stage === VillageStage.SHAKHA ? 'bg-orange-100 text-orange-700 dark:bg-orange-900/40 dark:text-orange-300' :
                        v.stage === VillageStage.MILAN ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300' :
                        v.stage === VillageStage.MANDALI ? 'bg-purple-100 text-purple-700 dark:bg-purple-900/40 dark:text-purple-300' :
                        'bg-gray-100 text-gray-500 dark:bg-gray-700 dark:text-gray-400'
                      }`}>
                        {v.stage}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const renderSettings = () => (
    <div className="p-4 pb-24 space-y-6">
       <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">सेटिंग्स</h1>

       <div className="bg-white dark:bg-gray-800 rounded-3xl p-4 shadow-sm space-y-2 border dark:border-gray-700 overflow-hidden">
          <div className="flex items-center justify-between p-3 border-b dark:border-gray-700 last:border-0">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-xl"><Moon size={20} /></div>
              <span className="font-bold dark:text-gray-200">डार्क मोड इंटरफ़ेस</span>
            </div>
            <button onClick={() => setDarkMode(!darkMode)} className="p-1 bg-gray-100 dark:bg-gray-700 rounded-full w-12 flex justify-start items-center relative transition-all duration-300">
               <div className={`w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-all ${darkMode ? 'translate-x-4 bg-blue-600' : 'bg-white'}`}>
                 {darkMode ? <Moon size={12} className="text-white" /> : <Sun size={12} className="text-yellow-500" />}
               </div>
            </button>
          </div>
       </div>

       <div className="space-y-3">
         <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">प्रबंधन (Management)</h2>
         <div className="bg-white dark:bg-gray-800 rounded-3xl p-4 shadow-sm border dark:border-gray-700 overflow-hidden">
            <button 
              onClick={() => setActiveTab('area-mgmt')}
              className="w-full flex items-center justify-between p-4 border-b dark:border-gray-700 last:border-0 active:bg-gray-50 dark:active:bg-gray-900/40 transition-colors"
            >
              <div className="flex items-center gap-4">
                <div className="p-2.5 bg-orange-50 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400 rounded-xl"><Map size={24} /></div>
                <div className="text-left">
                  <div className="font-bold dark:text-gray-200">क्षेत्र प्रबंधन</div>
                  <div className="text-[10px] text-gray-400 uppercase font-bold tracking-tight">खंड, मंडल और गांव जोड़ें/सुधारें</div>
                </div>
              </div>
              <ChevronRight size={18} className="text-gray-300" />
            </button>
         </div>
       </div>

       <div className="flex items-center gap-3 p-3 text-gray-400 justify-center">
         <BarChart3 size={20} />
         <span className="text-[10px] font-bold uppercase tracking-widest">ऐप वर्जन 1.0.7 (फील्ड कनेक्ट)</span>
       </div>
    </div>
  );

  return (
    <div className="min-h-screen max-w-md mx-auto relative bg-gray-50 dark:bg-gray-950 transition-colors duration-200">
      <main className="min-h-screen">
        {activeTab === 'home' && renderHome()}
        {activeTab === 'people' && renderPeople()}
        {activeTab === 'trips' && renderTrips()}
        {activeTab === 'work-status' && renderWorkStatus()}
        {activeTab === 'settings' && renderSettings()}
        {activeTab === 'area-mgmt' && renderAreaManagement()}
      </main>

      <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-md bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg border-t border-gray-200 dark:border-gray-800 flex justify-around items-center p-3 z-40 shadow-2xl rounded-t-[2.5rem]">
        <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon={<Home />} label="होम" />
        <NavButton active={activeTab === 'people'} onClick={() => {setActiveTab('people'); setSelectedContactId(null);}} icon={<Users />} label="संपर्क" />
        <NavButton active={activeTab === 'work-status'} onClick={() => {setActiveTab('work-status'); setSelectedVillageId(null);}} icon={<LayoutGrid />} label="कार्यस्थिति" />
        <NavButton active={activeTab === 'trips'} onClick={() => setActiveTab('trips')} icon={<MapPin />} label="यात्रा" />
        <NavButton active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} icon={<Settings />} label="सेट" />
      </nav>

      {isAddingContact && (
        <ContactFormModal 
          khands={khands} mandals={mandals} villages={villages} 
          onClose={() => setIsAddingContact(false)} 
          onSubmit={handleAddContact} 
        />
      )}

      {isAddingTrip && (
        <TripFormModal 
          khands={khands} mandals={mandals} villages={villages} contacts={contacts}
          onClose={() => setIsAddingTrip(false)} 
          onSubmit={handleAddTrip} 
        />
      )}

      {isLoggingVisit && (
        <VisitLogModal 
          contactName={contacts.find(c => c.id === isLoggingVisit)?.name || ''} 
          onClose={() => setIsLoggingVisit(null)} 
          onSubmit={(notes, followUp) => handleLogVisit(isLoggingVisit!, notes, followUp)} 
        />
      )}
    </div>
  );
};

// --- Sub Components ---

const NavButton = ({ active, icon, label, onClick }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center p-2 rounded-2xl transition-all duration-300 ${active ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/30 scale-110' : 'text-gray-400 hover:text-gray-600 dark:hover:text-gray-300'}`}>
    {React.cloneElement(icon, { size: 22 })}
    <span className="text-[10px] mt-1 font-bold uppercase tracking-tight">{label}</span>
  </button>
);

const StatCard = ({ label, value, color, onClick }: any) => (
  <div onClick={onClick} className={`${color} p-4 rounded-[1.5rem] shadow-sm flex flex-col justify-between active:scale-95 transition-all cursor-pointer border`}>
    <div className="text-[10px] font-bold opacity-80 uppercase tracking-wider">{label}</div>
    <div className="text-2xl font-black mt-1 tracking-tight">{value}</div>
  </div>
);

const TripCard = ({ trip, mandalName, onClick, isCompleted }: any) => (
  <div 
    onClick={onClick} 
    className={`bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 border-l-4 ${isCompleted ? 'border-l-green-500 opacity-70' : 'border-l-orange-500'} active:scale-95 transition-all`}
  >
    <div className="flex justify-between items-start">
      <div>
        <div className="text-[10px] font-bold text-gray-400 mb-1">{new Date(trip.date).toLocaleDateString('hi-IN', { dateStyle: 'medium' })}</div>
        <div className="font-bold dark:text-gray-100">{mandalName} दौरा</div>
        <div className="text-[10px] text-gray-500 dark:text-gray-400 uppercase font-bold tracking-tight mt-1">
          {trip.villageIds.length} गांव • {trip.peopleIds.length} संपर्क
        </div>
      </div>
      {isCompleted ? <CheckCircle2 className="text-green-500" size={18} /> : <ChevronRight className="text-gray-300" size={20} />}
    </div>
  </div>
);

const TripDetail = ({ trip, mandals, villages, contacts, onBack, onDelete, onToggleComplete }: any) => {
  const mandal = mandals.find((m: any) => m.id === trip.mandalId);
  const tripVillages = villages.filter((v: any) => trip.villageIds.includes(v.id));
  const tripPeople = contacts.filter((c: any) => trip.peopleIds.includes(c.id));

  return (
    <div className="p-4 pb-24 space-y-6 animate-in slide-in-from-right duration-300">
      <button onClick={onBack} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700"><ArrowLeft size={20} className="dark:text-gray-200"/></button>

      <div className="flex flex-col gap-1 px-1">
