    if (type === 'khand') {
      setKhands(prev => prev.filter(k => k.id !== id));
      setMandals(prev => prev.filter(m => m.khandId !== id));
    } else if (type === 'mandal') {
      setMandals(prev => prev.filter(m => m.id !== id));
      setVillages(prev => prev.filter(v => v.mandalId !== id));
    } else if (type === 'village') {
