    const filteredVillages = villages.filter(v => {
      const matchesSearch = v.name.toLowerCase().includes(workStatusSearch.toLowerCase());
      const mandal = mandals.find(m => m.id === v.mandalId);
      const kMatch = dashKhand === 'all' || mandal?.khandId === dashKhand;
      const mMatch = dashMandal === 'all' || v.mandalId === dashMandal;
      return matchesSearch && kMatch && mMatch;
    });

    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">कार्यस्थिति</h1>
          <Building2 className="text-blue-600" />
        </header>

        {/* Sync Area Filters Display */}
        {(dashKhand !== 'all' || dashMandal !== 'all') && (
           <div className="bg-orange-50 dark:bg-orange-900/20 p-2 rounded-xl border border-orange-100 dark:border-orange-800 text-[10px] font-bold text-orange-700 dark:text-orange-300 flex justify-between">
             <span>दिखा रहा है: {dashKhand !== 'all' ? getKhandName(dashKhand) : ''} {dashMandal !== 'all' ? `• ${getMandalName(dashMandal)}` : ''}</span>
             <button onClick={() => {setDashKhand('all'); setDashMandal('all');}} className="flex items-center gap-1"><X size={10}/> साफ़ करें</button>
           </div>
        )}

        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input type="text" placeholder="गांव खोजें..." value={workStatusSearch} onChange={(e) => setWorkStatusSearch(e.target.value)} className="w-full bg-white dark:bg-gray-800 dark:text-gray-100 border dark:border-gray-700 rounded-xl py-3 pl-10 pr-4 outline-none shadow-sm" />
        </div>

        <div className="space-y-6">
          {mandals.filter(m => {
            const kMatch = dashKhand === 'all' || m.khandId === dashKhand;
            const mMatch = dashMandal === 'all' || m.id === dashMandal;
            return kMatch && mMatch;
          }).map(m => {
            const mandalVillages = filteredVillages.filter(v => v.mandalId === m.id);
            if (mandalVillages.length === 0) return null;
            return (
              <div key={m.id} className="space-y-2">
                <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] px-1 flex items-center gap-2">
                   <LayoutGrid size={12} /> {m.name}
                </h3>
                <div className="grid grid-cols-1 gap-2">
                  {mandalVillages.map(v => (
                    <div 
                      key={v.id} 
                      onClick={() => setSelectedVillageId(v.id)}
                      className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex justify-between items-center active:scale-[0.98] transition-all"
                    >
                      <div>
                        <div className="font-bold dark:text-gray-100">{v.name}</div>
                        {v.stage === VillageStage.SHAKHA && v.shakhaData?.shakhaName && (
                          <div className="text-[10px] text-orange-600 dark:text-orange-400 font-bold uppercase mt-1">शाखा: {v.shakhaData.shakhaName}</div>
                        )}
                      </div>
                      <span className={`text-[10px] px-3 py-1 rounded-full font-bold uppercase tracking-wider ${
                        v.stage === VillageStage.SHAKHA ? 'bg-orange-100 text-orange-700 dark:bg-orange-900/40 dark:text-orange-300' :
                        v.stage === VillageStage.MILAN ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300' :
                        v.stage === VillageStage.MANDALI ? 'bg-purple-100 text-purple-700 dark:bg-purple-900/40 dark:text-purple-300' :
                        'bg-gray-100 text-gray-500 dark:bg-gray-700 dark:text-gray-400'
                      }`}>
                        {v.stage}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const renderSettings = () => (
    <div className="p-4 pb-24 space-y-6">
       <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">सेटिंग्स</h1>

       <div className="bg-white dark:bg-gray-800 rounded-3xl p-4 shadow-sm space-y-2 border dark:border-gray-700 overflow-hidden">
          <div className="flex items-center justify-between p-3 border-b dark:border-gray-700 last:border-0">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-xl"><Moon size={20} /></div>
              <span className="font-bold dark:text-gray-200">डार्क मोड इंटरफ़ेस</span>
            </div>
            <button onClick={() => setDarkMode(!darkMode)} className="p-1 bg-gray-100 dark:bg-gray-700 rounded-full w-12 flex justify-start items-center relative transition-all duration-300">
               <div className={`w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-all ${darkMode ? 'translate-x-4 bg-blue-600' : 'bg-white'}`}>
                 {darkMode ? <Moon size={12} className="text-white" /> : <Sun size={12} className="text-yellow-500" />}
               </div>
            </button>
          </div>
       </div>

       <div className="space-y-3">
         <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">प्रबंधन (Management)</h2>
         <div className="bg-white dark:bg-gray-800 rounded-3xl p-4 shadow-sm border dark:border-gray-700 overflow-hidden">
            <button 
              onClick={() => setActiveTab('area-mgmt')}
              className="w-full flex items-center justify-between p-4 border-b dark:border-gray-700 last:border-0 active:bg-gray-50 dark:active:bg-gray-900/40 transition-colors"
            >
              <div className="flex items-center gap-4">
                <div className="p-2.5 bg-orange-50 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400 rounded-xl"><Map size={24} /></div>
                <div className="text-left">
                  <div className="font-bold dark:text-gray-200">क्षेत्र प्रबंधन</div>
                  <div className="text-[10px] text-gray-400 uppercase font-bold tracking-tight">खंड, मंडल और गांव जोड़ें/सुधारें</div>
                </div>
              </div>
              <ChevronRight size={18} className="text-gray-300" />
            </button>
         </div>
       </div>

       <div className="flex items-center gap-3 p-3 text-gray-400 justify-center">
         <BarChart3 size={20} />
         <span className="text-[10px] font-bold uppercase tracking-widest">ऐप वर्जन 1.0.7 (फील्ड कनेक्ट)</span>
       </div>
    </div>
  );

  return (
    <div className="min-h-screen max-w-md mx-auto relative bg-gray-50 dark:bg-gray-950 transition-colors duration-200">
      <main className="min-h-screen">
        {activeTab === 'home' && renderHome()}
        {activeTab === 'people' && renderPeople()}
        {activeTab === 'trips' && renderTrips()}
        {activeTab === 'work-status' && renderWorkStatus()}
        {activeTab === 'settings' && renderSettings()}
        {activeTab === 'area-mgmt' && renderAreaManagement()}
      </main>

      <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-md bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg border-t border-gray-200 dark:border-gray-800 flex justify-around items-center p-3 z-40 shadow-2xl rounded-t-[2.5rem]">
        <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon={<Home />} label="होम" />
        <NavButton active={activeTab === 'people'} onClick={() => {setActiveTab('people'); setSelectedContactId(null);}} icon={<Users />} label="संपर्क" />
        <NavButton active={activeTab === 'work-status'} onClick={() => {setActiveTab('work-status'); setSelectedVillageId(null);}} icon={<LayoutGrid />} label="कार्यस्थिति" />
        <NavButton active={activeTab === 'trips'} onClick={() => setActiveTab('trips')} icon={<MapPin />} label="यात्रा" />
        <NavButton active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} icon={<Settings />} label="सेट" />
      </nav>

      {isAddingContact && (
        <ContactFormModal 
          khands={khands} mandals={mandals} villages={villages} 
          onClose={() => setIsAddingContact(false)} 
          onSubmit={handleAddContact} 
        />
      )}

      {isAddingTrip && (
        <TripFormModal 
          khands={khands} mandals={mandals} villages={villages} contacts={contacts}
          onClose={() => setIsAddingTrip(false)} 
          onSubmit={handleAddTrip} 
        />
      )}

      {isLoggingVisit && (
        <VisitLogModal 
          contactName={contacts.find(c => c.id === isLoggingVisit)?.name || ''} 
          onClose={() => setIsLoggingVisit(null)} 
          onSubmit={(notes, followUp) => handleLogVisit(isLoggingVisit!, notes, followUp)} 
        />
      )}
    </div>
  );
};

