const TripFormModal = ({ khands, mandals, villages, contacts, onClose, onSubmit }: any) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [khandId, setKhandId] = useState('');
  const [mandalId, setMandalId] = useState('');
  const [selectedVillageIds, setSelectedVillageIds] = useState<string[]>([]);
  const [selectedPeopleIds, setSelectedPeopleIds] = useState<string[]>([]);
  const [notes, setNotes] = useState('');

  const filteredMandals = mandals.filter((m: any) => m.khandId === khandId);
  const filteredVillages = villages.filter((v: any) => v.mandalId === mandalId);
  const filteredPeople = contacts.filter((c: any) => c.mandalId === mandalId);

  const toggleVillage = (id: string) => {
    setSelectedVillageIds(prev => prev.includes(id) ? prev.filter(v => v !== id) : [...prev, id]);
  };

  const togglePerson = (id: string) => {
    setSelectedPeopleIds(prev => prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]);
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-end">
      <div className="bg-white dark:bg-gray-900 w-full rounded-t-[3rem] p-8 space-y-5 max-h-[90vh] overflow-y-auto animate-in slide-in-from-bottom duration-500 shadow-2xl">
        <div className="w-12 h-1.5 bg-gray-200 dark:bg-gray-700 rounded-full mx-auto mb-2" />
        <h2 className="text-2xl font-black dark:text-white tracking-tight">नई यात्रा योजना</h2>

        <div className="space-y-6">
           <div className="space-y-1">
             <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">यात्रा की तारीख</label>
             <input type="date" className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-bold focus:ring-2 focus:ring-orange-500/20" value={date} onChange={e=>setDate(e.target.value)} />
           </div>

           <div className="grid grid-cols-2 gap-3">
             <div className="space-y-1">
               <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">खंड</label>
               <select className="w-full p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-bold text-xs" value={khandId} onChange={e=>{setKhandId(e.target.value); setMandalId('');}}>
                 <option value="">चुनें...</option>
                 {khands.map((k: any) => <option key={k.id} value={k.id}>{k.name}</option>)}
               </select>
             </div>
             <div className="space-y-1">
               <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">मंडल</label>
               <select className="w-full p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-bold text-xs" value={mandalId} disabled={!khandId} onChange={e=>{setMandalId(e.target.value); setSelectedVillageIds([]); setSelectedPeopleIds([]);}}>
                 <option value="">चुनें...</option>
                 {filteredMandals.map((m: any) => <option key={m.id} value={m.id}>{m.name}</option>)}
               </select>
             </div>
           </div>

           {mandalId && (
             <>
               <div className="space-y-2">
                 <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">गांवों का चयन ({selectedVillageIds.length})</label>
                 <div className="flex flex-wrap gap-2 max-h-32 overflow-y-auto p-1">
                   {filteredVillages.map((v: any) => (
                     <button 
                       key={v.id} 
                       type="button"
                       onClick={() => toggleVillage(v.id)}
                       className={`px-3 py-2 rounded-xl text-xs font-bold border transition-all ${
                         selectedVillageIds.includes(v.id) 
                           ? 'bg-orange-500 text-white border-orange-500' 
                           : 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 border-transparent'
                       }`}
                     >
                       {v.name}
                     </button>
                   ))}
                 </div>
               </div>

               <div className="space-y-2">
                 <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">संपर्क चयन ({selectedPeopleIds.length})</label>
                 <div className="grid grid-cols-1 gap-2 max-h-40 overflow-y-auto p-1">
                   {filteredPeople.map((c: any) => (
                     <button 
                       key={c.id} 
                       type="button"
                       onClick={() => togglePerson(c.id)}
                       className={`flex items-center gap-3 p-3 rounded-2xl border text-left transition-all ${
                         selectedPeopleIds.includes(c.id) 
                           ? 'bg-blue-500 text-white border-blue-500' 
                           : 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 border-transparent'
                       }`}
                     >
                       <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold ${selectedPeopleIds.includes(c.id) ? 'bg-white/20' : 'bg-gray-300'}`}>{c.name[0]}</div>
                       <span className="text-xs font-bold">{c.name}</span>
                     </button>
                   ))}
                 </div>
               </div>
             </>
           )}

           <div className="space-y-1">
             <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">विशेष टिप्पणी (वैकल्पिक)</label>
             <textarea 
               placeholder="जैसे: मंडल बैठक या विशेष संपर्क..." 
               className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-medium text-sm min-h-[80px]" 
               value={notes} 
               onChange={e=>setNotes(e.target.value)} 
             />
           </div>
        </div>

        <div className="flex gap-4 pt-4">
          <button onClick={onClose} className="flex-1 p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-400 font-bold rounded-2xl active:scale-95 transition-all">रद्द</button>
          <button 
            disabled={!mandalId || selectedVillageIds.length === 0}
            onClick={()=>onSubmit({ 
              date, 
              khandId,
              mandalId, 
              villageIds: selectedVillageIds, 
              peopleIds: selectedPeopleIds, 
              notes, 
              isCompleted: false
            })} 
            className="flex-1 p-4 bg-orange-600 text-white font-bold rounded-2xl shadow-lg shadow-orange-500/30 active:scale-95 transition-all disabled:opacity-50"
          >
            योजना बनाएं
          </button>
        </div>
      </div>
    </div>
  );
};

