  const mandalName = mandals.find((m: any) => m.id === contact.mandalId)?.name || contact.mandalId;
  const villageName = villages.find((v: any) => v.id === contact.villageId)?.name || contact.villageId;

  return (
    <div className="p-4 pb-24 space-y-6 animate-in slide-in-from-right duration-300">
      <header className="flex justify-between items-center">
        <button onClick={onBack} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700"><ArrowLeft size={20} className="dark:text-gray-200"/></button>
        <button onClick={onDelete} className="p-3 bg-red-50 dark:bg-red-900/20 text-red-600 rounded-2xl border border-red-100 dark:border-red-900/30"><Trash2 size={20}/></button>
      </header>

      <div className="text-center space-y-4">
        <div className="w-24 h-24 rounded-full bg-blue-500 mx-auto flex items-center justify-center text-white text-4xl font-black shadow-xl ring-4 ring-white dark:ring-gray-800">{contact.name[0]}</div>
        <div>
           <h2 className="text-2xl font-black dark:text-white tracking-tight">{contact.name}</h2>
           <a href={`tel:${contact.phone}`} className="text-blue-600 font-bold flex items-center justify-center gap-1 mt-1">
             <Phone size={14} /> {contact.phone}
           </a>
        </div>
      </div>

      <div className="bg-white dark:bg-gray-800 rounded-[2.5rem] p-6 shadow-sm border dark:border-gray-700 space-y-6">
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">श्रेणी</label>
            <select 
              value={contact.category}
              onChange={(e) => onUpdate({ category: e.target.value })}
              className="w-full bg-gray-50 dark:bg-gray-900 p-3 rounded-2xl border dark:border-gray-700 font-bold text-xs dark:text-gray-100 outline-none"
            >
              {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">स्थिति</label>
            <select 
              value={contact.status}
              onChange={(e) => onUpdate({ status: e.target.value })}
              className="w-full bg-gray-50 dark:bg-gray-900 p-3 rounded-2xl border dark:border-gray-700 font-bold text-xs dark:text-gray-100 outline-none"
            >
              {Object.values(Status).map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
        </div>

        <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-2xl border border-blue-100 dark:border-blue-800 flex items-center gap-3">
          <MapPin size={20} className="text-blue-600" />
          <div className="text-[10px] font-bold text-blue-800 dark:text-blue-300 uppercase tracking-tight">
            {khandName} • {mandalName} • {villageName}
          </div>
        </div>

