           <input placeholder="मोबाइल" type="tel" className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none" value={phone} onChange={e=>setPhone(e.target.value)} />
           <select className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none text-sm" value={khandId} onChange={e=>{setKhandId(e.target.value); setMandalId(''); setVillageId('');}}><option value="">खंड चुनें</option>{khands.map((k: any) => <option key={k.id} value={k.id}>{k.name}</option>)}</select>
           <div className="grid grid-cols-2 gap-3">
             <select className="p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none text-sm" value={mandalId} disabled={!khandId} onChange={e=>{setMandalId(e.target.value); setVillageId('');}}><option value="">मंडल चुनें</option>{mandals.filter((m: any) => m.khandId === khandId).map((m: any) => <option key={m.id} value={m.id}>{m.name}</option>)}</select>
             <select className="p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none text-sm" value={villageId} disabled={!mandalId} onChange={e=>setVillageId(e.target.value)}><option value="">गांव चुनें</option>{villages.filter((v: any)=>v.mandalId===mandalId).map((v: any) => <option key={v.id} value={v.id}>{v.name}</option>)}</select>
           </div>
           <select className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none text-sm" value={cat} onChange={e=>setCat(e.target.value as Category)}>{Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}</select>
        </div>
        <div className="flex gap-4 pt-4"><button onClick={onClose} className="flex-1 p-4 bg-gray-100 dark:bg-gray-800 font-bold rounded-2xl">रद्द</button><button disabled={!name || !phone || !villageId} onClick={()=>onSubmit({ name, phone, khandId, mandalId, villageId, category: cat, status: Status.SAKRIYA })} className="flex-1 p-4 bg-blue-600 text-white font-bold rounded-2xl disabled:opacity-50">सुरक्षित</button></div>
      </div>
    </div>
  );
};

const VisitLogModal = ({ contactName, onClose, onSubmit }: any) => {
