        <div className="flex gap-3"><button onClick={onClose} className="flex-1 p-4 bg-gray-100 dark:bg-gray-800 font-bold rounded-2xl">रद्द</button><button disabled={!notes} onClick={()=>onSubmit(notes, '')} className="flex-1 p-4 bg-green-600 text-white font-bold rounded-2xl">दर्ज करें</button></div>
