                </div>
              </div>
              <div className="p-4 space-y-3">
                <div className="flex justify-between items-center px-1">
                  <span className="text-[10px] font-bold text-gray-400 uppercase">मंडल</span>
                  <button onClick={() => setEditingItem({ type: 'mandal', parentId: k.id, name: '' })} className="text-[10px] font-bold text-blue-600 flex items-center gap-1"><Plus size={12}/> जोड़ें</button>
                </div>
                <div className="grid grid-cols-1 gap-2">
                  {mandals.filter(m => m.khandId === k.id).map(m => (
                    <div key={m.id} className="bg-gray-50 dark:bg-gray-900/50 p-3 rounded-2xl border dark:border-gray-700">
                      <div className="flex justify-between items-center mb-2">
                        <div className="font-bold dark:text-gray-200 text-sm">{m.name}</div>
                        <div className="flex gap-1">
                           <button onClick={() => setEditingItem({ type: 'mandal', id: m.id, parentId: k.id, name: m.name })} className="p-1.5 text-gray-400 hover:text-blue-600"><Edit2 size={14}/></button>
                           <button onClick={() => handleDeleteAreaItem('mandal', m.id)} className="p-1.5 text-gray-400 hover:text-red-600"><Trash2 size={14}/></button>
                        </div>
                      </div>
                      <div className="flex justify-between items-center mt-2 px-1">
                        <span className="text-[9px] font-bold text-gray-400 uppercase">गांव</span>
                        <button onClick={() => setEditingItem({ type: 'village', parentId: m.id, name: '' })} className="text-[9px] font-bold text-orange-600 flex items-center gap-1"><Plus size={10}/> जोड़ें</button>
                      </div>
                      <div className="flex flex-wrap gap-1.5 mt-2">
                        {villages.filter(v => v.mandalId === m.id).map(v => (
                          <div key={v.id} className="bg-white dark:bg-gray-800 px-2.5 py-1 rounded-lg border dark:border-gray-700 text-[10px] font-bold dark:text-gray-300 flex items-center gap-2">
                            {v.name}
                            <button onClick={() => setEditingItem({ type: 'village', id: v.id, parentId: m.id, name: v.name })} className="text-gray-400 hover:text-blue-600"><Edit2 size={8}/></button>
                            <button onClick={() => handleDeleteAreaItem('village', v.id)} className="text-gray-400 hover:text-red-600"><Trash2 size={8}/></button>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>
      {editingItem && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[60] flex items-center p-6">
          <div className="bg-white dark:bg-gray-900 w-full rounded-[2.5rem] p-8 space-y-6 shadow-2xl animate-in zoom-in duration-300">
            <h2 className="text-xl font-black dark:text-white tracking-tight">
               {editingItem.id ? 'सुधारें' : 'नया'} {editingItem.type === 'khand' ? 'खंड' : editingItem.type === 'mandal' ? 'मंडल' : 'गांव'}
            </h2>
            <input autoFocus className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-white rounded-2xl outline-none border dark:border-gray-700 font-bold" placeholder="नाम..." value={editingItem.name} onChange={e => setEditingItem({ ...editingItem, name: e.target.value })} />
            <div className="flex gap-3">
              <button onClick={() => setEditingItem(null)} className="flex-1 p-4 bg-gray-100 dark:bg-gray-800 text-gray-500 font-bold rounded-2xl">रद्द</button>
              <button onClick={handleSaveAreaItem} disabled={!editingItem.name} className="flex-1 p-4 bg-blue-600 text-white font-bold rounded-2xl shadow-lg shadow-blue-500/30 disabled:opacity-50">सुरक्षित</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  const renderSettings = () => (
    <div className="p-4 pb-24 space-y-6">
       <h1 className="text-2xl font-bold text-blue-900 dark:text-blue-400">सेटिंग्स</h1>
       <div className="bg-white dark:bg-gray-800 rounded-3xl p-4 shadow-sm border dark:border-gray-700 overflow-hidden">
          <div className="flex items-center justify-between p-3 border-b dark:border-gray-700 last:border-0">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-xl"><Moon size={20} /></div>
              <span className="font-bold dark:text-gray-200">डार्क मोड</span>
            </div>
            <button onClick={() => setDarkMode(!darkMode)} className="p-1 bg-gray-100 dark:bg-gray-700 rounded-full w-12 flex justify-start transition-all">
               <div className={`w-6 h-6 rounded-full shadow-sm transition-all ${darkMode ? 'translate-x-4 bg-blue-600' : 'bg-white'}`} />
            </button>
          </div>
       </div>

       <div className="space-y-3">
         <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">प्रबंधन एवं बैकअप</h2>
         <div className="bg-white dark:bg-gray-800 rounded-3xl p-4 shadow-sm border dark:border-gray-700 overflow-hidden">
            <button onClick={() => setActiveTab('area-mgmt')} className="w-full flex items-center justify-between p-4 border-b dark:border-gray-700 active:bg-gray-50 dark:active:bg-gray-900/40 transition-colors">
              <div className="flex items-center gap-4">
                <div className="p-2.5 bg-orange-50 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400 rounded-xl"><Map size={24} /></div>
                <div className="text-left">
                  <div className="font-bold dark:text-gray-200">क्षेत्र प्रबंधन</div>
                  <div className="text-[10px] text-gray-400 uppercase font-bold tracking-tight">खंड, मंडल और गांव</div>
                </div>
              </div>
              <ChevronRight size={18} className="text-gray-300" />
            </button>

            <button onClick={exportData} className="w-full flex items-center justify-between p-4 border-b dark:border-gray-700 active:bg-gray-50 dark:active:bg-gray-900/40 transition-colors">
              <div className="flex items-center gap-4">
                <div className="p-2.5 bg-green-50 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-xl"><Download size={24} /></div>
                <div className="text-left">
                  <div className="font-bold dark:text-gray-200">डेटा बैकअप लें</div>
                  <div className="text-[10px] text-gray-400 uppercase font-bold tracking-tight">फ़ाइल के रूप में सुरक्षित करें</div>
                </div>
              </div>
              <ChevronRight size={18} className="text-gray-300" />
            </button>

            <button onClick={resetAllData} className="w-full flex items-center justify-between p-4 active:bg-red-50 dark:active:bg-red-900/20 transition-colors">
              <div className="flex items-center gap-4">
                <div className="p-2.5 bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-xl"><RotateCcw size={24} /></div>
                <div className="text-left">
                  <div className="font-bold text-red-600">सारा डेटा साफ़ करें</div>
                  <div className="text-[10px] text-gray-400 uppercase font-bold tracking-tight">ऐप को रिसेट करें</div>
                </div>
              </div>
              <ChevronRight size={18} className="text-gray-300" />
            </button>
         </div>
       </div>
    </div>
  );

  return (
    <div className="min-h-screen max-w-md mx-auto relative bg-gray-50 dark:bg-gray-950 transition-colors duration-200">
      <main className="min-h-screen">
        {activeTab === 'home' && renderHome()}
        {activeTab === 'people' && renderPeople()}
        {activeTab === 'trips' && renderTrips()}
        {activeTab === 'work-status' && renderWorkStatus()}
        {activeTab === 'settings' && renderSettings()}
        {activeTab === 'area-mgmt' && renderAreaManagement()}
      </main>

      <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-md bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg border-t border-gray-200 dark:border-gray-800 flex justify-around items-center p-3 z-40 shadow-2xl rounded-t-[2.5rem]">
        <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon={<Home />} label="होम" />
        <NavButton active={activeTab === 'people'} onClick={() => {setActiveTab('people'); setSelectedContactId(null);}} icon={<Users />} label="संपर्क" />
        <NavButton active={activeTab === 'work-status'} onClick={() => {setActiveTab('work-status'); setSelectedVillageId(null);}} icon={<LayoutGrid />} label="कार्य" />
        <NavButton active={activeTab === 'trips'} onClick={() => setActiveTab('trips')} icon={<MapPin />} label="यात्रा" />
        <NavButton active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} icon={<Settings />} label="सेट" />
      </nav>

      {isAddingContact && (
        <ContactFormModal khands={khands} mandals={mandals} villages={villages} onClose={() => setIsAddingContact(false)} onSubmit={handleAddContact} />
      )}
      {isAddingTrip && (
        <TripFormModal khands={khands} mandals={mandals} villages={villages} contacts={contacts} onClose={() => setIsAddingTrip(false)} onSubmit={handleAddTrip} />
      )}
      {isLoggingVisit && (
        <VisitLogModal contactName={contacts.find(c => c.id === isLoggingVisit)?.name || ''} onClose={() => setIsLoggingVisit(null)} onSubmit={(notes: string, followUp: string) => handleLogVisit(isLoggingVisit!, notes, followUp)} />
      )}
    </div>
  );
};

// --- Helper Components ---

const NavButton = ({ active, icon, label, onClick }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center p-2 rounded-2xl transition-all ${active ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/30 scale-110' : 'text-gray-400'}`}>
    {React.cloneElement(icon, { size: 22 })}
    <span className="text-[10px] mt-1 font-bold uppercase">{label}</span>
  </button>
);

const StatCard = ({ label, value, color, onClick }: any) => (
  <div onClick={onClick} className={`${color} p-4 rounded-[1.5rem] shadow-sm flex flex-col justify-between active:scale-95 transition-all cursor-pointer border`}>
    <div className="text-[10px] font-bold opacity-80 uppercase">{label}</div>
    <div className="text-2xl font-black mt-1">{value}</div>
  </div>
);

const TripCard = ({ trip, mandalName, onClick, isCompleted }: any) => (
  <div onClick={onClick} className={`bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 border-l-4 ${isCompleted ? 'border-l-green-500 opacity-70' : 'border-l-orange-500'} active:scale-95 transition-all`}>
    <div className="flex justify-between items-start">
      <div>
        <div className="text-[10px] font-bold text-gray-400 mb-1">{new Date(trip.date).toLocaleDateString('hi-IN')}</div>
        <div className="font-bold dark:text-gray-100">{mandalName} दौरा</div>
        <div className="text-[10px] text-gray-500 uppercase mt-1">{trip.villageIds.length} गांव • {trip.peopleIds.length} संपर्क</div>
      </div>
      {isCompleted ? <CheckCircle2 className="text-green-500" size={18} /> : <ChevronRight className="text-gray-300" size={20} />}
    </div>
  </div>
);

const TripDetail = ({ trip, mandals, villages, contacts, onBack, onDelete, onToggleComplete }: any) => {
  const mandal = mandals.find((m: any) => m.id === trip.mandalId);
  const tripVillages = villages.filter((v: any) => trip.villageIds.includes(v.id));
  const tripPeople = contacts.filter((c: any) => trip.peopleIds.includes(c.id));
  return (
    <div className="p-4 pb-24 space-y-6 animate-in slide-in-from-right duration-300">
      <button onClick={onBack} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700"><ArrowLeft size={20} className="dark:text-gray-200"/></button>
      <h2 className="text-2xl font-black dark:text-white">{mandal?.name} यात्रा ({new Date(trip.date).toLocaleDateString('hi-IN')})</h2>
      <div className="bg-white dark:bg-gray-800 rounded-3xl p-6 shadow-sm border dark:border-gray-700 space-y-6">
        <div>
          <label className="text-[10px] font-bold text-gray-400 uppercase">लक्ष्य गांव</label>
          <div className="flex flex-wrap gap-2 mt-2">{tripVillages.map((v: any) => <span key={v.id} className="bg-orange-50 dark:bg-orange-900/20 text-orange-700 dark:text-orange-300 px-3 py-1.5 rounded-xl text-xs font-bold">{v.name}</span>)}</div>
        </div>
        <div className="border-t dark:border-gray-700 pt-6">
          <label className="text-[10px] font-bold text-gray-400 uppercase">संपर्क व्यक्ति</label>
          <div className="space-y-2 mt-2">{tripPeople.map((c: any) => <div key={c.id} className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-900/50 rounded-2xl border dark:border-gray-800"><div className="w-8 h-8 bg-blue-500 rounded-full flex items-center justify-center text-white text-xs font-bold">{c.name[0]}</div><div className="flex-1 text-sm font-bold dark:text-gray-200">{c.name}</div><a href={`tel:${c.phone}`} className="p-2 text-blue-600"><Phone size={16} /></a></div>)}</div>
        </div>
      </div>
      <div className="space-y-3">
        <button onClick={onToggleComplete} className={`w-full p-4 rounded-2xl font-bold flex items-center justify-center gap-2 ${trip.isCompleted ? 'bg-gray-200 text-gray-600' : 'bg-green-600 text-white shadow-lg'}`}>{trip.isCompleted ? <X size={20}/> : <CheckCircle2 size={20}/>}{trip.isCompleted ? 'अधूरा मार्क करें' : 'यात्रा पूर्ण मार्क करें'}</button>
        <button onClick={onDelete} className="w-full p-4 text-red-600 bg-red-50 dark:bg-red-900/10 rounded-2xl font-bold flex items-center justify-center gap-2"><Trash2 size={20}/> हटाएं</button>
      </div>
    </div>
  );
};

const TripFormModal = ({ khands, mandals, villages, contacts, onClose, onSubmit }: any) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [khandId, setKhandId] = useState('');
  const [mandalId, setMandalId] = useState('');
  const [selectedVillageIds, setSelectedVillageIds] = useState<string[]>([]);
  const [selectedPeopleIds, setSelectedPeopleIds] = useState<string[]>([]);
  const toggleVillage = (id: string) => setSelectedVillageIds(prev => prev.includes(id) ? prev.filter(v => v !== id) : [...prev, id]);
  const togglePerson = (id: string) => setSelectedPeopleIds(prev => prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]);
  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-end">
      <div className="bg-white dark:bg-gray-900 w-full rounded-t-[3rem] p-8 space-y-5 max-h-[90vh] overflow-y-auto animate-in slide-in-from-bottom duration-500 shadow-2xl">
        <h2 className="text-2xl font-black dark:text-white">नई यात्रा</h2>
        <div className="space-y-4">
           <div><label className="text-[10px] font-bold text-gray-400">तारीख</label><input type="date" className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none" value={date} onChange={e=>setDate(e.target.value)} /></div>
           <div className="grid grid-cols-2 gap-3">
             <select className="p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none text-xs" value={khandId} onChange={e=>{setKhandId(e.target.value); setMandalId('');}}><option value="">खंड चुनें</option>{khands.map((k: any) => <option key={k.id} value={k.id}>{k.name}</option>)}</select>
             <select className="p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none text-xs" value={mandalId} disabled={!khandId} onChange={e=>{setMandalId(e.target.value); setSelectedVillageIds([]); setSelectedPeopleIds([]);}}><option value="">मंडल चुनें</option>{mandals.filter((m: any) => m.khandId === khandId).map((m: any) => <option key={m.id} value={m.id}>{m.name}</option>)}</select>
           </div>
           {mandalId && (
             <div className="space-y-4">
               <label className="text-[10px] font-bold text-gray-400">गांव चयन</label>
               <div className="flex flex-wrap gap-2">{villages.filter((v: any) => v.mandalId === mandalId).map((v: any) => <button key={v.id} onClick={() => toggleVillage(v.id)} className={`px-3 py-2 rounded-xl text-xs font-bold border transition-all ${selectedVillageIds.includes(v.id) ? 'bg-orange-500 text-white' : 'bg-gray-100 dark:bg-gray-800 text-gray-600'}`}>{v.name}</button>)}</div>
             </div>
           )}
        </div>
        <div className="flex gap-4 pt-4"><button onClick={onClose} className="flex-1 p-4 bg-gray-100 dark:bg-gray-800 font-bold rounded-2xl">रद्द</button><button disabled={!mandalId || selectedVillageIds.length === 0} onClick={()=>onSubmit({ date, khandId, mandalId, villageIds: selectedVillageIds, peopleIds: selectedPeopleIds, notes: '', isCompleted: false})} className="flex-1 p-4 bg-orange-600 text-white font-bold rounded-2xl disabled:opacity-50">योजना बनाएं</button></div>
      </div>
    </div>
  );
};

const ContactFormModal = ({ khands, mandals, villages, onClose, onSubmit }: any) => {
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [khandId, setKhandId] = useState('');
  const [mandalId, setMandalId] = useState('');
  const [villageId, setVillageId] = useState('');
  const [cat, setCat] = useState(Category.KARYAKARTA);
  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-end">
      <div className="bg-white dark:bg-gray-900 w-full rounded-t-[3rem] p-8 space-y-5 max-h-[90vh] overflow-y-auto animate-in slide-in-from-bottom duration-500">
        <h2 className="text-2xl font-black dark:text-white">नया संपर्क</h2>
        <div className="space-y-4">
