import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Home, 
  Users, 
  MapPin, 
  List, 
  Calendar as CalendarIcon, 
  Settings, 
  Plus, 
  ChevronRight, 
  Phone, 
  CheckCircle2, 
  ArrowLeft,
  Search,
  Trash2,
  X,
  Moon,
  Sun,
  LayoutGrid,
  Building2,
  UserPlus,
  BarChart3,
  Map,
  Edit2,
  ChevronDown,
  Filter,
  Download,
  RotateCcw,
  Bell,
  User,
  Info,
  Upload,
  MessageSquare,
  ShieldCheck
} from 'lucide-react';
import { 
  Category, 
  Status, 
  Khand, 
  Mandal, 
  Village, 
  Contact, 
  TripPlan, 
  CustomList, 
  VisitHistory,
  VillageStage,
  ShakhaPosition,
  ShakhaData
} from './types';
import { 
  INITIAL_KHANDS, 
  INITIAL_MANDALS, 
  INITIAL_VILLAGES, 
  INITIAL_CONTACTS, 
  INITIAL_TRIPS, 
  INITIAL_LISTS 
} from './constants';

type Tab = 'home' | 'people' | 'trips' | 'lists' | 'work-status' | 'calendar' | 'settings' | 'area-mgmt';

// Helper to load from localStorage
const loadData = <T,>(key: string, defaultValue: T): T => {
  try {
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : defaultValue;
  } catch (e) {
    return defaultValue;
  }
};

const App: React.FC = () => {
  // --- State with Persistence ---
  const [activeTab, setActiveTab] = useState<Tab>('home');
  const [khands, setKhands] = useState<Khand[]>(() => loadData('khands', INITIAL_KHANDS));
  const [mandals, setMandals] = useState<Mandal[]>(() => loadData('mandals', INITIAL_MANDALS));
  const [villages, setVillages] = useState<Village[]>(() => loadData('villages', INITIAL_VILLAGES));
  const [contacts, setContacts] = useState<Contact[]>(() => loadData('contacts', INITIAL_CONTACTS));
  const [trips, setTrips] = useState<TripPlan[]>(() => loadData('trips', INITIAL_TRIPS));
  const [darkMode, setDarkMode] = useState(() => loadData('darkMode', false));

  // New App Settings States
  const [userName, setUserName] = useState(() => loadData('userName', 'क्षेत्र कार्यकर्ता'));
  const [notificationsEnabled, setNotificationsEnabled] = useState(() => loadData('notifications', true));

  // Global Filters
  const [dashKhand, setDashKhand] = useState<string>('all');
  const [dashMandal, setDashMandal] = useState<string>('all');

  // People specific
  const [peopleSearch, setPeopleSearch] = useState('');
  const [peopleStatusFilter, setPeopleStatusFilter] = useState<string | 'all'>('all');

  // Work Status specific
  const [workStatusSearch, setWorkStatusSearch] = useState('');

  // Selected Items
  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [selectedTripId, setSelectedTripId] = useState<string | null>(null);
  const [selectedVillageId, setSelectedVillageId] = useState<string | null>(null);

  // Area Management State
  const [editingItem, setEditingItem] = useState<{ type: 'khand' | 'mandal' | 'village', id?: string, parentId?: string, name: string } | null>(null);

  // Modals
  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isAddingTrip, setIsAddingTrip] = useState(false);
  const [isLoggingVisit, setIsLoggingVisit] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Persistence Effects ---
  useEffect(() => {
    localStorage.setItem('khands', JSON.stringify(khands));
  }, [khands]);
  useEffect(() => {
    localStorage.setItem('mandals', JSON.stringify(mandals));
  }, [mandals]);
  useEffect(() => {
    localStorage.setItem('villages', JSON.stringify(villages));
  }, [villages]);
  useEffect(() => {
    localStorage.setItem('contacts', JSON.stringify(contacts));
  }, [contacts]);
  useEffect(() => {
    localStorage.setItem('trips', JSON.stringify(trips));
  }, [trips]);
  useEffect(() => {
    localStorage.setItem('userName', JSON.stringify(userName));
  }, [userName]);
  useEffect(() => {
    localStorage.setItem('notifications', JSON.stringify(notificationsEnabled));
  }, [notificationsEnabled]);

  useEffect(() => {
    localStorage.setItem('darkMode', JSON.stringify(darkMode));
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // --- Helpers & Memos ---
  const getKhandName = (id: string) => khands.find(k => k.id === id)?.name || id;
  const getMandalName = (id: string) => mandals.find(m => m.id === id)?.name || id;
  const getVillageName = (id: string) => villages.find(v => v.id === id)?.name || id;

  const groupedTrips = useMemo(() => {
    const pending = trips.filter(t => !t.isCompleted).sort((a,b) => a.date.localeCompare(b.date));
    const groups: Record<string, TripPlan[]> = {};
    pending.forEach(t => {
      if (!groups[t.date]) groups[t.date] = [];
      groups[t.date].push(t);
    });
    return Object.entries(groups).slice(0, 3);
  }, [trips]);

  const stats = useMemo(() => {
    const filteredContacts = contacts.filter(c => {
      const kMatch = dashKhand === 'all' || c.khandId === dashKhand;
      const mMatch = dashMandal === 'all' || c.mandalId === dashMandal;
      return kMatch && mMatch;
    });

    const villageStats = villages.filter(v => {
      const mandal = mandals.find(m => m.id === v.mandalId);
      if (!mandal) return false;
      const kMatch = dashKhand === 'all' || mandal.khandId === dashKhand;
      const mMatch = dashMandal === 'all' || v.mandalId === dashMandal;
      return kMatch && mMatch;
    }).reduce((acc, v) => {
      acc[v.stage] = (acc[v.stage] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return {
      total: filteredContacts.length,
      active: filteredContacts.filter(c => c.status === Status.SAKRIYA).length,
      sanchit: filteredContacts.filter(c => c.status === Status.SANCHIT).length,
      sajjan: filteredContacts.filter(c => c.status === Status.SAJJAN).length,
      utsuk: filteredContacts.filter(c => c.status === Status.UTSUK).length,
      pending: filteredContacts.filter(c => {
         const lastVisit = c.history[c.history.length - 1];
         if (!lastVisit?.nextFollowUp) return false;
         return new Date(lastVisit.nextFollowUp) < new Date();
      }).length,
      villages: villageStats
    };
  }, [contacts, villages, mandals, dashKhand, dashMandal]);

  // --- Handlers ---
  const handleStatClick = (filter: string | 'all') => {
    setPeopleStatusFilter(filter);
    setActiveTab('people');
    setSelectedContactId(null);
  };

  const handleWorkStatClick = () => {
    setActiveTab('work-status');
    setSelectedVillageId(null);
  };

  const handleAddContact = (newContact: Omit<Contact, 'id' | 'listIds' | 'history'>) => {
    const contact: Contact = { ...newContact, id: `c${Date.now()}`, listIds: [], history: [] };
    setContacts(prev => [...prev, contact]);
    setIsAddingContact(false);
  };

  const handleUpdateContact = (id: string, updates: Partial<Contact>) => {
    setContacts(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  };

  const handleDeleteContact = (id: string) => {
    if(window.confirm('क्या आप इस संपर्क को हटाना चाहते हैं?')) {
      setContacts(prev => prev.filter(c => c.id !== id));
      setSelectedContactId(null);
    }
  };

  const handleAddTrip = (newTrip: Omit<TripPlan, 'id' | 'isCompleted'>) => {
    const trip: TripPlan = { ...newTrip, id: `t${Date.now()}`, isCompleted: false };
    setTrips(prev => [...prev, trip]);
    setIsAddingTrip(false);
  };

  const handleDeleteTrip = (id: string) => {
    if(window.confirm('क्या आप इस यात्रा योजना को हटाना चाहते हैं?')) {
      setTrips(prev => prev.filter(t => t.id !== id));
      setSelectedTripId(null);
    }
  };

  const handleToggleTripCompletion = (id: string) => {
    setTrips(prev => prev.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t));
  };

  const handleLogVisit = (contactId: string, notes: string, nextFollowUp: string) => {
    const newVisit: VisitHistory = { 
      id: `h${Date.now()}`, 
      date: new Date().toISOString().split('T')[0], 
      notes, 
      nextFollowUp 
    };
    setContacts(prev => prev.map(c => c.id === contactId ? { 
      ...c, 
      lastVisited: newVisit.date, 
      history: [...c.history, newVisit] 
    } : c));
    setIsLoggingVisit(null);
  };

  const updateVillageStage = (villageId: string, stage: VillageStage) => {
    setVillages(prev => prev.map(v => v.id === villageId ? { ...v, stage } : v));
  };

  const updateShakhaData = (villageId: string, data: Partial<ShakhaData>) => {
    setVillages(prev => prev.map(v => v.id === villageId ? { 
      ...v, 
      shakhaData: { 
        shakhaName: v.shakhaData?.shakhaName || '', 
        positions: v.shakhaData?.positions || {}, 
        ...data 
      } 
    } : v));
  };

  const handleSaveAreaItem = () => {
    if (!editingItem) return;
    const { type, id, name, parentId } = editingItem;

    if (type === 'khand') {
      if (id) setKhands(prev => prev.map(k => k.id === id ? { ...k, name } : k));
      else setKhands(prev => [...prev, { id: `k${Date.now()}`, name }]);
    } else if (type === 'mandal') {
      if (id) setMandals(prev => prev.map(m => m.id === id ? { ...m, name } : m));
      else setMandals(prev => [...prev, { id: `m${Date.now()}`, name, khandId: parentId! }]);
    } else if (type === 'village') {
      if (id) setVillages(prev => prev.map(v => v.id === id ? { ...v, name } : v));
      else setVillages(prev => [...prev, { id: `v${Date.now()}`, name, mandalId: parentId!, stage: VillageStage.NONE }]);
    }
    setEditingItem(null);
  };

  const handleDeleteAreaItem = (type: 'khand' | 'mandal' | 'village', id: string) => {
    if(window.confirm('हटाने से सारा संबंधित डेटा डिलीट हो जाएगा। क्या आप वाकई हटाना चाहते हैं?')) {
      if (type === 'khand') {
        setKhands(prev => prev.filter(k => k.id !== id));
        setMandals(prev => prev.filter(m => m.khandId !== id));
      } else if (type === 'mandal') {
        setMandals(prev => prev.filter(m => m.id !== id));
        setVillages(prev => prev.filter(v => v.mandalId !== id));
      } else if (type === 'village') {
        setVillages(prev => prev.filter(v => v.id !== id));
      }
    }
  };

  const resetAllData = () => {
    if(window.confirm('सावधानी! यह आपकी सारी जानकारी मिटाकर ऐप को शुरुआत जैसा कर देगा। क्या आप वाकई रिसेट करना चाहते हैं?')) {
      setKhands(INITIAL_KHANDS);
