  const exportData = () => {
    const data = { khands, mandals, villages, contacts, trips, userName, notificationsEnabled };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `pravaas_plan_backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const importData = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = JSON.parse(e.target?.result as string);
        if (data.khands) setKhands(data.khands);
        if (data.mandals) setMandals(data.mandals);
        if (data.villages) setVillages(data.villages);
        if (data.contacts) setContacts(data.contacts);
        if (data.trips) setTrips(data.trips);
        if (data.userName) setUserName(data.userName);
        if (data.notificationsEnabled !== undefined) setNotificationsEnabled(data.notificationsEnabled);
        alert('डेटा सफलतापूर्वक आयात किया गया!');
      } catch (err) {
        alert('फ़ाइल पढ़ने में त्रुटि हुई। कृपया सही बैकअप फ़ाइल चुनें।');
