                      <div className="flex justify-between items-center mb-2">
                        <div className="font-bold dark:text-gray-200 text-sm">{m.name}</div>
                        <div className="flex gap-1">
                           <button onClick={() => setEditingItem({ type: 'mandal', id: m.id, parentId: k.id, name: m.name })} className="p-1.5 text-gray-400 hover:text-blue-600"><Edit2 size={14}/></button>
                           <button onClick={() => handleDeleteAreaItem('mandal', m.id)} className="p-1.5 text-gray-400 hover:text-red-600"><Trash2 size={14}/></button>
                        </div>
                      </div>
                      <div className="flex justify-between items-center mt-2 px-1">
                        <span className="text-[9px] font-bold text-gray-400 uppercase">गांव</span>
                        <button onClick={() => setEditingItem({ type: 'village', parentId: m.id, name: '' })} className="text-[9px] font-bold text-orange-600 flex items-center gap-1"><Plus size={10}/> जोड़ें</button>
                      </div>
                      <div className="flex flex-wrap gap-1.5 mt-2">
                        {villages.filter(v => v.mandalId === m.id).map(v => (
                          <div key={v.id} className="bg-white dark:bg-gray-800 px-2.5 py-1 rounded-lg border dark:border-gray-700 text-[10px] font-bold dark:text-gray-300 flex items-center gap-2">
                            {v.name}
                            <button onClick={() => setEditingItem({ type: 'village', id: v.id, parentId: m.id, name: v.name })} className="text-gray-400 hover:text-blue-600"><Edit2 size={8}/></button>
                            <button onClick={() => handleDeleteAreaItem('village', v.id)} className="text-gray-400 hover:text-red-600"><Trash2 size={8}/></button>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>
      {editingItem && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[60] flex items-center p-6">
          <div className="bg-white dark:bg-gray-900 w-full rounded-[2.5rem] p-8 space-y-6 shadow-2xl animate-in zoom-in duration-300">
            <h2 className="text-xl font-black dark:text-white tracking-tight">
               {editingItem.id ? 'सुधारें' : 'नया'} {editingItem.type === 'khand' ? 'खंड' : editingItem.type === 'mandal' ? 'मंडल' : 'गांव'}
            </h2>
            <input autoFocus className="w-full p-4 bg-gray-100 dark:bg-gray-800 dark:text-white rounded-2xl outline-none border dark:border-gray-700 font-bold" placeholder="नाम..." value={editingItem.name} onChange={e => setEditingItem({ ...editingItem, name: e.target.value })} />
            <div className="flex gap-3">
              <button onClick={() => setEditingItem(null)} className="flex-1 p-4 bg-gray-100 dark:bg-gray-800 text-gray-500 font-bold rounded-2xl">रद्द</button>
              <button onClick={handleSaveAreaItem} disabled={!editingItem.name} className="flex-1 p-4 bg-blue-600 text-white font-bold rounded-2xl shadow-lg shadow-blue-500/30 disabled:opacity-50">सुरक्षित</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  const renderSettings = () => (
    <div className="p-4 pb-24 space-y-6">
       <h1 className="text-2xl font-black text-blue-900 dark:text-blue-400 tracking-tight">सेटिंग्स</h1>

       {/* User Profile Section */}
       <div className="bg-white dark:bg-gray-800 rounded-3xl p-5 shadow-sm border dark:border-gray-700 flex items-center gap-4">
          <div className="w-14 h-14 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
             <User size={28} />
          </div>
          <div className="flex-1">
             <input 
               type="text" 
               className="bg-transparent border-none p-0 text-lg font-black dark:text-white outline-none focus:ring-0"
               value={userName}
               onChange={(e) => setUserName(e.target.value)}
               placeholder="अपना नाम लिखें"
             />
             <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">क्षेत्र कार्यकर्ता प्रोफ़ाइल</div>
          </div>
          <div className="p-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-xl">
             <Edit2 size={16} />
          </div>
       </div>

       <div className="space-y-3">
         <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">एप्लीकेशन सेटिंग्स</h2>
         <div className="bg-white dark:bg-gray-800 rounded-3xl p-2 shadow-sm border dark:border-gray-700 overflow-hidden">
            {/* Dark Mode Switch */}
            <div className="flex items-center justify-between p-4 border-b dark:border-gray-700">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-xl"><Moon size={20} /></div>
                <span className="font-bold dark:text-gray-200">डार्क मोड</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className={`p-1 rounded-full w-12 flex items-center transition-all ${darkMode ? 'bg-indigo-600' : 'bg-gray-200 dark:bg-gray-700'}`}>
                 <div className={`w-5 h-5 rounded-full shadow-sm bg-white transform transition-transform ${darkMode ? 'translate-x-5' : 'translate-x-0'}`} />
              </button>
            </div>

            {/* Notifications Switch */}
            <div className="flex items-center justify-between p-4 border-b dark:border-gray-700">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-orange-50 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400 rounded-xl"><Bell size={20} /></div>
                <span className="font-bold dark:text-gray-200">सूचनाएं</span>
              </div>
              <button onClick={() => setNotificationsEnabled(!notificationsEnabled)} className={`p-1 rounded-full w-12 flex items-center transition-all ${notificationsEnabled ? 'bg-orange-600' : 'bg-gray-200 dark:bg-gray-700'}`}>
                 <div className={`w-5 h-5 rounded-full shadow-sm bg-white transform transition-transform ${notificationsEnabled ? 'translate-x-5' : 'translate-x-0'}`} />
              </button>
            </div>

            {/* Language Selection (Mock) */}
            <div className="flex items-center justify-between p-4">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-xl"><MessageSquare size={20} /></div>
                <span className="font-bold dark:text-gray-200">भाषा</span>
              </div>
              <span className="text-[10px] font-bold text-blue-600 uppercase bg-blue-50 dark:bg-blue-900/40 px-3 py-1 rounded-full tracking-widest">हिन्दी</span>
            </div>
         </div>
       </div>

       <div className="space-y-3">
         <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">प्रबंधन एवं बैकअप</h2>
         <div className="bg-white dark:bg-gray-800 rounded-3xl p-2 shadow-sm border dark:border-gray-700 overflow-hidden">
            <button onClick={() => setActiveTab('area-mgmt')} className="w-full flex items-center justify-between p-4 border-b dark:border-gray-700 active:bg-gray-50 dark:active:bg-gray-900/40 transition-colors">
              <div className="flex items-center gap-4">
                <div className="p-2.5 bg-purple-50 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 rounded-xl"><Map size={24} /></div>
                <div className="text-left">
                  <div className="font-bold dark:text-gray-200">क्षेत्र प्रबंधन</div>
                  <div className="text-[10px] text-gray-400 uppercase font-bold tracking-tight">खंड, मंडल और गांव</div>
                </div>
              </div>
              <ChevronRight size={18} className="text-gray-300" />
            </button>

            <button onClick={exportData} className="w-full flex items-center justify-between p-4 border-b dark:border-gray-700 active:bg-gray-50 dark:active:bg-gray-900/40 transition-colors">
              <div className="flex items-center gap-4">
                <div className="p-2.5 bg-green-50 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-xl"><Download size={24} /></div>
                <div className="text-left">
                  <div className="font-bold dark:text-gray-200">डेटा बैकअप (Export)</div>
                  <div className="text-[10px] text-gray-400 uppercase font-bold tracking-tight">फ़ाइल के रूप में डाउनलोड करें</div>
                </div>
              </div>
              <ChevronRight size={18} className="text-gray-300" />
            </button>

            <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-between p-4 border-b dark:border-gray-700 active:bg-gray-50 dark:active:bg-gray-900/40 transition-colors">
              <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={importData} />
              <div className="flex items-center gap-4">
                <div className="p-2.5 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-xl"><Upload size={24} /></div>
                <div className="text-left">
                  <div className="font-bold dark:text-gray-200">डेटा आयात (Import)</div>
                  <div className="text-[10px] text-gray-400 uppercase font-bold tracking-tight">पुराना बैकअप लोड करें</div>
                </div>
              </div>
              <ChevronRight size={18} className="text-gray-300" />
            </button>

            <button onClick={resetAllData} className="w-full flex items-center justify-between p-4 active:bg-red-50 dark:active:bg-red-900/20 transition-colors">
              <div className="flex items-center gap-4">
                <div className="p-2.5 bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-xl"><RotateCcw size={24} /></div>
                <div className="text-left">
                  <div className="font-bold text-red-600">सारा डेटा साफ़ करें</div>
                  <div className="text-[10px] text-gray-400 uppercase font-bold tracking-tight">ऐप को पूर्ण रिसेट करें</div>
                </div>
              </div>
              <ChevronRight size={18} className="text-gray-300" />
            </button>
         </div>
       </div>

       {/* About Section */}
       <div className="space-y-3">
         <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest px-1">ऐप के बारे में</h2>
         <div className="bg-white dark:bg-gray-800 rounded-3xl p-5 shadow-sm border dark:border-gray-700 space-y-4">
            <div className="flex items-center gap-4">
               <div className="p-2 bg-gray-50 dark:bg-gray-900/40 text-gray-400 rounded-xl"><Info size={20} /></div>
               <div>
                  <div className="text-sm font-bold dark:text-gray-200">वर्जन 1.0.0 (Beta)</div>
                  <div className="text-[10px] text-gray-400 font-bold uppercase">प्रवास प्लान मैनेजमेंट सिस्टम</div>
               </div>
            </div>
            <div className="flex items-center gap-4">
               <div className="p-2 bg-gray-50 dark:bg-gray-900/40 text-gray-400 rounded-xl"><ShieldCheck size={20} /></div>
               <div className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter leading-relaxed">
                  आपका सारा डेटा केवल आपके डिवाइस पर सुरक्षित है। हम कोई भी जानकारी बाहरी सर्वर पर नहीं भेजते हैं।
               </div>
            </div>
         </div>
       </div>
    </div>
  );

  return (
    <div className="min-h-screen max-w-md mx-auto relative bg-gray-50 dark:bg-gray-950 transition-colors duration-200">
      <main className="min-h-screen">
        {activeTab === 'home' && renderHome()}
        {activeTab === 'people' && renderPeople()}
        {activeTab === 'trips' && renderTrips()}
        {activeTab === 'work-status' && renderWorkStatus()}
        {activeTab === 'settings' && renderSettings()}
        {activeTab === 'area-mgmt' && renderAreaManagement()}
      </main>

      <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-md bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg border-t border-gray-200 dark:border-gray-800 flex justify-around items-center p-3 z-40 shadow-2xl rounded-t-[2.5rem]">
        <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon={<Home />} label="होम" />
        <NavButton active={activeTab === 'people'} onClick={() => {setActiveTab('people'); setSelectedContactId(null);}} icon={<Users />} label="संपर्क" />
        <NavButton active={activeTab === 'work-status'} onClick={() => {setActiveTab('work-status'); setSelectedVillageId(null);}} icon={<LayoutGrid />} label="कार्य" />
        <NavButton active={activeTab === 'trips'} onClick={() => setActiveTab('trips')} icon={<MapPin />} label="यात्रा" />
        <NavButton active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} icon={<Settings />} label="सेट" />
      </nav>

      {isAddingContact && (
        <ContactFormModal khands={khands} mandals={mandals} villages={villages} onClose={() => setIsAddingContact(false)} onSubmit={handleAddContact} />
      )}
      {isAddingTrip && (
        <TripFormModal khands={khands} mandals={mandals} villages={villages} contacts={contacts} onClose={() => setIsAddingTrip(false)} onSubmit={handleAddTrip} />
      )}
      {isLoggingVisit && (
        <VisitLogModal contactName={contacts.find(c => c.id === isLoggingVisit)?.name || ''} onClose={() => setIsLoggingVisit(null)} onSubmit={(notes: string, followUp: string) => handleLogVisit(isLoggingVisit!, notes, followUp)} />
      )}
    </div>
  );
};

// --- Helper Components ---

const NavButton = ({ active, icon, label, onClick }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center p-2 rounded-2xl transition-all duration-300 ${active ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/30 scale-105 shadow-sm' : 'text-gray-400'}`}>
    {React.cloneElement(icon, { size: 22, strokeWidth: active ? 3 : 2 })}
    <span className={`text-[9px] mt-1 font-black uppercase tracking-widest ${active ? 'opacity-100' : 'opacity-60'}`}>{label}</span>
  </button>
);

const StatCard = ({ label, value, color, onClick }: any) => (
  <div onClick={onClick} className={`${color} p-4 rounded-[1.75rem] shadow-sm flex flex-col justify-between active:scale-95 transition-all cursor-pointer border`}>
    <div className="text-[9px] font-black opacity-60 uppercase tracking-widest">{label}</div>
    <div className="text-2xl font-black mt-1.5">{value}</div>
  </div>
);

const TripCard = ({ trip, mandalName, onClick, isCompleted }: any) => (
  <div onClick={onClick} className={`bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 border-l-4 ${isCompleted ? 'border-l-green-500 opacity-60' : 'border-l-orange-500'} active:scale-95 transition-all`}>
    <div className="flex justify-between items-start">
      <div>
        <div className="text-[10px] font-bold text-gray-400 mb-1">{new Date(trip.date).toLocaleDateString('hi-IN')}</div>
        <div className="font-bold dark:text-gray-100">{mandalName} दौरा</div>
        <div className="text-[9px] font-black text-gray-500 uppercase mt-1 tracking-tight">{trip.villageIds.length} गांव • {trip.peopleIds.length} सदस्य</div>
      </div>
      {isCompleted ? <CheckCircle2 className="text-green-500" size={18} /> : <ChevronRight className="text-gray-300" size={20} />}
    </div>
  </div>
);

const TripDetail = ({ trip, mandals, villages, contacts, onBack, onDelete, onToggleComplete }: any) => {
  const mandal = mandals.find((m: any) => m.id === trip.mandalId);
  const tripVillages = villages.filter((v: any) => trip.villageIds.includes(v.id));
  const tripPeople = contacts.filter((c: any) => trip.peopleIds.includes(c.id));
  return (
    <div className="p-4 pb-24 space-y-6 animate-in slide-in-from-right duration-300">
      <button onClick={onBack} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700 transition-transform active:scale-90"><ArrowLeft size={20} className="dark:text-gray-200"/></button>
      <h2 className="text-2xl font-black dark:text-white tracking-tight">{mandal?.name} यात्रा ({new Date(trip.date).toLocaleDateString('hi-IN')})</h2>
      <div className="bg-white dark:bg-gray-800 rounded-3xl p-6 shadow-sm border dark:border-gray-700 space-y-6">
        <div>
          <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">लक्ष्य गांव</label>
          <div className="flex flex-wrap gap-2 mt-2">{tripVillages.map((v: any) => <span key={v.id} className="bg-orange-50 dark:bg-orange-900/20 text-orange-700 dark:text-orange-300 px-3 py-1.5 rounded-xl text-xs font-bold">{v.name}</span>)}</div>
        </div>
        <div className="border-t dark:border-gray-700 pt-6">
          <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">निर्धारित संपर्क</label>
          <div className="space-y-2 mt-2">{tripPeople.map((c: any) => <div key={c.id} className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-900/50 rounded-2xl border dark:border-gray-800"><div className="w-8 h-8 bg-blue-500 rounded-full flex items-center justify-center text-white text-xs font-bold">{c.name[0]}</div><div className="flex-1 text-sm font-bold dark:text-gray-200">{c.name}</div><a href={`tel:${c.phone}`} className="p-2 text-blue-600"><Phone size={16} /></a></div>)}</div>
        </div>
      </div>
      <div className="space-y-3">
        <button onClick={onToggleComplete} className={`w-full p-4 rounded-2xl font-bold flex items-center justify-center gap-2 ${trip.isCompleted ? 'bg-gray-200 text-gray-600' : 'bg-green-600 text-white shadow-lg shadow-green-500/30'}`}>{trip.isCompleted ? <X size={20}/> : <CheckCircle2 size={20}/>}{trip.isCompleted ? 'अधूरा मार्क करें' : 'यात्रा पूर्ण मार्क करें'}</button>
        <button onClick={onDelete} className="w-full p-4 text-red-600 bg-red-50 dark:bg-red-900/10 rounded-2xl font-bold flex items-center justify-center gap-2 border border-red-100 dark:border-transparent"><Trash2 size={20}/> हटाएं</button>
      </div>
    </div>
  );
};

const TripFormModal = ({ khands, mandals, villages, contacts, onClose, onSubmit }: any) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [khandId, setKhandId] = useState('');
  const [mandalId, setMandalId] = useState('');
  const [selectedVillageIds, setSelectedVillageIds] = useState<string[]>([]);
  const [selectedPeopleIds, setSelectedPeopleIds] = useState<string[]>([]);

  const toggleVillage = (id: string) => setSelectedVillageIds(prev => prev.includes(id) ? prev.filter(v => v !== id) : [...prev, id]);
  const togglePerson = (id: string) => setSelectedPeopleIds(prev => prev.includes(id) ? prev.filter(p => p !== id) : [...prev, id]);

  const villageList = mandalId ? villages.filter((v: any) => v.mandalId === mandalId) : [];
  const contactList = mandalId ? contacts.filter((c: any) => c.mandalId === mandalId) : [];

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-end">
      <div className="bg-white dark:bg-gray-900 w-full rounded-t-[3rem] p-8 space-y-5 max-h-[90vh] overflow-y-auto animate-in slide-in-from-bottom duration-500 shadow-2xl no-scrollbar">
        <h2 className="text-2xl font-black dark:text-white tracking-tight">नई यात्रा योजना</h2>

        <div className="space-y-6">
           {/* Date */}
           <div>
              <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">तारीख</label>
              <input type="date" className="w-full mt-1 p-4 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none border-2 border-transparent focus:border-orange-500 transition-colors font-bold" value={date} onChange={e=>setDate(e.target.value)} />
           </div>

           {/* Location Selectors */}
           <div className="grid grid-cols-2 gap-3">
             <div className="space-y-1">
               <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">खंड</label>
               <select className="w-full p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-bold text-sm" value={khandId} onChange={e=>{setKhandId(e.target.value); setMandalId(''); setSelectedVillageIds([]); setSelectedPeopleIds([]);}}><option value="">खंड चुनें</option>{khands.map((k: any) => <option key={k.id} value={k.id}>{k.name}</option>)}</select>
             </div>
             <div className="space-y-1">
               <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">मंडल</label>
               <select className="w-full p-3 bg-gray-100 dark:bg-gray-800 dark:text-gray-100 rounded-2xl outline-none font-bold text-sm" value={mandalId} disabled={!khandId} onChange={e=>{setMandalId(e.target.value); setSelectedVillageIds([]); setSelectedPeopleIds([]);}}><option value="">मंडल चुनें</option>{mandals.filter((m: any) => m.khandId === khandId).map((m: any) => <option key={m.id} value={m.id}>{m.name}</option>)}</select>
             </div>
           </div>

           {mandalId && (
             <>
               {/* Village Selector */}
               <div className="space-y-3">
                 <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">गांव का चयन ({selectedVillageIds.length})</label>
                 <div className="flex flex-wrap gap-2">
                   {villageList.map((v: any) => (
                     <button key={v.id} onClick={() => toggleVillage(v.id)} className={`px-3 py-2 rounded-xl text-[11px] font-bold border-2 transition-all ${selectedVillageIds.includes(v.id) ? 'bg-orange-500 border-orange-500 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-800 text-gray-600 border-transparent'}`}>
                       {v.name}
                     </button>
                   ))}
                 </div>
               </div>

               {/* Contacts Selector */}
               <div className="space-y-3">
                 <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">सदस्यों का चयन ({selectedPeopleIds.length})</label>
                 <div className="space-y-2">
                   {contactList.map((c: any) => (
                     <button key={c.id} onClick={() => togglePerson(c.id)} className={`w-full p-3 rounded-2xl text-left font-bold border-2 transition-all flex items-center justify-between ${selectedPeopleIds.includes(c.id) ? 'bg-blue-500 border-blue-500 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-800 text-gray-600 border-transparent'}`}>
                       <span className="text-sm">{c.name}</span>
                       {selectedPeopleIds.includes(c.id) && <CheckCircle2 size={16} />}
                     </button>
                   ))}
                   {contactList.length === 0 && <p className="text-[10px] text-gray-400 italic">इस मंडल में कोई संपर्क उपलब्ध नहीं है</p>}
                 </div>
               </div>
             </>
           )}
        </div>

