  INITIAL_KHANDS, 
  INITIAL_MANDALS, 
  INITIAL_VILLAGES, 
  INITIAL_CONTACTS, 
  INITIAL_TRIPS, 
  INITIAL_LISTS,
  INITIAL_CATEGORIES
} from './constants';

type Tab = 'home' | 'people' | 'trips' | 'lists' | 'work-status' | 'settings' | 'area-mgmt' | 'cat-mgmt';

const loadData = <T,>(key: string, defaultValue: T): T => {
  try {
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : defaultValue;
  } catch (e) {
    return defaultValue;
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('home');
  const [khands, setKhands] = useState<Khand[]>(() => loadData('khands', INITIAL_KHANDS));
  const [mandals, setMandals] = useState<Mandal[]>(() => loadData('mandals', INITIAL_MANDALS));
  const [villages, setVillages] = useState<Village[]>(() => loadData('villages', INITIAL_VILLAGES));
  const [contacts, setContacts] = useState<Contact[]>(() => loadData('contacts', INITIAL_CONTACTS));
  const [trips, setTrips] = useState<TripPlan[]>(() => loadData('trips', INITIAL_TRIPS));
  const [categories, setCategories] = useState<string[]>(() => loadData('categories', INITIAL_CATEGORIES));
  const [customLists, setCustomLists] = useState<CustomList[]>(() => loadData('customLists', INITIAL_LISTS));
  const [darkMode, setDarkMode] = useState(() => loadData('darkMode', false));
  const [userName, setUserName] = useState(() => loadData('userName', 'क्षेत्र कार्यकर्ता'));

  const [dashKhand, setDashKhand] = useState<string>('all');
  const [dashMandal, setDashMandal] = useState<string>('all');
  const [peopleSearch, setPeopleSearch] = useState('');
  const [peopleStatusFilter, setPeopleStatusFilter] = useState<string | 'all'>('all');
  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [selectedTripId, setSelectedTripId] = useState<string | null>(null);
  const [selectedVillageId, setSelectedVillageId] = useState<string | null>(null);
  const [selectedListId, setSelectedListId] = useState<string | null>(null);

  const [editingItem, setEditingItem] = useState<{ type: 'khand' | 'mandal' | 'village', id?: string, parentId?: string, name: string } | null>(null);
  const [editingContact, setEditingContact] = useState<Contact | null>(null);
  const [editingTrip, setEditingTrip] = useState<TripPlan | null>(null);

  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isAddingTrip, setIsAddingTrip] = useState(false);
  const [isAddingList, setIsAddingList] = useState(false);
  const [isLoggingVisit, setIsLoggingVisit] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Helper Functions and Logic Fixes ---

  // Fix for: updateVillageStage
  const updateVillageStage = (id: string, stage: VillageStage) => {
    setVillages(prev => prev.map(v => v.id === id ? { ...v, stage } : v));
  };

  // Fix for: updateShakhaData
  const updateShakhaData = (id: string, data: Partial<ShakhaData>) => {
    setVillages(prev => prev.map(v => v.id === id ? { ...v, shakhaData: { ...v.shakhaData, ...data } as ShakhaData } : v));
  };

  // Fix for: handleLogVisit
  const handleLogVisit = (contactId: string, notes: string, nextFollowUp: string) => {
    const historyEntry: VisitHistory = {
      id: `h${Date.now()}`,
      date: new Date().toISOString(),
      notes,
      nextFollowUp: nextFollowUp || undefined
    };
    setContacts(prev => prev.map(c => 
      c.id === contactId 
        ? { ...c, history: [...c.history, historyEntry], lastVisited: historyEntry.date } 
        : c
    ));
    setIsLoggingVisit(null);
  };

  // Fix for: resetAllData
  const resetAllData = () => {
    if (window.confirm('क्या आप वाकई सारा डेटा मिटाना चाहते हैं?')) {
      setKhands(INITIAL_KHANDS);
      setMandals(INITIAL_MANDALS);
      setVillages(INITIAL_VILLAGES);
      setContacts(INITIAL_CONTACTS);
      setTrips(INITIAL_TRIPS);
      setCategories(INITIAL_CATEGORIES);
      setCustomLists(INITIAL_LISTS);
      setUserName('क्षेत्र कार्यकर्ता');
      localStorage.clear();
      window.location.reload();
    }
  };

  // Fix for: exportData
  const exportData = () => {
    const data = { khands, mandals, villages, contacts, trips, categories, customLists, userName };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `pravas_backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  // Fix for: importData
  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.khands) setKhands(data.khands);
        if (data.mandals) setMandals(data.mandals);
        if (data.villages) setVillages(data.villages);
        if (data.contacts) setContacts(data.contacts);
        if (data.trips) setTrips(data.trips);
        if (data.categories) setCategories(data.categories);
        if (data.customLists) setCustomLists(data.customLists);
        if (data.userName) setUserName(data.userName);
        alert('डेटा सफलतापूर्वक आयात किया गया');
      } catch (err) {
        alert('गलत फाइल फॉर्मेट');
      }
    };
    reader.readAsText(file);
  };

  useEffect(() => {
    localStorage.setItem('khands', JSON.stringify(khands));
    localStorage.setItem('mandals', JSON.stringify(mandals));
    localStorage.setItem('villages', JSON.stringify(villages));
    localStorage.setItem('contacts', JSON.stringify(contacts));
    localStorage.setItem('trips', JSON.stringify(trips));
    localStorage.setItem('categories', JSON.stringify(categories));
    localStorage.setItem('customLists', JSON.stringify(customLists));
    localStorage.setItem('userName', JSON.stringify(userName));
    localStorage.setItem('darkMode', JSON.stringify(darkMode));
    if (darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [khands, mandals, villages, contacts, trips, categories, customLists, userName, darkMode]);

  const getKhandName = (id: string) => khands.find(k => k.id === id)?.name || id;
  const getMandalName = (id: string) => mandals.find(m => m.id === id)?.name || id;
  const getVillageName = (id: string) => villages.find(v => v.id === id)?.name || id;

  const stats = useMemo(() => {
    const filtered = contacts.filter(c => (dashKhand === 'all' || c.khandId === dashKhand) && (dashMandal === 'all' || c.mandalId === dashMandal));
    return {
      total: filtered.length,
      active: filtered.filter(c => c.status === Status.SAKRIYA).length,
      sanchit: filtered.filter(c => c.status === Status.SANCHIT).length,
      sajjan: filtered.filter(c => c.status === Status.SAJJAN).length,
      utsuk: filtered.filter(c => c.status === Status.UTSUK).length,
      pending: filtered.filter(c => c.history.length > 0 && c.history[c.history.length - 1].nextFollowUp && new Date(c.history[c.history.length - 1].nextFollowUp!) < new Date()).length
    };
  }, [contacts, dashKhand, dashMandal]);

  const handleUpdateContact = (id: string, updates: Partial<Contact>) => {
    setContacts(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
    setEditingContact(null);
  };

  const handleAddContact = (newContact: Omit<Contact, 'id' | 'listIds' | 'history'>) => {
    const contact: Contact = { ...newContact, id: `c${Date.now()}`, listIds: [], history: [] };
    setContacts(prev => [...prev, contact]);
    setIsAddingContact(false);
  };

  const handleUpdateTrip = (id: string, updates: Partial<TripPlan>) => {
    setTrips(prev => prev.map(t => t.id === id ? { ...t, ...updates } : t));
    setEditingTrip(null);
  };

  const handleAddTrip = (newTrip: Omit<TripPlan, 'id' | 'isCompleted'>) => {
    const trip: TripPlan = { ...newTrip, id: `t${Date.now()}`, isCompleted: false };
    setTrips(prev => [...prev, trip]);
    setIsAddingTrip(false);
  };

  const handleToggleListPerson = (listId: string, personId: string) => {
    setCustomLists(prev => prev.map(l => {
      if (l.id !== listId) return l;
      const peopleIds = l.peopleIds.includes(personId) 
        ? l.peopleIds.filter(id => id !== personId) 
        : [...l.peopleIds, personId];
      return { ...l, peopleIds };
    }));
  };

  const renderHome = () => (
    <div className="p-4 pb-24 space-y-6">
      <header className="flex justify-between items-center">
        <div>
           <h1 className="text-2xl font-black text-blue-900 dark:text-blue-400 tracking-tight">प्रवास प्लान</h1>
           <p className="text-[10px] text-gray-500 font-bold uppercase mt-0.5 tracking-widest">नमस्ते, {userName}</p>
        </div>
        <button onClick={() => setDarkMode(!darkMode)} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700">
          {darkMode ? <Sun size={20} className="text-yellow-400" /> : <Moon size={20} className="text-blue-600" />}
        </button>
      </header>
      <section className="bg-white dark:bg-gray-800 p-5 rounded-[2rem] shadow-sm border dark:border-gray-700 space-y-4">
        <div className="grid grid-cols-2 gap-3">
          <div className="relative">
            <select value={dashKhand} onChange={(e) => { setDashKhand(e.target.value); setDashMandal('all'); }} className="w-full bg-gray-50 dark:bg-gray-900 dark:text-gray-100 p-3 rounded-xl border dark:border-gray-700 font-bold text-xs appearance-none outline-none">
              <option value="all">सभी खंड</option>
              {khands.map(k => <option key={k.id} value={k.id}>{k.name}</option>)}
            </select>
          </div>
          <div className="relative">
            <select value={dashMandal} disabled={dashKhand === 'all'} onChange={(e) => setDashMandal(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 dark:text-gray-100 p-3 rounded-xl border dark:border-gray-700 font-bold text-xs appearance-none outline-none disabled:opacity-50">
              <option value="all">सभी मंडल</option>
              {mandals.filter(m => m.khandId === dashKhand).map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
          </div>
        </div>
      </section>
      <div className="grid grid-cols-2 gap-3">
        <StatCard label="कुल" value={stats.total} color="bg-blue-50 dark:bg-blue-900/20 text-blue-800" onClick={() => setActiveTab('people')} />
        <StatCard label="सक्रिय" value={stats.active} color="bg-green-50 dark:bg-green-900/20 text-green-800" onClick={() => { setPeopleStatusFilter(Status.SAKRIYA); setActiveTab('people'); }} />
      </div>
      <button onClick={() => setActiveTab('trips')} className="w-full p-5 bg-orange-600 text-white rounded-[2rem] font-bold flex justify-between items-center shadow-lg shadow-orange-500/20">
         <div className="flex items-center gap-3"><CalendarIcon size={24}/><span>यात्रा योजना देखें</span></div>
         <ChevronRight size={20}/>
      </button>
    </div>
  );

  const renderPeople = () => {
    if (selectedContactId) {
      const contact = contacts.find(c => c.id === selectedContactId);
      if (!contact) return null;
      return (
        <ContactProfile 
          contact={contact} 
          khands={khands} mandals={mandals} villages={villages} categories={categories}
          onBack={() => setSelectedContactId(null)} 
          onDelete={() => { if(window.confirm('हटाएं?')) { setContacts(c => c.filter(x => x.id !== contact.id)); setSelectedContactId(null); } }}
          onEdit={() => setEditingContact(contact)}
          onLogVisit={() => setIsLoggingVisit(contact.id)}
        />
      );
    }
    const filtered = contacts.filter(c => {
      const matchSearch = c.name.toLowerCase().includes(peopleSearch.toLowerCase()) || c.phone.includes(peopleSearch);
      const matchStatus = peopleStatusFilter === 'all' || c.status === peopleStatusFilter;
      const matchArea = (dashKhand === 'all' || c.khandId === dashKhand) && (dashMandal === 'all' || c.mandalId === dashMandal);
      return matchSearch && matchStatus && matchArea;
    });
    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-black dark:text-white">संपर्क</h1>
          <button onClick={() => setIsAddingContact(true)} className="p-3 bg-blue-600 text-white rounded-2xl shadow-lg shadow-blue-500/30"><Plus/></button>
        </header>
        <div className="relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} /><input type="text" placeholder="खोजें..." value={peopleSearch} onChange={e=>setPeopleSearch(e.target.value)} className="w-full bg-white dark:bg-gray-800 dark:text-white p-4 pl-10 rounded-2xl border dark:border-gray-700 outline-none" /></div>
        <div className="space-y-3">
          {filtered.map(c => (
            <div key={c.id} onClick={() => setSelectedContactId(c.id)} className="bg-white dark:bg-gray-800 p-4 rounded-2xl border dark:border-gray-700 flex items-center gap-4 active:scale-95 transition-all">
              <div className="w-12 h-12 rounded-full bg-blue-500 flex items-center justify-center text-white font-bold">{c.name[0]}</div>
              <div className="flex-1">
                <div className="font-bold dark:text-gray-100">{c.name}</div>
                <div className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter">{getVillageName(c.villageId)} • {getMandalName(c.mandalId)}</div>
              </div>
              <Phone size={18} className="text-blue-600" />
            </div>
          ))}
        </div>
      </div>
    );
  };

  // Fix for: renderTrips
  const renderTrips = () => {
    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-black dark:text-white">यात्रा योजनाएं</h1>
          <button onClick={() => setIsAddingTrip(true)} className="p-3 bg-orange-600 text-white rounded-2xl shadow-lg shadow-orange-500/30"><Plus/></button>
        </header>
        <div className="space-y-4">
          {trips.length === 0 ? (
            <div className="bg-white dark:bg-gray-800 p-10 rounded-[2rem] text-center border dark:border-gray-700 text-gray-400 font-bold">कोई यात्रा योजना नहीं है</div>
          ) : (
            trips.map(trip => (
              <div key={trip.id} className="bg-white dark:bg-gray-800 p-5 rounded-[2rem] border dark:border-gray-700 shadow-sm space-y-4">
                <div className="flex justify-between items-start">
                  <div>
                    <div className="text-blue-600 font-black text-sm uppercase tracking-tighter">{new Date(trip.date).toLocaleDateString('hi-IN')}</div>
                    <div className="font-bold dark:text-white mt-1 text-lg">{getMandalName(trip.mandalId)} ({getKhandName(trip.khandId)})</div>
                  </div>
                  <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${trip.isCompleted ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400'}`}>
                    {trip.isCompleted ? 'पूर्ण' : 'लंबित'}
                  </div>
                </div>
                <div className="flex flex-wrap gap-2">
                  {trip.villageIds.map(vid => (
                    <span key={vid} className="px-3 py-1 bg-gray-50 dark:bg-gray-900 dark:text-gray-300 rounded-xl text-[10px] font-black border dark:border-gray-700">{getVillageName(vid)}</span>
                  ))}
                </div>
                <div className="flex gap-2 pt-2">
                  {!trip.isCompleted && (
                    <button onClick={() => handleUpdateTrip(trip.id, { isCompleted: true })} className="flex-1 p-4 bg-green-500 text-white rounded-2xl font-bold text-xs flex items-center justify-center gap-2 shadow-lg shadow-green-500/20">
                      <CheckCircle2 size={16}/> पूर्ण चिह्नित करें
                    </button>
                  )}
                  <button onClick={() => setEditingTrip(trip)} className="p-4 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 rounded-2xl"><Edit2 size={20}/></button>
                  <button onClick={() => { if(window.confirm('मिटाएं?')) setTrips(prev => prev.filter(t => t.id !== trip.id)); }} className="p-4 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 rounded-2xl"><Trash2 size={20}/></button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    );
  };

  const renderLists = () => {
    if (selectedListId) {
      const list = customLists.find(l => l.id === selectedListId);
      if (!list) return null;
      return (
        <div className="p-4 pb-24 space-y-6 animate-in slide-in-from-right duration-300">
           <header className="flex items-center gap-4">
              <button onClick={() => setSelectedListId(null)} className="p-2 bg-white dark:bg-gray-800 rounded-xl border dark:border-gray-700"><ArrowLeft size={20} className="dark:text-white"/></button>
              <h2 className="text-xl font-black dark:text-white">{list.name}</h2>
              <button onClick={() => { if(window.confirm('हटाएं?')) { setCustomLists(prev => prev.filter(l => l.id !== selectedListId)); setSelectedListId(null); } }} className="ml-auto text-red-500 p-2"><Trash2 size={20}/></button>
           </header>
           <div className="space-y-3">
              {contacts.filter(c => list.peopleIds.includes(c.id)).map(c => (
                 <div key={c.id} onClick={() => setSelectedContactId(c.id)} className="bg-white dark:bg-gray-800 p-4 rounded-2xl border dark:border-gray-700 flex items-center gap-4">
                    <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center text-white text-xs font-bold">{c.name[0]}</div>
                    <div className="flex-1 font-bold dark:text-gray-100 text-sm">{c.name}</div>
                    <ChevronRight size={16} className="text-gray-300"/>
                 </div>
              ))}
              <button onClick={() => { /* Logic to manage list members can go here */ }} className="w-full p-4 border-2 border-dashed dark:border-gray-800 rounded-2xl text-gray-400 font-bold text-sm flex items-center justify-center gap-2">
                 <Plus size={16}/> सदस्य जोड़ें/हटाएं
              </button>
           </div>
        </div>
      );
    }
    return (
      <div className="p-4 pb-24 space-y-6">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-black dark:text-white">समन्वय सूची</h1>
          <button onClick={() => setIsAddingList(true)} className="p-3 bg-indigo-600 text-white rounded-2xl shadow-lg"><Plus/></button>
        </header>
        <div className="grid grid-cols-1 gap-3">
           {customLists.map(list => (
              <div key={list.id} onClick={() => setSelectedListId(list.id)} className="bg-white dark:bg-gray-800 p-5 rounded-[2rem] border dark:border-gray-700 flex justify-between items-center shadow-sm">
                 <div className="flex items-center gap-4">
                    <div className="p-3 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 rounded-2xl"><FolderOpen size={24}/></div>
                    <div>
                       <div className="font-bold dark:text-white">{list.name}</div>
                       <div className="text-[10px] font-bold text-gray-400 uppercase">{list.peopleIds.length} सदस्य</div>
                    </div>
                 </div>
                 <ChevronRight className="text-gray-300"/>
              </div>
           ))}
        </div>
      </div>
    );
  };

  const renderWorkStatus = () => {
    if (selectedVillageId) {
      const village = villages.find(v => v.id === selectedVillageId);
      if (!village) return null;
      return (
        <VillageWorkStatusDetail 
          village={village} contacts={contacts}
          onBack={() => setSelectedVillageId(null)}
          onContactClick={(id: string) => { setSelectedContactId(id); setActiveTab('people'); }}
          onUpdateStage={(stage: any) => updateVillageStage(village.id, stage)}
          onUpdateShakhaData={(data: any) => updateShakhaData(village.id, data)}
        />
      );
    }
    return (
      <div className="p-4 pb-24 space-y-4">
        <header className="flex justify-between items-center">
          <h1 className="text-2xl font-black dark:text-white">कार्यस्थिति</h1>
          <Building2 className="text-blue-600" />
        </header>
        <div className="space-y-4">
          {mandals.map(m => (
            <div key={m.id} className="space-y-2">
              <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">{m.name}</h3>
              <div className="grid grid-cols-1 gap-2">
                {villages.filter(v => v.mandalId === m.id).map(v => (
                  <div key={v.id} onClick={() => setSelectedVillageId(v.id)} className="bg-white dark:bg-gray-800 p-4 rounded-2xl border dark:border-gray-700 flex justify-between items-center">
                    <div className="font-bold dark:text-white text-sm">{v.name}</div>
                    <span className="text-[9px] font-black uppercase px-2 py-1 bg-gray-100 dark:bg-gray-700 dark:text-gray-300 rounded-full">{v.stage}</span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen max-w-md mx-auto relative bg-gray-50 dark:bg-gray-950">
      <main className="min-h-screen">
        {activeTab === 'home' && renderHome()}
        {activeTab === 'people' && renderPeople()}
        {activeTab === 'trips' && renderTrips()}
        {activeTab === 'lists' && renderLists()}
        {activeTab === 'work-status' && renderWorkStatus()}
        {activeTab === 'settings' && <SettingsTab 
          userName={userName} setUserName={setUserName} 
          darkMode={darkMode} setDarkMode={setDarkMode}
          setActiveTab={setActiveTab} exportData={exportData} resetAllData={resetAllData} 
          importData={() => fileInputRef.current?.click()}
        />}
        {activeTab === 'area-mgmt' && <AreaMgmt khands={khands} mandals={mandals} villages={villages} setKhands={setKhands} setMandals={setMandals} setVillages={setVillages} onBack={()=>setActiveTab('settings')} />}
        {activeTab === 'cat-mgmt' && <CatMgmt categories={categories} setCategories={setCategories} onBack={()=>setActiveTab('settings')} />}
      </main>
      <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={importData} />

      <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-md bg-white/90 dark:bg-gray-900/90 backdrop-blur-lg border-t dark:border-gray-800 flex justify-around items-center p-3 z-40 rounded-t-[2.5rem] shadow-2xl">
        <NavBtn active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon={<Home />} label="होम" />
        <NavBtn active={activeTab === 'people'} onClick={() => { setActiveTab('people'); setSelectedContactId(null); }} icon={<Users />} label="संपर्क" />
        <NavBtn active={activeTab === 'lists'} onClick={() => { setActiveTab('lists'); setSelectedListId(null); }} icon={<ListIcon />} label="सूची" />
        <NavBtn active={activeTab === 'work-status'} onClick={() => { setActiveTab('work-status'); setSelectedVillageId(null); }} icon={<Building2 />} label="कार्य" />
        <NavBtn active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} icon={<Settings />} label="सेट" />
      </nav>

      {(isAddingContact || editingContact) && (
        <ContactFormModal 
          khands={khands} mandals={mandals} villages={villages} categories={categories}
          initialData={editingContact}
          onClose={() => { setIsAddingContact(false); setEditingContact(null); }} 
          onSubmit={(data: any) => editingContact ? handleUpdateContact(editingContact.id, data) : handleAddContact(data)} 
        />
      )}
      {(isAddingTrip || editingTrip) && (
        <TripFormModal 
          khands={khands} mandals={mandals} villages={villages} contacts={contacts}
          initialData={editingTrip}
          onClose={() => { setIsAddingTrip(false); setEditingTrip(null); }} 
          onSubmit={(data: any) => editingTrip ? handleUpdateTrip(editingTrip.id, data) : handleAddTrip(data)} 
        />
      )}
      {isLoggingVisit && (
        <VisitLogModal contactName={contacts.find(c => c.id === isLoggingVisit)?.name || ''} onClose={() => setIsLoggingVisit(null)} onSubmit={(notes: string, fup: string) => handleLogVisit(isLoggingVisit!, notes, fup)} />
      )}
      {isAddingList && (
         <PromptModal title="नई सूची" placeholder="सूची का नाम..." onSubmit={(name: string) => { if(name) { setCustomLists(prev => [...prev, { id: `l${Date.now()}`, name, peopleIds: [] }]); setIsAddingList(false); } }} onCancel={() => setIsAddingList(false)} />
      )}
    </div>
  );
};

// --- Sub Components ---

const NavBtn = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center p-2 rounded-2xl transition-all ${active ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/30' : 'text-gray-400'}`}>
    {React.cloneElement(icon, { size: 20, strokeWidth: active ? 3 : 2 })}
    <span className="text-[9px] mt-1 font-black uppercase tracking-widest">{label}</span>
  </button>
);

const StatCard = ({ label, value, color, onClick }: any) => (
  <div onClick={onClick} className={`${color} p-4 rounded-3xl shadow-sm border border-transparent dark:border-gray-800 active:scale-95 transition-all flex flex-col justify-between h-24`}>
     <div className="text-[10px] font-black uppercase opacity-60">{label}</div>
     <div className="text-2xl font-black">{value}</div>
  </div>
);

const ContactProfile = ({ contact, khands, mandals, villages, categories, onBack, onDelete, onEdit, onLogVisit }: any) => {
  const vName = villages.find((v: any) => v.id === contact.villageId)?.name || '';
  const mName = mandals.find((m: any) => m.id === contact.mandalId)?.name || '';
  return (
    <div className="p-4 pb-24 space-y-6 animate-in slide-in-from-right duration-300">
      <header className="flex justify-between items-center">
        <button onClick={onBack} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700"><ArrowLeft size={20} className="dark:text-white"/></button>
        <div className="flex gap-2">
           <button onClick={onEdit} className="p-3 bg-blue-50 text-blue-600 rounded-2xl"><Edit2 size={20}/></button>
           <button onClick={onDelete} className="p-3 bg-red-50 text-red-600 rounded-2xl"><Trash2 size={20}/></button>
        </div>
      </header>
      <div className="text-center space-y-4">
         <div className="w-24 h-24 rounded-full bg-blue-600 mx-auto flex items-center justify-center text-white text-3xl font-black shadow-xl ring-4 ring-white dark:ring-gray-800">{contact.name[0]}</div>
         <h2 className="text-2xl font-black dark:text-white">{contact.name}</h2>
         <div className="flex justify-center items-center gap-4">
            <a href={`tel:${contact.phone}`} className="flex items-center gap-2 bg-green-500 text-white px-4 py-2 rounded-full font-bold text-sm shadow-lg shadow-green-500/20"><Phone size={14}/> कॉल</a>
         </div>
      </div>
      <div className="bg-white dark:bg-gray-800 p-6 rounded-[2.5rem] border dark:border-gray-700 space-y-6">
         <div className="grid grid-cols-2 gap-4">
            <div><label className="text-[10px] font-bold text-gray-400 uppercase">श्रेणी</label><div className="text-sm font-bold dark:text-white mt-1">{contact.category}</div></div>
            <div><label className="text-[10px] font-bold text-gray-400 uppercase">स्थिति</label><div className="text-sm font-bold dark:text-white mt-1">{contact.status}</div></div>
         </div>
         <div className="flex items-center gap-2 text-[10px] font-bold text-blue-600 bg-blue-50 dark:bg-blue-900/30 p-3 rounded-xl uppercase">
            <MapPin size={14}/> {vName} • {mName}
         </div>
         <div className="space-y-3">
            <h4 className="text-[10px] font-black text-gray-400 uppercase">मुलाकात इतिहास</h4>
            {contact.history.map((h: any) => (
               <div key={h.id} className="p-3 bg-gray-50 dark:bg-gray-900/50 rounded-xl border dark:border-gray-800">
                  <div className="text-[10px] font-bold text-blue-500">{new Date(h.date).toLocaleDateString('hi-IN')}</div>
                  <div className="text-xs dark:text-gray-300 mt-1">"{h.notes}"</div>
               </div>
            ))}
         </div>
      </div>
      <button onClick={onLogVisit} className="w-full p-4 bg-blue-600 text-white font-bold rounded-2xl shadow-lg shadow-blue-500/30 flex items-center justify-center gap-2"><CheckCircle2 size={18}/> मुलाकात दर्ज करें</button>
    </div>
  );
};

const VillageWorkStatusDetail = ({ village, contacts, onBack, onContactClick, onUpdateStage, onUpdateShakhaData }: any) => {
  const vContacts = contacts.filter((c: any) => c.villageId === village.id);
  return (
    <div className="p-4 pb-24 space-y-6 animate-in slide-in-from-right duration-300">
       <button onClick={onBack} className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700"><ArrowLeft size={20} className="dark:text-white"/></button>
       <h2 className="text-2xl font-black dark:text-white">{village.name} कार्यस्थिति</h2>
       <div className="bg-white dark:bg-gray-800 p-6 rounded-[2.5rem] border dark:border-gray-700 space-y-6">
          <div className="space-y-3">
             <label className="text-[10px] font-bold text-gray-400 uppercase px-1">कार्य प्रकार</label>
             <div className="grid grid-cols-2 gap-2">
                {Object.values(VillageStage).map(s => <button key={s} onClick={() => onUpdateStage(s)} className={`p-3 rounded-2xl text-[10px] font-black border transition-all ${village.stage === s ? 'bg-orange-600 text-white border-orange-600' : 'bg-gray-50 dark:bg-gray-900 text-gray-500 border-gray-100 dark:border-gray-800'}`}>{s}</button>)}
             </div>
