         <div className="bg-white dark:bg-gray-800 p-5 rounded-[2rem] border dark:border-gray-700 space-y-4 shadow-sm">
            <div className="flex gap-2">
               <input className="flex-1 bg-gray-50 dark:bg-gray-900 p-4 rounded-xl font-bold dark:text-white outline-none border dark:border-gray-700" placeholder="नई श्रेणी जोड़ें..." value={newCat} onChange={e=>setNewCat(e.target.value)}/>
