        <button onClick={importData} className="w-full p-5 flex justify-between items-center active:bg-gray-50 dark:active:bg-gray-900/40"><div className="flex items-center gap-4 text-blue-500"><Upload/><span className="font-bold dark:text-white">बैकअप रिस्टोर करें</span></div></button>
        <button onClick={resetAllData} className="w-full p-5 flex justify-between items-center text-red-600 active:bg-red-50 dark:active:bg-red-900/10 transition-all"><div className="flex items-center gap-4"><RotateCcw/><span className="font-bold">ऐप रिसेट करें</span></div></button>
     </div>
     <div className="text-center">
        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Pravas Plan v2.5.0 • Local Only</p>
     </div>
  </div>
);

