                 if(n) logVisit(selectedContact.id, n);
               }}
               className="w-full bg-blue-600 text-white p-5 rounded-3xl font-bold flex items-center justify-center gap-3 shadow-lg"
             >
               <CheckCircle size={20}/> मुलाकात दर्ज करें
             </button>
          </div>
        </div>
      )}
    </div>
  );
};

